enum class Classification : uint8_t {
    Exploitable = 0,        // PoC exists or mechanically generatable
    ConfirmedReachable = 1, // CFG+DFG confirm reachability, no PoC
    ConfirmedIssue = 2,     // Static analysis confirms pattern (legacy compat)
    ConfirmedStatic = 3,    // Pattern confirmed, reachability unverified
    Inconclusive = 4,       // Pattern present, insufficient evidence
    FalsePositive = 5,      // Disproved by dominance or sanitizer
    NonExploitable = 6      // Confirmed unreachable or impossible state
};

