// ── IMP7: DeduplicationEngine ───────────────────────────────────────────────
class DeduplicationEngine {
public:
    struct UniqueFindings {
        std::vector<Finding> deduplicated;
        std::map<std::string, std::vector<std::string>> presence_matrix;
        int raw_count = 0, unique_count = 0;
        float reduction_ratio = 0.0f;
    };
    static std::string canonical_id(const Finding& f) {
        std::string bn = f.file;
        size_t sl = bn.rfind('/');
        if (sl != std::string::npos) bn = bn.substr(sl + 1);
        return bn + ":" + f.function_name + ":" + f.issue_type_string();
    }
    UniqueFindings deduplicate(const std::vector<Finding>& all) {
        UniqueFindings r;
        r.raw_count = static_cast<int>(all.size());
        std::map<std::string, std::vector<size_t>> groups;
        for (size_t i = 0; i < all.size(); ++i) groups[canonical_id(all[i])].push_back(i);
        for (auto& kv : groups) {
            size_t best = kv.second[0];
            for (size_t idx : kv.second) {
                if (all[idx].confidence > all[best].confidence) best = idx;
            }
            Finding cf = all[best];
            std::vector<std::string> rels;
            for (size_t idx : kv.second)
                if (std::find(rels.begin(), rels.end(), all[idx].release) == rels.end())
                    rels.push_back(all[idx].release);
            r.presence_matrix[kv.first] = rels;
            std::string rl; for (size_t i = 0; i < rels.size(); ++i) { if (i) rl += ", "; rl += rels[i]; }
            cf.evidence += " [Deduplicated from " + std::to_string(kv.second.size()) + " instances across: " + rl + "]";
            r.deduplicated.push_back(cf);
        }
        r.unique_count = static_cast<int>(r.deduplicated.size());
        r.reduction_ratio = r.raw_count > 0 ? 1.0f - float(r.unique_count) / float(r.raw_count) : 0.0f;
        return r;
    }
};

// ── IMP5: CrossVersionDiffEngine ────────────────────────────────────────────
class CrossVersionDiffEngine {
public:
    struct FindingDiff {
        std::string canonical_id;
        std::vector<std::string> present_in, absent_in;
        std::string evolution, commit_hint;
    };
    static bool ver_less(const std::string& a, const std::string& b) {
        auto parse = [](const std::string& v) {
            std::vector<int> p; std::istringstream s(v); std::string t;
            while (std::getline(s, t, '.')) { try { p.push_back(std::stoi(t)); } catch (...) { p.push_back(0); } }
            while (p.size() < 3) p.push_back(0); return p;
        };
        return parse(a) < parse(b);
    }
    std::vector<FindingDiff> compute_diffs(const std::vector<Finding>& all) {
        std::set<std::string> all_vers;
        std::map<std::string, std::set<std::string>> groups;
        for (auto& f : all) { groups[DeduplicationEngine::canonical_id(f)].insert(f.release); all_vers.insert(f.release); }
        std::vector<std::string> sv(all_vers.begin(), all_vers.end());
        std::sort(sv.begin(), sv.end(), ver_less);
        std::vector<FindingDiff> diffs;
        for (auto& kv : groups) {
            FindingDiff d; d.canonical_id = kv.first;
            for (auto& v : sv) { if (kv.second.count(v)) d.present_in.push_back(v); else d.absent_in.push_back(v); }
            d.evolution = d.absent_in.empty() ? "PERSISTENT" : (d.present_in.size() == 1 ? "INTRODUCED" : "PARTIAL");
            if (!d.present_in.empty() && !d.absent_in.empty()) {
                for (size_t i = 1; i < sv.size(); ++i)
                    if (kv.second.count(sv[i]) && !kv.second.count(sv[i-1]))
                        { d.evolution = "REGRESSION"; d.commit_hint = "Between " + sv[i-1] + " and " + sv[i]; break; }
            }
            diffs.push_back(d);
        }
        return diffs;
    }
    std::string generate_diff_report(const std::vector<FindingDiff>& diffs) {
        std::string r = "=== CROSS-VERSION DIFFERENTIAL REPORT ===\n\n";
        for (auto& d : diffs) {
            r += "[" + d.evolution + "] " + d.canonical_id + " — ";
            for (size_t i = 0; i < d.present_in.size(); ++i) { if (i) r += ","; r += d.present_in[i]; }
            if (!d.commit_hint.empty()) r += " (" + d.commit_hint + ")";
            r += "\n";
        }
        return r;
    }
};

// ── IMP6: ExploitPathWeightedScorer ─────────────────────────────────────────
class ExploitPathWeightedScorer {
public:
    static float sev_f(Severity s) { return s == Severity::Critical ? 1.0f : s == Severity::High ? 0.75f : s == Severity::Medium ? 0.50f : 0.25f; }
    static int sev_r(Severity s) { return s == Severity::Critical ? 4 : s == Severity::High ? 3 : s == Severity::Medium ? 2 : 1; }
    void rescore_all_findings(std::vector<Finding>& findings) {
        for (auto& f : findings) {
            float ts = sev_f(f.severity), ps = std::min(1.0f, float(f.execution_path.size()) / 5.0f);
            float rb = f.reachability == "direct_exploit" ? 0.20f : (f.reachability == "rpc" || f.reachability == "p2p") ? 0.10f : f.reachability == "confirmed_path" ? 0.08f : 0.0f;
            float w = ts * 0.35f + ps * 0.30f + f.confidence * 0.25f + rb;
            Severity ns = w >= 0.82f ? Severity::Critical : w >= 0.62f ? Severity::High : w >= 0.42f ? Severity::Medium : Severity::Low;
            if (sev_r(ns) < sev_r(f.severity) - 1) ns = f.severity;
            if (ns != f.severity) { f.evidence += " [ExploitPathWeightedScorer: rescored, weighted=" + std::to_string(w).substr(0,4) + "]"; f.severity = ns; }
        }
    }
};

// ── IMP1: CompilerWipeVerifier ──────────────────────────────────────────────
class CompilerWipeVerifier {
public:
    struct WipeVerificationResult { std::string file_path, function_name, wipe_token, verdict; bool survives_o0=false, survives_o2=false; };
    std::vector<WipeVerificationResult> verify_wipe_findings(std::vector<Finding>& wf, const std::string& base) {
        std::vector<WipeVerificationResult> results;
        for (auto& f : wf) {
            if (f.issue_type != IssueType::CompilerOptimizationRemoval && f.issue_type != IssueType::DeadStoreElimination) continue;
            WipeVerificationResult r; r.file_path = f.file; r.function_name = f.function_name;
            r.wipe_token = f.evidence.find("OPENSSL_cleanse") != std::string::npos ? "OPENSSL_cleanse" : f.evidence.find("memset") != std::string::npos ? "memset" : "memory_cleanse";
            std::string src = base + "/" + f.file;
            std::string c0 = "clang++ -std=c++17 -O0 -S -emit-llvm " + src + " -o /tmp/audit_o0.ll 2>/dev/null";
            std::string c2 = "clang++ -std=c++17 -O2 -S -emit-llvm " + src + " -o /tmp/audit_o2.ll 2>/dev/null";
            if (system(c0.c_str()) == 0) { std::ifstream i0("/tmp/audit_o0.ll"); std::string ir((std::istreambuf_iterator<char>(i0)),std::istreambuf_iterator<char>()); r.survives_o0 = ir.find(r.wipe_token) != std::string::npos || ir.find("llvm.memset") != std::string::npos; }
            if (system(c2.c_str()) == 0) { std::ifstream i2("/tmp/audit_o2.ll"); std::string ir((std::istreambuf_iterator<char>(i2)),std::istreambuf_iterator<char>()); r.survives_o2 = ir.find(r.wipe_token) != std::string::npos || ir.find("llvm.memset") != std::string::npos; }
            if (r.survives_o0 && !r.survives_o2) { r.verdict = "ELIDED_AT_O2"; f.classification = Classification::ConfirmedIssue; f.confidence = std::min(0.95, f.confidence + 0.15); f.evidence += " [CompilerWipeVerifier: ELIDED at -O2]"; }
            else if (r.survives_o2) { r.verdict = "SAFE"; f.classification = Classification::NonExploitable; f.evidence += " [CompilerWipeVerifier: SURVIVES -O2]"; }
            else { r.verdict = "UNKNOWN"; f.manual_review_required = true; f.evidence += " [CompilerWipeVerifier: compilation failed]"; }
            results.push_back(r);
        }
        return results;
    }
    std::string generate_wipe_verification_report(const std::vector<WipeVerificationResult>& rs) {
        int e=0,s=0,u=0; for (auto& r : rs) { if (r.verdict=="ELIDED_AT_O2") e++; else if (r.verdict=="SAFE") s++; else u++; }
        return std::to_string(rs.size()) + " verified: " + std::to_string(e) + " ELIDED, " + std::to_string(s) + " SAFE, " + std::to_string(u) + " UNKNOWN";
    }
};

// ── IMP2: RuntimeAnalysisIntegrator ─────────────────────────────────────────
class RuntimeAnalysisIntegrator {
public:
    std::string generate_sanitizer_harness(const std::vector<Finding>& findings, const std::string& base) {
        std::string sh = "#!/bin/bash\n# Sanitizer audit harness — auto-generated\nset -e\nBASE=\"" + base + "\"\n\n";
        sh += "echo '[*] Building with AddressSanitizer...'\n";
        sh += "cd \"$BASE\" && ./configure CXXFLAGS=\"-fsanitize=address -g -O1\" LDFLAGS=\"-fsanitize=address\" 2>/dev/null && make -j$(nproc) 2>/dev/null\n";
        sh += "echo '[*] Running ASAN test suite...'\n";
        sh += "timeout 300 ./src/bitcoind -regtest -rpcuser=user -rpcpass=pass -daemon 2>asan_output.txt\n";
        sh += "sleep 3\n";
        sh += "# Exercise key-sensitive paths\n";
        sh += "./src/bitcoin-cli -regtest -rpcuser=user -rpcpass=pass createwallet test_asan 2>>asan_output.txt\n";
        sh += "./src/bitcoin-cli -regtest -rpcuser=user -rpcpass=pass getnewaddress 2>>asan_output.txt\n";
        sh += "./src/bitcoin-cli -regtest -rpcuser=user -rpcpass=pass encryptwallet testpass123 2>>asan_output.txt || true\n";
        sh += "sleep 2\n";
        sh += "./src/bitcoin-cli -regtest -rpcuser=user -rpcpass=pass walletpassphrase testpass123 30 2>>asan_output.txt\n";
        sh += "./src/bitcoin-cli -regtest -rpcuser=user -rpcpass=pass walletlock 2>>asan_output.txt\n";
        sh += "./src/bitcoin-cli -regtest -rpcuser=user -rpcpass=pass stop 2>>asan_output.txt || true\n";
        sh += "sleep 2\n\n";
        sh += "echo '[*] Building with MemorySanitizer...'\n";
        sh += "make clean 2>/dev/null\n";
        sh += "cd \"$BASE\" && ./configure CXXFLAGS=\"-fsanitize=memory -g -O1\" LDFLAGS=\"-fsanitize=memory\" 2>/dev/null && make -j$(nproc) 2>/dev/null\n";
        sh += "timeout 300 ./src/bitcoind -regtest -rpcuser=user -rpcpass=pass -daemon 2>msan_output.txt\n";
        sh += "sleep 3\n";
        sh += "./src/bitcoin-cli -regtest -rpcuser=user -rpcpass=pass getnewaddress 2>>msan_output.txt\n";
        sh += "./src/bitcoin-cli -regtest -rpcuser=user -rpcpass=pass stop 2>>msan_output.txt || true\n\n";
        sh += "echo '[*] Sanitizer harness complete. Check asan_output.txt and msan_output.txt'\n";
        return sh;
    }
    std::vector<Finding> parse_sanitizer_output(std::vector<Finding>& findings,
            const std::string& asan_path, const std::string& msan_path, const std::string& /*tsan_path*/) {
        auto read_file = [](const std::string& p) -> std::string {
            std::ifstream f(p); if (!f) return "";
            return std::string((std::istreambuf_iterator<char>(f)), std::istreambuf_iterator<char>());
        };
        std::string asan = read_file(asan_path);
        std::string msan = read_file(msan_path);
        for (auto& f : findings) {
            if (asan.find(f.function_name) != std::string::npos && asan.find("ERROR") != std::string::npos) {
                f.classification = Classification::ConfirmedIssue;
                f.confidence = std::min(0.95, f.confidence + 0.20);
                f.evidence += " [RuntimeAnalysisIntegrator: ASAN confirmed error in " + f.function_name + "]";
            }
            if (msan.find(f.function_name) != std::string::npos && msan.find("uninitialized") != std::string::npos) {
                f.confidence = std::min(0.90, f.confidence + 0.15);
                f.evidence += " [RuntimeAnalysisIntegrator: MSAN uninitialized read in " + f.function_name + "]";
            }
        }
        return findings;
    }
};

// ── IMP3: BDBPageWalker ─────────────────────────────────────────────────────
class BDBPageWalker {
public:
    struct BDBPageAnalysis {
        std::string wallet_path;
        int total_pages = 0, leaf_pages = 0, deleted_record_slots = 0;
        int non_zeroed_deleted_slots = 0, recoverable_key_records = 0;
        std::vector<std::string> recoverable_addresses;
        bool confirmed_vulnerable = false;
        float evidence_confidence = 0.0f;
    };
    BDBPageAnalysis analyze_wallet_file(const std::string& wp) {
        BDBPageAnalysis result;
        result.wallet_path = wp;
        std::ifstream f(wp, std::ios::binary);
        if (!f) { Logger::instance().warning("BDBPageWalker: cannot open " + wp); return result; }
        std::vector<unsigned char> data((std::istreambuf_iterator<char>(f)), std::istreambuf_iterator<char>());
        if (data.size() < 512) return result;
        uint32_t page_size = 4096;
        if (data.size() >= 24) {
            uint32_t ps = data[20] | (data[21] << 8) | (data[22] << 16) | (data[23] << 24);
            if (ps >= 512 && ps <= 65536 && (ps & (ps - 1)) == 0) page_size = ps;
        }
        size_t num_pages = data.size() / page_size;
        result.total_pages = static_cast<int>(num_pages);
        for (size_t pg = 0; pg < num_pages; ++pg) {
            size_t off = pg * page_size;
            if (off + 26 > data.size()) break;
            uint8_t ptype = data[off + 25];
            if (ptype == 5 || ptype == 6) {
                result.leaf_pages++;
                uint16_t num_entries = data[off + 20] | (data[off + 21] << 8);
                size_t idx_off = off + 26;
                for (uint16_t e = 0; e < num_entries && idx_off + 2 <= off + page_size; ++e) {
                    uint16_t item_off = data[idx_off] | (data[idx_off + 1] << 8);
                    idx_off += 2;
                    size_t abs_off = off + item_off;
                    if (abs_off + 3 >= data.size()) continue;
                    uint16_t item_len = data[abs_off] | (data[abs_off + 1] << 8);
                    uint8_t item_type = data[abs_off + 2];
                    if (item_type == 0x02) {
                        result.deleted_record_slots++;
                        bool all_zero = true;
                        size_t data_start = abs_off + 3;
                        size_t check_len = std::min(static_cast<size_t>(item_len), data.size() - data_start);
                        for (size_t b = 0; b < check_len && b < 64; ++b)
                            if (data[data_start + b] != 0) { all_zero = false; break; }
                        if (!all_zero) {
                            result.non_zeroed_deleted_slots++;
                            if (check_len >= 4 && data[data_start] == 0x03 &&
                                data[data_start+1] == 'k' && data[data_start+2] == 'e' && data[data_start+3] == 'y') {
                                result.recoverable_key_records++;
                                if (check_len >= 4 + 33) {
                                    // Extract pubkey hash → address (simplified)
                                    result.recoverable_addresses.push_back(
                                        "recovered_key_slot_" + std::to_string(result.recoverable_key_records));
                                }
                            }
                        }
                    }
                }
            }
        }
        result.confirmed_vulnerable = result.recoverable_key_records > 0;
        result.evidence_confidence = result.confirmed_vulnerable ? 0.98f : 0.60f;
        return result;
    }
    Finding create_confirmed_bdb_finding(const BDBPageAnalysis& a, const std::string& release) {
        Finding f;
        f.finding_id = IDGenerator::instance().next();
        f.release = release; f.file = a.wallet_path; f.function_name = "BDB_page_walker";
        f.issue_type = IssueType::WalletLeakage; f.classification = Classification::ConfirmedIssue;
        f.severity = Severity::Critical; f.confidence = a.evidence_confidence;
        f.secret_material_type = SecretMaterialType::PrivateKey;
        f.reachability = "local_file_access"; f.review_tier = "immediate";
        f.novelty_tag = "KnownVariant"; f.reproducible = true; f.manual_review_required = false;
        f.evidence = "BDB PAGE WALKER CONFIRMED: wallet " + a.wallet_path + " contains " +
            std::to_string(a.recoverable_key_records) + " recoverable pre-encryption private key records in " +
            std::to_string(a.non_zeroed_deleted_slots) + " non-zeroed deleted BDB page slots (of " +
            std::to_string(a.deleted_record_slots) + " total deleted). " +
            std::to_string(a.total_pages) + " pages scanned, " + std::to_string(a.leaf_pages) +
            " leaf pages. Keys recoverable without passphrase. Version: " + release + ".";
        f.execution_path = {"Attacker obtains copy of wallet.dat (backup, stolen device, cloud sync)",
            "BDB page walker finds " + std::to_string(a.recoverable_key_records) + " deleted key records",
            "Pre-encryption keys extracted — passphrase not required",
            "All funds at recovered addresses are immediately spendable"};
        return f;
    }
};

// ── IMP4: WalletIterationScorer ─────────────────────────────────────────────
class WalletIterationScorer {
public:
    struct IterationRiskScore {
        std::string wallet_path;
        uint32_t iterations = 0; uint8_t method = 0;
        double rtx4090_gps = 0, seconds_8lower = 0, seconds_8alnum = 0;
        std::string risk_tier, recommendation;
    };
    IterationRiskScore score_wallet(const std::string& wp) {
        IterationRiskScore r; r.wallet_path = wp;
        std::ifstream f(wp, std::ios::binary);
        if (!f) return r;
        std::vector<unsigned char> data((std::istreambuf_iterator<char>(f)), std::istreambuf_iterator<char>());
        // Search for mkey marker
        for (size_t i = 0; i + 20 < data.size(); ++i) {
            if (data[i] == 0x04 && data[i+1] == 'm' && data[i+2] == 'k' && data[i+3] == 'e' && data[i+4] == 'y') {
                // Parse past the mkey record to find iterations
                size_t off = i + 5;
                // Skip key ID, vchCryptedKey, vchSalt
                if (off + 1 >= data.size()) break;
                uint8_t id_size = data[off]; off += 1 + id_size;
                if (off + 1 >= data.size()) break;
                uint8_t key_len = data[off]; off += 1 + key_len;
                if (off + 1 >= data.size()) break;
                uint8_t salt_len = data[off]; off += 1 + salt_len;
                if (off + 8 >= data.size()) break;
                r.method = static_cast<uint8_t>(data[off] | (data[off+1] << 8) | (data[off+2] << 16) | (data[off+3] << 24));
                off += 4;
                r.iterations = data[off] | (data[off+1] << 8) | (data[off+2] << 16) | (data[off+3] << 24);
                break;
            }
        }
        if (r.iterations == 0) r.iterations = 25000;
        double base_rate = (r.method == 0) ? 40e9 : 2e9;
        r.rtx4090_gps = base_rate / std::max(1.0, static_cast<double>(r.iterations));
        r.seconds_8lower = 208827064576.0 / std::max(1.0, r.rtx4090_gps);
        r.seconds_8alnum = 218340105584896.0 / std::max(1.0, r.rtx4090_gps);
        if (r.seconds_8lower < 3600) r.risk_tier = "CRITICAL";
        else if (r.seconds_8alnum < 86400.0 * 365) r.risk_tier = "HIGH";
        else r.risk_tier = "MEDIUM";
        r.recommendation = r.risk_tier == "CRITICAL" ? "Wallet passphrase crackable within hours — rotate immediately" :
            r.risk_tier == "HIGH" ? "Wallet at risk with GPU cluster — use 20+ char passphrase" :
            "Iteration count adequate for moderate passphrases";
        return r;
    }
    Finding create_iteration_finding(const IterationRiskScore& s, const std::string& release) {
        Finding f;
        f.finding_id = IDGenerator::instance().next();
        f.release = release; f.file = s.wallet_path; f.function_name = "KDF_iteration_analysis";
        f.issue_type = IssueType::WeakKDF; f.classification = Classification::ConfirmedIssue;
        f.severity = s.risk_tier == "CRITICAL" ? Severity::Critical : s.risk_tier == "HIGH" ? Severity::High : Severity::Medium;
        f.confidence = 0.95f; f.secret_material_type = SecretMaterialType::MasterKey;
        f.reachability = "local_file_access"; f.review_tier = s.risk_tier == "CRITICAL" ? "immediate" : "scheduled";
        f.novelty_tag = "KnownVariant"; f.reproducible = true; f.manual_review_required = false;
        char buf[64]; std::snprintf(buf, sizeof(buf), "%.0f", s.rtx4090_gps);
        f.evidence = "ITERATION SCORE: wallet " + s.wallet_path + " uses " + std::to_string(s.iterations) +
            " KDF iterations (method " + std::to_string(s.method) + "). RTX 4090 rate: " + buf +
            " guesses/sec. 8-char lowercase crackable in " + std::to_string(static_cast<int>(s.seconds_8lower)) +
            " seconds. Risk tier: " + s.risk_tier + ". " + s.recommendation + ". Version: " + release + ".";
        f.execution_path = {"Attacker obtains wallet.dat", "Extract mkey record with " +
            std::to_string(s.iterations) + " iterations", "GPU brute-force at " + std::string(buf) + " guesses/sec",
            "Passphrase recovered → master key decrypted → all private keys accessible"};
        return f;
    }
};

// ── IMP8: EnvironmentProfileResolver ────────────────────────────────────────
class EnvironmentProfileResolver {
public:
    struct EnvironmentProfile {
        std::string os_name = "unknown";
        bool rlimit_core_default_zero = false, coredumpctl_enabled = false;
        bool systemd_coredump_enabled = false, swap_enabled = false;
        std::string ulimit_core = "unknown";
    };
    EnvironmentProfile detect_current_environment() {
        EnvironmentProfile p;
#ifdef __linux__
        p.os_name = "Linux";
        std::ifstream cp("/proc/sys/kernel/core_pattern");
        if (cp) { std::string pattern; std::getline(cp, pattern);
            p.rlimit_core_default_zero = (pattern.find("/dev/null") != std::string::npos || pattern == "0");
            p.systemd_coredump_enabled = (pattern.find("systemd-coredump") != std::string::npos);
            p.coredumpctl_enabled = p.systemd_coredump_enabled; }
        std::ifstream sw("/proc/swaps");
        if (sw) { std::string line; std::getline(sw, line); std::getline(sw, line); p.swap_enabled = !line.empty(); }
#elif defined(__APPLE__)
        p.os_name = "macOS";
        p.rlimit_core_default_zero = true;
#else
        p.os_name = "Unknown";
#endif
        FILE* ul = popen("ulimit -c 2>/dev/null", "r");
        if (ul) { char buf[64]; if (fgets(buf, sizeof(buf), ul)) p.ulimit_core = std::string(buf); pclose(ul);
            while (!p.ulimit_core.empty() && (p.ulimit_core.back() == '\n' || p.ulimit_core.back() == '\r')) p.ulimit_core.pop_back(); }
        return p;
    }
    void resolve_crash_dump_findings(std::vector<Finding>& findings, const EnvironmentProfile& p) {
        for (auto& f : findings) {
            if (f.issue_type != IssueType::CrashDumpPersistence) continue;
            if (p.rlimit_core_default_zero && !p.coredumpctl_enabled) {
                f.classification = Classification::NonExploitable;
                f.evidence += " [EnvironmentProfileResolver: core dumps disabled by default on " + p.os_name + "]";
            } else if (p.systemd_coredump_enabled) {
                f.classification = Classification::ConfirmedIssue;
                f.confidence = std::max(f.confidence, 0.92);
                f.evidence += " [EnvironmentProfileResolver: systemd-coredump enabled — dumps captured automatically]";
            } else if (p.ulimit_core == "unlimited") {
                f.classification = Classification::ConfirmedIssue;
                f.confidence = std::max(f.confidence, 0.88);
                f.evidence += " [EnvironmentProfileResolver: ulimit -c unlimited — dumps written to cwd]";
            } else {
                f.manual_review_required = true;
                f.evidence += " [EnvironmentProfileResolver: profile inconclusive — ulimit=" + p.ulimit_core + "]";
            }
        }
    }
};

