// ── BackCheckEnhanced: dead code + const/enum false positive filter ─────
class BackCheckEnhanced {
public:
    void filter_false_positives(std::vector<Finding>& findings,
                                 const std::vector<Release>& releases) {
        int filtered = 0;
        for (auto& f : findings) {
            for (auto& rel : releases) {
                if (rel.name != f.release) continue;
                for (auto& tu : rel.translation_units) {
                    if (tu.file_path != f.file) continue;
                    size_t pos = tu.raw_content.find(f.function_name);
                    if (pos == std::string::npos) continue;
                    size_t start = (pos > 500) ? pos - 500 : 0;
                    std::string before = tu.raw_content.substr(start, pos - start);
                    // Dead code: #if 0 without matching #endif
                    if (before.rfind("#if 0") != std::string::npos &&
                        before.rfind("#endif") == std::string::npos) {
                        f.confidence = std::max(0.05, f.confidence - 0.40);
                        f.classification = Classification::NonExploitable;
                        f.evidence += " [BackCheck: in #if 0 dead code]";
                        filtered++;
                    }
                    // DEPRECATED/DISABLED markers
                    if (before.find("DEPRECATED") != std::string::npos ||
                        before.find("DISABLED") != std::string::npos) {
                        f.confidence = std::max(0.10, f.confidence - 0.25);
                        f.evidence += " [BackCheck: DEPRECATED/DISABLED]";
                        filtered++;
                    }
                    // const/enum variables are not secrets
                    size_t line_start = tu.raw_content.rfind('\n', pos);
                    if (line_start != std::string::npos) {
                        std::string line = tu.raw_content.substr(line_start, pos - line_start);
                        if ((line.find("const ") != std::string::npos || line.find("enum ") != std::string::npos) &&
                            (f.issue_type == IssueType::StaleDecryptedKey || f.issue_type == IssueType::HeapRetainedPrivateKey)) {
                            f.confidence = std::max(0.05, f.confidence - 0.35);
                            f.evidence += " [BackCheck: const/enum not a secret]";
                            filtered++;
                        }
                    }
                    break;
                }
                break;
            }
        }
        Logger::instance().info("BackCheckEnhanced: " + std::to_string(filtered) + " false positives filtered");
    }
};


