// ── Pre-scan file filter ─────────────────────────────────────────────────────
static bool should_skip_file(const std::string& file_path) {
    // Skip non-security directories
    static const char* skip_dirs[] = {
        "zmq/", "bench/", "doc/", "share/", "contrib/",
        "test/", "qt/", "univalue/", "leveldb/", "secp256k1/",
        nullptr
    };
    for (int i = 0; skip_dirs[i]; ++i) {
        if (file_path.find(skip_dirs[i]) != std::string::npos) return true;
    }
    return false;
}

static bool has_security_relevant_content(const std::string& raw_content) {
    static const char* keywords[] = {
        "CKey", "CPrivKey", "vMasterKey", "walletpassphrase", "GetPrivKey",
        "DecryptKey", "memory_cleanse", "OPENSSL_cleanse", "nValueIn",
        "GetBlockSubsidy", "CheckInputs", "VerifyScript", "stack.size",
        "OP_CHECKSIG", "CAmount", "cs_main", "mapWallet",
        nullptr
    };
    for (int i = 0; keywords[i]; ++i) {
        if (raw_content.find(keywords[i]) != std::string::npos) return true;
    }
    return false;
}

// ── Enhanced Canonical Deduplicator ──────────────────────────────────────────
class CanonicalDeduplicator {
public:
    struct CanonicalFinding {
        Finding representative;
        std::vector<std::string> versions_confirmed;
        std::vector<std::string> versions_absent;
        std::string first_seen_release;
        float novelty_score = 0.0f;
        bool binary_confirmed = false;
        std::string exploit_scenario;
        struct DynamicAnalysis {
            bool recommended = false;
            std::string reason;
            std::string method;
            bool binary_required = false;
        } dynamic_analysis;
    };

    static std::string canonical_key(const Finding& f) {
        std::string bn = f.file;
        size_t sl = bn.rfind('/');
        if (sl != std::string::npos) bn = bn.substr(sl + 1);
        return f.issue_type_string() + ":" + bn + ":" + f.function_name;
    }

    // Remove IncompleteZeroization findings with no concrete exploitation path
    static bool is_memory_residency_nonbug(const Finding& f) {
        if (f.issue_type != IssueType::IncompleteZeroization &&
            f.issue_type != IssueType::UnboundedKeyLifetime &&
            f.issue_type != IssueType::StaleDecryptedKey) return false;
        // Only keep if there is a concrete attacker path beyond process memory access
        bool has_path = f.reachability.find("rpc") != std::string::npos ||
                        f.reachability.find("p2p") != std::string::npos ||
                        f.reachability.find("crash") != std::string::npos ||
                        f.reachability.find("file") != std::string::npos ||
                        f.reachability.find("network") != std::string::npos;
        if (!has_path) return true; // no concrete path = non-bug
        // Also kill pure "variable in scope N lines" findings
        if (f.evidence.find("in scope for") != std::string::npos) return true;
        if (f.evidence.find("held in memory during normal") != std::string::npos) return true;
        return false;
    }

    static void populate_dynamic_analysis(CanonicalFinding& cf) {
        auto& da = cf.dynamic_analysis;
        const Finding& f = cf.representative;
        bool is_inconclusive = f.classification == Classification::Inconclusive;
        bool is_rpc = f.reachability.find("rpc") != std::string::npos;
        bool is_p2p = f.reachability.find("p2p") != std::string::npos;
        bool high_novelty = cf.novelty_score >= 0.7f;
        bool confirmed_high = f.classification == Classification::ConfirmedIssue && f.confidence >= 0.90;

        da.recommended = !confirmed_high && (is_inconclusive || is_rpc || is_p2p || high_novelty);
        da.binary_required = cf.binary_confirmed;

        if (is_rpc) {
            da.method = "Run against regtest node with crafted RPC call; check error codes and response fields";
            da.reason = "RPC handler code path only reachable at runtime";
        } else if (is_p2p) {
            da.method = "Fuzz with AFL++ targeting P2P message deserialization; inject malformed messages";
            da.reason = "P2P deserialization path triggers only with network peer input";
        } else if (f.issue_type == IssueType::ConsensusDoubleSpend ||
                   f.issue_type == IssueType::ConsensusInflation) {
            da.method = "Craft minimal regtest transaction; submit via sendrawtransaction; verify acceptance";
            da.reason = "Consensus rule violation requires full node execution to confirm";
        } else {
            da.method = "Attach LLDB/GDB with watchpoint on relevant memory region; trigger code path";
            da.reason = "Dynamic confirmation would distinguish reachable from dead code path";
        }
    }

    std::vector<CanonicalFinding> deduplicate(
            const std::vector<Finding>& raw, const std::vector<std::string>& all_versions) {
        std::map<std::string, CanonicalFinding> map;

        for (const auto& f : raw) {
            // Kill memory-residency non-bugs
            if (is_memory_residency_nonbug(f)) continue;

            std::string key = canonical_key(f);
            if (map.find(key) == map.end()) {
                CanonicalFinding cf;
                cf.representative = f;
                cf.versions_confirmed.push_back(f.release);
                cf.first_seen_release = f.release;
                cf.novelty_score = static_cast<float>(f.confidence);
                map[key] = std::move(cf);
            } else {
                auto& cf = map[key];
                // Upgrade representative if higher confidence/severity
                if (f.confidence > cf.representative.confidence) cf.representative = f;
                if (std::find(cf.versions_confirmed.begin(), cf.versions_confirmed.end(), f.release)
                        == cf.versions_confirmed.end())
                    cf.versions_confirmed.push_back(f.release);
                cf.novelty_score = std::max(cf.novelty_score, static_cast<float>(f.confidence));
            }
        }

        // Compute versions_absent and populate dynamic analysis
        std::vector<CanonicalFinding> result;
        result.reserve(map.size());
        for (auto& kv : map) {
            auto& cf = kv.second;
            for (auto& v : all_versions) {
                if (std::find(cf.versions_confirmed.begin(), cf.versions_confirmed.end(), v)
                        == cf.versions_confirmed.end())
                    cf.versions_absent.push_back(v);
            }
            populate_dynamic_analysis(cf);
            result.push_back(std::move(cf));
        }
        return result;
    }
};

// ── Chunked Pipeline ──────────────────────────────────────────────────────────
class ChunkedPipeline {
public:
    static constexpr int CHUNK_SIZE = 500;

    struct Checkpoint {
        std::set<std::string> processed_files;
        int chunks_written = 0;
    };

    static Checkpoint load_checkpoint(const std::string& path) {
        Checkpoint cp;
        std::ifstream f(path);
        if (!f) return cp;
        std::string line;
        while (std::getline(f, line)) {
            if (!line.empty() && line[0] == 'F') cp.processed_files.insert(line.substr(2));
            if (!line.empty() && line[0] == 'C') { try { cp.chunks_written = std::stoi(line.substr(2)); } catch (...) {} }
        }
        return cp;
    }

    static void save_checkpoint(const std::string& path, const Checkpoint& cp) {
        std::ofstream f(path);
        for (auto& fn : cp.processed_files) f << "F:" << fn << "\n";
        f << "C:" << cp.chunks_written << "\n";
    }

    static void write_chunk(const std::vector<Finding>& chunk, int chunk_id, const std::string& out_dir) {
        std::string fname = out_dir + "/report_chunk_" + std::to_string(chunk_id) + ".json";
        std::ofstream out(fname);
        if (!out) return;
        out << "[\n";
        bool first = true;
        for (auto& f : chunk) {
            if (!first) out << ",\n";
            first = false;
            out << "  {\"finding_id\":" << f.finding_id
                << ",\"issue_type\":\"" << f.issue_type_string() << "\""
                << ",\"severity\":\"" << f.severity_string() << "\""
                << ",\"confidence\":" << f.confidence
                << ",\"file\":\"" << f.file << "\""
                << ",\"function\":\"" << f.function_name << "\""
                << ",\"release\":\"" << f.release << "\""
                << ",\"evidence\":\"" << json_escape(f.evidence) << "\""
                << "}";
        }
        out << "\n]\n";
    }

    static std::string json_escape(const std::string& s) {
        std::string r;
        for (char c : s) {
            if (c == '"') r += "\\\"";
            else if (c == '\\') r += "\\\\";
            else if (c == '\n') r += "\\n";
            else r += c;
        }
        return r;
    }
};

// ── ConsensusBugDetector ──────────────────────────────────────────────────────
class ConsensusBugDetector {
public:
    std::vector<Finding> detect(const std::shared_ptr<TranslationUnit>& tu, const std::string& rel) {
        std::vector<Finding> findings;
        if (!tu || tu->raw_content.empty()) return findings;
        const std::string& rc = tu->raw_content;

        // CBS-1: Script stack bounds — OP_ handler without stack.size() check
        {
            std::vector<std::string> op_handlers = {"OP_CHECKSIG", "OP_CHECKMULTISIG", "OP_EQUALVERIFY",
                "case OP_CHECKLOCKTIMEVERIFY", "case OP_CHECKSEQUENCEVERIFY"};
            for (auto& op : op_handlers) {
                size_t pos = rc.find(op);
                if (pos == std::string::npos) continue;
                size_t window_end = std::min(pos + 800, rc.size());
                std::string window = rc.substr(pos, window_end - pos);
                bool has_stack_check = window.find("stack.size()") != std::string::npos ||
                                       window.find("stacktop(") != std::string::npos ||
                                       window.find(".size() <") != std::string::npos ||
                                       window.find("CleanupScriptCode") != std::string::npos;
                if (!has_stack_check) {
                    std::string fn = extract_enclosing_function_name(rc, pos);
                    ConfidenceBuilder cb;
                    cb.add(0.35f, "OP_ handler: " + op);
                    cb.add(0.25f, "no stack.size() guard in 800-char window");
                    cb.add(0.15f, "script eval stack underflow possible");
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = rel;
                    f.file = tu->file_path; f.function_name = fn;
                    f.issue_type = IssueType::ScriptExploitation;
                    f.classification = Classification::Inconclusive;
                    f.severity = Severity::Critical; f.confidence = cb.build();
                    f.secret_material_type = SecretMaterialType::None;
                    f.reachability = "p2p"; f.review_tier = "immediate";
                    f.novelty_tag = "InconclusiveNovel"; f.reproducible = true;
                    f.manual_review_required = true;
                    f.evidence = "CBS-1: STACK BOUNDS — " + op + " in " + fn + "@" + tu->file_path +
                        " without stack.size() guard. Script stack underflow => crash or undefined behavior. "
                        "Peer can send crafted script. Version: " + rel + "." + cb.rationale();
                    f.execution_path = {"Peer sends crafted transaction with script using " + op,
                        "Script interpreter enters handler without checking stack depth",
                        "stack.pop() on empty stack → UB or crash",
                        "Node crashes → DoS or consensus split from peers that handled correctly"};
                    findings.push_back(f); break;
                }
            }
        }

        // CBS-2: Merkle CVE-2012-2459 — duplicate txid in block
        {
            bool has_merkle = rc.find("ComputeMerkleRoot") != std::string::npos ||
                              rc.find("BlockMerkleRoot") != std::string::npos ||
                              rc.find("merkle") != std::string::npos;
            if (has_merkle) {
                bool has_dup_check = rc.find("duplicat") != std::string::npos ||
                                     rc.find("CVE-2012-2459") != std::string::npos ||
                                     rc.find("MutateMerkleTree") != std::string::npos ||
                                     rc.find("fMutated") != std::string::npos;
                if (!has_dup_check) {
                    size_t mpos = rc.find("ComputeMerkleRoot");
                    if (mpos == std::string::npos) mpos = rc.find("merkle");
                    std::string fn = extract_enclosing_function_name(rc, mpos);
                    ConfidenceBuilder cb;
                    cb.add(0.40f, "merkle computation found");
                    cb.add(0.30f, "no duplicate txid check (CVE-2012-2459 pattern)");
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = rel;
                    f.file = tu->file_path; f.function_name = fn;
                    f.issue_type = IssueType::ConsensusDoubleSpend;
                    f.classification = Classification::Inconclusive;
                    f.severity = Severity::High; f.confidence = cb.build();
                    f.secret_material_type = SecretMaterialType::None;
                    f.reachability = "p2p"; f.review_tier = "immediate";
                    f.novelty_tag = "InconclusiveNovel"; f.reproducible = true;
                    f.manual_review_required = true;
                    f.evidence = "CBS-2: MERKLE DUPLICATE TXID (CVE-2012-2459 class) — " + fn +
                        "@" + tu->file_path + " computes merkle root without checking for "
                        "duplicate consecutive txids. Block with last tx duplicated passes "
                        "naive merkle check, enabling SPV proof spoofing. Version: " + rel + "." + cb.rationale();
                    f.execution_path = {"Attacker crafts block where tx[N-1] == tx[N]",
                        "Naive merkle computation produces same root as valid block",
                        "Node accepts block without detecting duplicate",
                        "SPV clients can be fed fraudulent inclusion proofs"};
                    findings.push_back(f);
                }
            }
        }

        // CBS-3: cs_main missing on chain tip update
        {
            std::vector<std::string> chain_update_tokens = {"pindexBestHeader", "chainActive.SetTip", "m_best_header"};
            for (auto& tok : chain_update_tokens) {
                size_t pos = rc.find(tok);
                if (pos == std::string::npos) continue;
                size_t ws = (pos > 500) ? pos - 500 : 0;
                std::string before = rc.substr(ws, pos - ws);
                bool has_cs_main = before.find("cs_main") != std::string::npos ||
                                   before.find("LOCK(cs") != std::string::npos ||
                                   before.find("AssertLockHeld(cs") != std::string::npos;
                if (!has_cs_main) {
                    std::string fn = extract_enclosing_function_name(rc, pos);
                    ConfidenceBuilder cb;
                    cb.add(0.35f, "chain tip update: " + tok);
                    cb.add(0.28f, "no cs_main lock in 500-char window before update");
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = rel;
                    f.file = tu->file_path; f.function_name = fn;
                    f.issue_type = IssueType::RaceCondition;
                    f.classification = Classification::Inconclusive;
                    f.severity = Severity::Critical; f.confidence = cb.build();
                    f.secret_material_type = SecretMaterialType::None;
                    f.reachability = "p2p"; f.review_tier = "immediate";
                    f.novelty_tag = "InconclusiveNovel"; f.reproducible = true;
                    f.manual_review_required = true;
                    f.evidence = "CBS-3: CS_MAIN RACE — chain tip update (" + tok + ") in " + fn +
                        "@" + tu->file_path + " without cs_main lock. Concurrent access from "
                        "net_processing and validation threads can cause consensus split. Version: " +
                        rel + "." + cb.rationale();
                    f.execution_path = {"Two threads process competing blocks simultaneously",
                        tok + " updated without cs_main by thread A",
                        "Thread B reads stale chain tip",
                        "Nodes diverge on accepted chain → consensus split"};
                    findings.push_back(f); break;
                }
            }
        }

        // CBS-4: BIP66 strict DER missing on CHECKSIG variant
        {
            if (rc.find("CheckSignatureEncoding") != std::string::npos ||
                rc.find("EvalScript") != std::string::npos) {
                bool has_strict_der = rc.find("SCRIPT_VERIFY_STRICTENC") != std::string::npos ||
                                     rc.find("IsValidSignatureEncoding") != std::string::npos ||
                                     rc.find("CheckDERSignature") != std::string::npos;
                bool has_checksig = rc.find("OP_CHECKSIG") != std::string::npos ||
                                    rc.find("OP_CHECKMULTISIG") != std::string::npos;
                if (has_checksig && !has_strict_der) {
                    size_t pos = rc.find("OP_CHECKSIG");
                    std::string fn = extract_enclosing_function_name(rc, pos);
                    ConfidenceBuilder cb;
                    cb.add(0.35f, "CHECKSIG without SCRIPT_VERIFY_STRICTENC");
                    cb.add(0.25f, "BIP66 non-compliance allows malleable signatures");
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = rel;
                    f.file = tu->file_path; f.function_name = fn;
                    f.issue_type = IssueType::SighashKeyRecovery;
                    f.classification = Classification::Inconclusive;
                    f.severity = Severity::High; f.confidence = cb.build();
                    f.secret_material_type = SecretMaterialType::None;
                    f.reachability = "p2p"; f.review_tier = "scheduled";
                    f.novelty_tag = "KnownVariant"; f.reproducible = true;
                    f.manual_review_required = true;
                    f.evidence = "CBS-4: BIP66 STRICT DER — CHECKSIG path in " + fn +
                        "@" + tu->file_path + " without SCRIPT_VERIFY_STRICTENC. "
                        "Non-strict DER allows signature malleability, enabling txid mutation "
                        "without invalidating signatures (pre-segwit). Version: " + rel + "." + cb.rationale();
                    f.execution_path = {"Attacker observes signed transaction",
                        "Mutates DER signature encoding (re-encode S without changing value)",
                        "Transaction now has different txid but same validity",
                        "Double-spend by re-submitting with same inputs but new txid"};
                    findings.push_back(f);
                }
            }
        }

        return findings;
    }
};

// ── NovelBugHunter ────────────────────────────────────────────────────────────
class NovelBugHunter {
public:
    struct NovelFinding {
        Finding base;
        float novelty_score = 0.0f;
        std::string taint_source;
        std::string taint_sink;
        std::vector<std::string> taint_path;
    };

    std::vector<Finding> hunt(const std::shared_ptr<TranslationUnit>& tu, const std::string& rel) {
        std::vector<Finding> findings;
        if (!tu || tu->raw_content.empty()) return findings;
        const std::string& rc = tu->raw_content;

        // NB-1: Type narrowing cast — uint64_t/size_t → int in security context
        {
            std::vector<std::string> narrow_casts = {"(int)(", "(int) (", "static_cast<int>(",
                "(int32_t)(", "(uint32_t)("};
            std::vector<std::string> security_context = {"nValue", "nFee", "nSize", "nCount",
                "length", "offset", "nLen", "nBytes"};
            for (auto& cast : narrow_casts) {
                size_t pos = rc.find(cast);
                while (pos != std::string::npos) {
                    size_t ctx_start = (pos > 200) ? pos - 200 : 0;
                    std::string ctx = rc.substr(ctx_start, pos - ctx_start + 100);
                    for (auto& sec : security_context) {
                        if (ctx.find(sec) != std::string::npos) {
                            std::string fn = extract_enclosing_function_name(rc, pos);
                            ConfidenceBuilder cb;
                            cb.add(0.30f, "narrowing cast " + cast);
                            cb.add(0.20f, "near security token " + sec);
                            cb.add(0.15f, "potential truncation vulnerability");
                            Finding f;
                            f.finding_id = IDGenerator::instance().next(); f.release = rel;
                            f.file = tu->file_path; f.function_name = fn;
                            f.issue_type = IssueType::IntegerOverflow;
                            f.classification = Classification::Inconclusive;
                            f.severity = Severity::Medium; f.confidence = cb.build();
                            f.secret_material_type = SecretMaterialType::None;
                            f.reachability = "p2p"; f.review_tier = "scheduled";
                            f.novelty_tag = "InconclusiveNovel"; f.reproducible = true;
                            f.manual_review_required = true;
                            f.evidence = "NB-1: TYPE NARROWING — cast " + cast + " near " + sec +
                                " in " + fn + "@" + tu->file_path +
                                ". uint64_t/size_t truncated to int; values > INT_MAX wrap negative. "
                                "If peer-controlled, enables allocation/loop bound manipulation. Version: " +
                                rel + "." + cb.rationale();
                            f.execution_path = {"Peer sends message with length field > INT_MAX",
                                "Length cast to int wraps to negative",
                                "Negative value passed to allocation or bounds check",
                                "Heap corruption or bypass of length validation"};
                            findings.push_back(f); break;
                        }
                    }
                    pos = rc.find(cast, pos + 1);
                }
            }
        }

        // NB-2: assert() in consensus-critical path (compiled out in release)
        {
            std::vector<std::string> consensus_files = {"validation.cpp", "script/interpreter.cpp",
                "consensus/", "primitives/"};
            bool is_consensus = false;
            for (auto& cf : consensus_files)
                if (tu->file_path.find(cf) != std::string::npos) { is_consensus = true; break; }
            if (is_consensus) {
                size_t pos = rc.find("assert(");
                while (pos != std::string::npos) {
                    // Skip BOOST_CHECK and similar — only bare assert()
                    size_t ls = rc.rfind('\n', pos);
                    std::string line = rc.substr(ls != std::string::npos ? ls : 0, pos - (ls != std::string::npos ? ls : 0));
                    if (line.find("//") == std::string::npos) { // not commented
                        std::string fn = extract_enclosing_function_name(rc, pos);
                        ConfidenceBuilder cb;
                        cb.add(0.40f, "assert() in consensus file " + tu->file_path);
                        cb.add(0.25f, "assert() removed in release builds → unchecked assumption");
                        Finding f;
                        f.finding_id = IDGenerator::instance().next(); f.release = rel;
                        f.file = tu->file_path; f.function_name = fn;
                        f.issue_type = IssueType::ConsensusDoubleSpend;
                        f.classification = Classification::Inconclusive;
                        f.severity = Severity::High; f.confidence = cb.build();
                        f.secret_material_type = SecretMaterialType::None;
                        f.reachability = "p2p"; f.review_tier = "scheduled";
                        f.novelty_tag = "InconclusiveNovel"; f.reproducible = true;
                        f.manual_review_required = true;
                        f.evidence = "NB-2: ASSERT IN CONSENSUS — assert() in " + fn +
                            "@" + tu->file_path + ". In release builds (NDEBUG), assert() is a no-op. "
                            "The safety invariant is unchecked in production. "
                            "If the assertion would fail, behavior is undefined. Version: " + rel + "." + cb.rationale();
                        f.execution_path = {"Production binary built with NDEBUG",
                            "assert() compiled to nothing in " + fn,
                            "Assumed invariant violated by peer input",
                            "Undefined behavior — potential crash or consensus divergence"};
                        findings.push_back(f);
                        break; // one per file to avoid noise
                    }
                    pos = rc.find("assert(", pos + 1);
                }
            }
        }

        // NB-3: Unbounded vector growth from peer-supplied length
        {
            std::vector<std::string> resize_tokens = {".resize(", ".reserve(", "std::vector<", "new uint8_t["};
            std::vector<std::string> peer_sources = {"ReadVarInt", "ReadCompactSize", "nCount", "nLen",
                "payload", "msg.data", "vRecv", "CDataStream"};
            for (auto& rt : resize_tokens) {
                size_t pos = rc.find(rt);
                while (pos != std::string::npos) {
                    size_t ctx_s = (pos > 300) ? pos - 300 : 0;
                    std::string ctx = rc.substr(ctx_s, pos - ctx_s + 200);
                    bool from_peer = false;
                    for (auto& ps : peer_sources)
                        if (ctx.find(ps) != std::string::npos) { from_peer = true; break; }
                    bool has_max = ctx.find("MAX_SIZE") != std::string::npos ||
                                   ctx.find("MAX_BLOCK") != std::string::npos ||
                                   ctx.find("nMaxRawTxFee") != std::string::npos ||
                                   ctx.find("if (n >") != std::string::npos ||
                                   ctx.find("nSize < ") != std::string::npos;
                    if (from_peer && !has_max) {
                        std::string fn = extract_enclosing_function_name(rc, pos);
                        ConfidenceBuilder cb;
                        cb.add(0.30f, "resize/reserve from peer source");
                        cb.add(0.22f, "no MAX_SIZE guard nearby");
                        Finding f;
                        f.finding_id = IDGenerator::instance().next(); f.release = rel;
                        f.file = tu->file_path; f.function_name = fn;
                        f.issue_type = IssueType::DoS;
                        f.classification = Classification::Inconclusive;
                        f.severity = Severity::High; f.confidence = cb.build();
                        f.secret_material_type = SecretMaterialType::None;
                        f.reachability = "p2p"; f.review_tier = "scheduled";
                        f.novelty_tag = "InconclusiveNovel"; f.reproducible = true;
                        f.manual_review_required = true;
                        f.evidence = "NB-3: UNBOUNDED VECTOR — " + rt + " in " + fn +
                            "@" + tu->file_path + " from peer-supplied length without MAX_SIZE guard. "
                            "Peer can exhaust node memory by sending crafted length field. Version: " +
                            rel + "." + cb.rationale();
                        f.execution_path = {"Peer sends message with fabricated length field",
                            "Node calls " + rt + " with peer-controlled size",
                            "Allocation of up to SIZE_MAX bytes attempted",
                            "OOM → node crash → DoS"};
                        findings.push_back(f); break;
                    }
                    pos = rc.find(rt, pos + 1);
                }
            }
        }

        // NB-4: Non-cryptographic RNG in security context
        {
            for (auto& rng_tok : {"rand()", "time(NULL)", "srand(", "std::rand("}) {
                size_t pos = rc.find(rng_tok);
                if (pos == std::string::npos) continue;
                size_t ctx_s = (pos > 500) ? pos - 500 : 0;
                std::string ctx = rc.substr(ctx_s, pos - ctx_s + 200);
                bool in_sec = ctx.find("nonce") != std::string::npos ||
                              ctx.find("key") != std::string::npos ||
                              ctx.find("seed") != std::string::npos ||
                              ctx.find("GetRandInt") != std::string::npos;
                if (in_sec) {
                    std::string fn = extract_enclosing_function_name(rc, pos);
                    ConfidenceBuilder cb;
                    cb.add(0.40f, "non-CSPRNG: " + std::string(rng_tok));
                    cb.add(0.30f, "near security-sensitive context");
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = rel;
                    f.file = tu->file_path; f.function_name = fn;
                    f.issue_type = IssueType::HeapRetainedPrivateKey;
                    f.classification = Classification::Inconclusive;
                    f.severity = Severity::Critical; f.confidence = cb.build();
                    f.secret_material_type = SecretMaterialType::PrivateKey;
                    f.reachability = "local"; f.review_tier = "immediate";
                    f.novelty_tag = "NovelHighPriority"; f.reproducible = true;
                    f.manual_review_required = true;
                    f.evidence = "NB-4: WEAK RNG — " + std::string(rng_tok) + " near security context in " +
                        fn + "@" + tu->file_path + ". Not cryptographically secure. "
                        "If used in nonce/key/seed generation, attacker can predict output. Version: " +
                        rel + "." + cb.rationale();
                    f.execution_path = {"rand() or time() seeded with predictable value",
                        "Nonce/key material generated with predictable output",
                        "Attacker predicts nonce → signature recovery → private key",
                        "All funds at addresses signed with predictable nonce compromised"};
                    findings.push_back(f); break;
                }
            }
        }

        return findings;
    }
};

// ── v2 JSON Report Emitter ────────────────────────────────────────────────────
class ReportV2Emitter {
public:
    void emit(const std::vector<CanonicalDeduplicator::CanonicalFinding>& findings,
              const std::vector<std::string>& releases_scanned,
              int raw_count, double elapsed_s, const std::string& path) {
        std::ofstream out(path);
        if (!out) { Logger::instance().error("Cannot write " + path); return; }

        auto esc = [](const std::string& s) {
            std::string r;
            for (char c : s) {
                if (c == '"') r += "\\\"";
                else if (c == '\\') r += "\\\\";
                else if (c == '\n') r += "\\n";
                else if (c == '\r') r += "";
                else r += c;
            }
            return r;
        };

        int unique = static_cast<int>(findings.size());
        double dedup = raw_count > 0 ? static_cast<double>(raw_count) / unique : 1.0;

        out << "{\n  \"meta\": {\n";
        out << "    \"tool_version\": \"2.0.0\",\n";
        out << "    \"releases_scanned\": [";
        for (size_t i = 0; i < releases_scanned.size(); ++i) {
            if (i) out << ", ";
            out << "\"" << releases_scanned[i] << "\"";
        }
        out << "],\n";
        out << "    \"total_unique_findings\": " << unique << ",\n";
        out << "    \"total_findings_before_dedup\": " << raw_count << ",\n";
        out << "    \"dedup_ratio\": \"" << std::fixed << std::setprecision(1) << dedup << ":1\",\n";
        out << "    \"scan_duration_seconds\": " << static_cast<int>(elapsed_s) << "\n";
        out << "  },\n  \"findings\": [\n";

        bool first = true;
        for (auto& cf : findings) {
            if (!first) out << ",\n";
            first = false;
            const Finding& f = cf.representative;
            out << "    {\n";
            out << "      \"finding_id\": " << f.finding_id << ",\n";
            out << "      \"issue_type\": \"" << f.issue_type_string() << "\",\n";
            out << "      \"classification\": \"" << f.classification_string() << "\",\n";
            out << "      \"severity\": \"" << f.severity_string() << "\",\n";
            out << "      \"confidence\": " << std::fixed << std::setprecision(3) << f.confidence << ",\n";
            out << "      \"novelty_score\": " << std::fixed << std::setprecision(3) << cf.novelty_score << ",\n";
            out << "      \"first_seen_release\": \"" << cf.first_seen_release << "\",\n";

            out << "      \"versions_confirmed\": [";
            for (size_t i = 0; i < cf.versions_confirmed.size(); ++i) {
                if (i) out << ", ";
                out << "\"" << cf.versions_confirmed[i] << "\"";
            }
            out << "],\n";

            out << "      \"versions_absent\": [";
            for (size_t i = 0; i < cf.versions_absent.size(); ++i) {
                if (i) out << ", ";
                out << "\"" << cf.versions_absent[i] << "\"";
            }
            out << "],\n";

            out << "      \"file\": \"" << esc(f.file) << "\",\n";
            out << "      \"function\": \"" << esc(f.function_name) << "\",\n";
            out << "      \"reachability\": \"" << esc(f.reachability) << "\",\n";
            out << "      \"evidence\": \"" << esc(f.evidence) << "\",\n";
            out << "      \"exploit_scenario\": ";
            if (!f.execution_path.empty()) {
                out << "\"";
                for (size_t i = 0; i < f.execution_path.size(); ++i) {
                    if (i) out << " → ";
                    out << esc(f.execution_path[i]);
                }
                out << "\",\n";
            } else { out << "null,\n"; }
            out << "      \"binary_confirmed\": " << (cf.binary_confirmed ? "true" : "false") << ",\n";
            out << "      \"dynamic_analysis\": {\n";
            out << "        \"recommended\": " << (cf.dynamic_analysis.recommended ? "true" : "false") << ",\n";
            out << "        \"reason\": \"" << esc(cf.dynamic_analysis.reason) << "\",\n";
            out << "        \"method\": \"" << esc(cf.dynamic_analysis.method) << "\",\n";
            out << "        \"binary_required\": " << (cf.dynamic_analysis.binary_required ? "true" : "false") << "\n";
            out << "      },\n";
            out << "      \"fix_recommendation\": \"" << esc(generate_fix(f)) << "\"\n";
            out << "    }";
        }
        out << "\n  ]\n}\n";
        Logger::instance().info("ReportV2Emitter: wrote " + path + " (" + std::to_string(unique) + " findings)");
    }

private:
    static std::string generate_fix(const Finding& f) {
        switch (f.issue_type) {
            case IssueType::ConsensusDoubleSpend: return "Add duplicate input check before value summation; gate on SCRIPT_VERIFY_STRICTENC for all CHECKSIG paths";
            case IssueType::ConsensusInflation: return "Add MoneyRange() check after all CAmount arithmetic; verify GetBlockSubsidy halving at every 210000-block boundary";
            case IssueType::ScriptExploitation: return "Add stack.size() >= N check before every stack.pop() in script interpreter; ensure disabled opcodes rejected in all contexts";
            case IssueType::RaceCondition: return "Acquire cs_main before any read or write to chain state; use AssertLockHeld() to enforce at compile time";
            case IssueType::DoS: return "Add MAX_SIZE guard before any resize/reserve driven by peer-supplied length fields";
            case IssueType::IntegerOverflow: return "Replace narrowing cast with checked conversion; use SafeAdd/SafeMul wrappers for CAmount arithmetic";
            case IssueType::HeapRetainedPrivateKey: return "Replace rand()/time() with GetStrongRandBytes(); use secure_allocator for all key material";
            default: return "Apply memory_cleanse() after key use; add explicit bounds checks on all peer-supplied values";
        }
    }
};




// ═══════════════════════════════════════════════════════════════════
// §1.9 — Lock-Order Graph + Cycle Detection
// ═══════════════════════════════════════════════════════════════════
class LockOrderAnalyzer {
public:
    struct LockEdge { std::string held; std::string acquired; std::string file; std::string function; };
    struct LockInversion { std::string mutex_a; std::string mutex_b; std::string file_ab; std::string file_ba; };

    std::vector<Finding> analyze_lock_order(const std::vector<std::shared_ptr<TranslationUnit>>& tus,
                                             const std::string& release) {
        std::vector<Finding> findings;
        // Build lock acquisition graph
        std::map<std::string, std::set<std::string>> graph; // held → {acquired}
        std::map<std::string, LockEdge> edge_info;
        static const char* locks[] = {"cs_main", "cs_wallet", "cs_KeyStore", "cs_vNodes",
            "cs_mapLocalHost", "cs_inventory", "cs_filter", nullptr};
        for (auto& tu : tus) {
            if (!tu) continue;
            const std::string& rc = tu->raw_content;
            for (int i = 0; locks[i]; ++i) {
                std::string lock_name = locks[i];
                size_t pos = rc.find("LOCK(" + lock_name);
                while (pos != std::string::npos) {
                    // Check what other locks are held in the 2000-char context before this LOCK
                    size_t ctx_start = (pos > 2000) ? pos - 2000 : 0;
                    std::string before = rc.substr(ctx_start, pos - ctx_start);
                    for (int j = 0; locks[j]; ++j) {
                        if (i == j) continue;
                        std::string other = locks[j];
                        if (before.rfind("LOCK(" + other) != std::string::npos) {
                            // other is held when lock_name is acquired
                            graph[other].insert(lock_name);
                            std::string edge_key = other + "->" + lock_name;
                            if (edge_info.find(edge_key) == edge_info.end()) {
                                edge_info[edge_key] = {other, lock_name, tu->file_path,
                                    extract_enclosing_function_name(rc, pos)};
                            }
                        }
                    }
                    pos = rc.find("LOCK(" + lock_name, pos + 1);
                }
            }
        }
        // Detect inversions: A→B exists AND B→A exists
        for (auto& kv : graph) {
            for (auto& target : kv.second) {
                if (graph.count(target) && graph[target].count(kv.first)) {
                    std::string ab_key = kv.first + "->" + target;
                    std::string ba_key = target + "->" + kv.first;
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = release;
                    f.file = edge_info.count(ab_key) ? edge_info[ab_key].file : "multiple";
                    f.function_name = edge_info.count(ab_key) ? edge_info[ab_key].function : "multiple";
                    f.issue_type = IssueType::RaceCondition;
                    f.severity = (kv.first == "cs_main" && target == "cs_wallet") ||
                                 (kv.first == "cs_wallet" && target == "cs_main")
                                 ? Severity::Critical : Severity::High;
                    f.classification = Classification::ConfirmedReachable;
                    ConfidenceBuilder cb; cb.set_base_cfg_reachable(); cb.set_attacker_indirect();
                    f.confidence = cb.build();
                    f.reachability = "p2p";
                    f.evidence = "LOCK ORDER INVERSION: " + kv.first + " → " + target + " AND " +
                        target + " → " + kv.first + ". Deadlock potential. " +
                        (kv.first == "cs_main" || target == "cs_main" ? 
                         "cs_main involved — documented invariant violation." : "") + cb.rationale();
                    f.execution_path = {"Thread A acquires " + kv.first,
                        "Thread A acquires " + target + " (edge: " + ab_key + ")",
                        "Thread B acquires " + target,
                        "Thread B attempts " + kv.first + " → DEADLOCK"};
                    f.attacker_input = "Concurrent P2P messages triggering both code paths";
                    f.fix_recommendation = "Enforce global lock ordering: cs_main before cs_wallet always";
                    findings.push_back(f);
                    // Remove reverse to avoid double-reporting
                    graph[target].erase(kv.first);
                }
            }
        }
        return findings;
    }
};

// ═══════════════════════════════════════════════════════════════════
// §1.10 — CAmount Range Propagation
// ═══════════════════════════════════════════════════════════════════
class IntegerRangeAnalyzer {
public:
    std::vector<Finding> analyze(const std::shared_ptr<TranslationUnit>& tu, const std::string& rel) {
        std::vector<Finding> findings;
        if (!tu || tu->raw_content.empty()) return findings;
        const std::string& rc = tu->raw_content;
        // Track CAmount arithmetic without MoneyRange guard
        std::vector<std::string> amount_vars = {"nValueIn", "nValueOut", "nValue", "nFee",
            "nTotalFee", "nModifiedFee", "nCredit", "nDebit", "nChange"};
        std::vector<std::string> arith_ops = {"+=", "-=", "+ ", "- ", "* "};
        for (auto& var : amount_vars) {
            size_t pos = rc.find(var);
            while (pos != std::string::npos) {
                size_t line_end = rc.find('\n', pos);
                if (line_end == std::string::npos) line_end = rc.size();
                std::string line = rc.substr(pos, std::min(line_end - pos, (size_t)120));
                bool has_arith = false;
                for (auto& op : arith_ops)
                    if (line.find(op) != std::string::npos) { has_arith = true; break; }
                if (has_arith) {
                    // Check 400-char forward window for range check
                    size_t check_end = std::min(pos + 400, rc.size());
                    std::string check_window = rc.substr(pos, check_end - pos);
                    bool has_range = check_window.find("MoneyRange") != std::string::npos ||
                                     check_window.find("MAX_MONEY") != std::string::npos ||
                                     check_window.find("nValue < 0") != std::string::npos ||
                                     check_window.find("nValue > 0") != std::string::npos ||
                                     check_window.find("assert(") != std::string::npos;
                    // Check if this is in consensus code
                    bool is_consensus = tu->file_path.find("validation") != std::string::npos ||
                                        tu->file_path.find("consensus") != std::string::npos ||
                                        tu->file_path.find("script/") != std::string::npos;
                    // Check if miner-controlled (from tx deserialization context)
                    bool is_miner = check_window.find("CTransaction") != std::string::npos ||
                                     check_window.find("tx.") != std::string::npos ||
                                     check_window.find("vin") != std::string::npos;
                    if (!has_range) {
                        std::string fn = extract_enclosing_function_name(rc, pos);
                        ConfidenceBuilder cb;
                        if (is_consensus) cb.set_base_cfg_reachable(); else cb.set_base_dfg_only();
                        if (is_miner) cb.set_attacker_direct(); else cb.set_attacker_indirect();
                        Finding f;
                        f.finding_id = IDGenerator::instance().next(); f.release = rel;
                        f.file = tu->file_path; f.function_name = fn;
                        f.issue_type = is_consensus ? IssueType::ConsensusInflation : IssueType::IntegerOverflow;
                        f.classification = cb.auto_classify();
                        f.severity = is_consensus ? Severity::Critical : (is_miner ? Severity::High : Severity::Medium);
                        f.confidence = cb.build();
                        f.reachability = is_miner ? "p2p" : "local";
                        f.attacker_input = is_miner ? "Peer-supplied transaction field: " + var : "Internal computation on " + var;
                        f.evidence = "INT RANGE: " + var + " arithmetic without MoneyRange/MAX_MONEY check in " +
                            fn + "@" + tu->file_path + ". CAmount range [0, 21M*COIN] not enforced. " +
                            (is_consensus ? "CONSENSUS PATH — value overflow = inflation. " : "") +
                            (is_miner ? "Miner-controlled input. " : "") + cb.rationale();
                        f.execution_path = {"CAmount " + var + " receives arithmetic operation",
                            "No MoneyRange() check in 400-char window",
                            is_consensus ? "Consensus validation accepts overflow value" : "Wallet computes incorrect balance",
                            is_miner ? "Miner crafts tx to trigger overflow" : "Internal overflow from accumulated fees"};
                        f.fix_recommendation = "Add MoneyRange(" + var + ") after every CAmount arithmetic operation in consensus code";
                        findings.push_back(f); break;
                    }
                }
                pos = rc.find(var, pos + 1);
            }
        }
        return findings;
    }
};

// ═══════════════════════════════════════════════════════════════════
// §3.4 — Impossible State Eliminator
// ═══════════════════════════════════════════════════════════════════
class ImpossibleStateEliminator {
public:
    void eliminate(std::vector<Finding>& findings) {
        int eliminated = 0;
        for (auto& f : findings) {
            // Rule 1: "wallet locked AND master key in plaintext" = impossible
            bool needs_locked = f.evidence.find("IsLocked") != std::string::npos ||
                                 f.evidence.find("wallet is locked") != std::string::npos;
            bool needs_plaintext = f.issue_type == IssueType::StaleDecryptedKey ||
                                    f.issue_type == IssueType::HeapRetainedPrivateKey;
            if (needs_locked && needs_plaintext && f.evidence.find("after lock") == std::string::npos) {
                f.classification = Classification::FalsePositive;
                f.suppression_reason = "impossible_state: wallet locked AND plaintext key mutually exclusive";
                eliminated++;
            }
            // Rule 2: "RPC unauthenticated AND rpcauth configured" = impossible
            bool needs_unauth = f.reachability.find("unauth") != std::string::npos;
            bool implies_auth = f.evidence.find("rpcauth") != std::string::npos ||
                                 f.evidence.find("cookie") != std::string::npos;
            if (needs_unauth && implies_auth) {
                f.classification = Classification::FalsePositive;
                f.suppression_reason = "impossible_state: unauthenticated access AND rpcauth configured";
                eliminated++;
            }
            // Rule 3: attacker needs root/physical = suppress above LOW
            if ((f.attacker_input.find("root") != std::string::npos ||
                 f.attacker_input.find("physical") != std::string::npos) &&
                f.severity != Severity::Low && f.severity != Severity::Informational) {
                f.severity = Severity::Low;
                f.evidence += " [ImpossibleState: attacker needs root/physical → capped at LOW]";
                eliminated++;
            }
        }
        Logger::instance().info("ImpossibleStateEliminator: " + std::to_string(eliminated) + " findings adjusted");
    }
};

// ═══════════════════════════════════════════════════════════════════
// §3.1 — Dominance-Based Wipe Verifier
// ═══════════════════════════════════════════════════════════════════
class DominanceWipeVerifier {
public:
    void verify(std::vector<Finding>& findings, const std::vector<Release>& releases) {
        int suppressed = 0;
        for (auto& f : findings) {
            if (f.issue_type != IssueType::IncompleteZeroization &&
                f.issue_type != IssueType::DeadStoreElimination &&
                f.issue_type != IssueType::StaleDecryptedKey) continue;
            // Find the source TU and check if wipe dominates all exits
            for (auto& rel : releases) {
                if (rel.name != f.release) continue;
                for (auto& tu : rel.translation_units) {
                    if (tu.file_path != f.file) continue;
                    size_t fn_pos = tu.raw_content.find(f.function_name + "(");
                    if (fn_pos == std::string::npos) continue;
                    size_t fn_start = tu.raw_content.find('{', fn_pos);
                    if (fn_start == std::string::npos) continue;
                    size_t fn_end = find_matching_scope_end(tu.raw_content, fn_start);
                    if (fn_end == std::string::npos) continue;
                    std::string body = tu.raw_content.substr(fn_start, fn_end - fn_start);
                    // Check if wipe call exists and dominates all return paths
                    bool has_wipe = body.find("memory_cleanse") != std::string::npos ||
                                    body.find("OPENSSL_cleanse") != std::string::npos ||
                                    body.find("explicit_bzero") != std::string::npos;
                    // Count returns AFTER the wipe vs returns BEFORE
                    if (has_wipe) {
                        size_t wipe_pos = body.find("memory_cleanse");
                        if (wipe_pos == std::string::npos) wipe_pos = body.find("OPENSSL_cleanse");
                        if (wipe_pos == std::string::npos) wipe_pos = body.find("explicit_bzero");
                        // Count returns after wipe (safe) vs before wipe (unsafe)
                        int returns_before = 0, returns_after = 0;
                        size_t rp = body.find("return ");
                        while (rp != std::string::npos) {
                            if (rp < wipe_pos) returns_before++;
                            else returns_after++;
                            rp = body.find("return ", rp + 1);
                        }
                        if (returns_before == 0) {
                            // Wipe dominates all exits → false positive
                            f.classification = Classification::FalsePositive;
                            f.suppression_reason = "dominance: wipe at offset " + std::to_string(wipe_pos) +
                                " dominates all " + std::to_string(returns_after) + " return paths";
                            f.confidence = std::max(0.0, f.confidence * 0.1);
                            suppressed++;
                        } else {
                            // Wipe exists but doesn't dominate all paths
                            f.evidence += " [Dominance: " + std::to_string(returns_before) +
                                " return paths BEFORE wipe — incomplete cleanup]";
                        }
                    }
                    break;
                }
                break;
            }
        }
        Logger::instance().info("DominanceWipeVerifier: " + std::to_string(suppressed) + " findings suppressed");
    }
};

// ═══════════════════════════════════════════════════════════════════
// §2.1 — Enhanced Transaction Validity Analyzer (static)
// ═══════════════════════════════════════════════════════════════════
class TransactionValidityAnalyzer {
public:
    std::vector<Finding> analyze(const std::shared_ptr<TranslationUnit>& tu, const std::string& rel) {
        std::vector<Finding> findings;
        if (!tu || tu->raw_content.empty()) return findings;
        const std::string& rc = tu->raw_content;
        // Only analyze validation files
        if (rc.find("CheckTransaction") == std::string::npos &&
            rc.find("ConnectBlock") == std::string::npos &&
            rc.find("VerifyScript") == std::string::npos &&
            rc.find("SignatureHash") == std::string::npos) return findings;

        // TVA-1: Sighash type validation before use
        {
            size_t sh_pos = rc.find("SignatureHash");
            if (sh_pos != std::string::npos) {
                size_t fn_start = rc.rfind('{', sh_pos);
                if (fn_start != std::string::npos) {
                    std::string before_sig = rc.substr(fn_start, sh_pos - fn_start);
                    bool validates_type = before_sig.find("nHashType") != std::string::npos &&
                        (before_sig.find("if (") != std::string::npos || before_sig.find("switch") != std::string::npos);
                    size_t switch_pos = rc.find("switch", sh_pos);
                    bool has_default = false;
                    if (switch_pos != std::string::npos && switch_pos - sh_pos < 2000) {
                        std::string switch_body = rc.substr(switch_pos, std::min((size_t)2000, rc.size() - switch_pos));
                        has_default = switch_body.find("default:") != std::string::npos;
                        bool default_returns_zero = switch_body.find("default:") != std::string::npos &&
                            (switch_body.find("uint256()") != std::string::npos || switch_body.find("return 0") != std::string::npos);
                        if (default_returns_zero) {
                            std::string fn = extract_enclosing_function_name(rc, sh_pos);
                            ConfidenceBuilder cb; cb.set_base_cfg_reachable(); cb.set_attacker_direct();
                            Finding f;
                            f.finding_id = IDGenerator::instance().next(); f.release = rel;
                            f.file = tu->file_path; f.function_name = fn;
                            f.issue_type = IssueType::SighashKeyRecovery;
                            f.classification = cb.auto_classify();
                            f.severity = Severity::Critical; f.confidence = cb.build();
                            f.reachability = "p2p"; f.attacker_input = "Transaction with invalid sighash type byte";
                            f.evidence = "TVA-1: SIGHASH DEFAULT ZERO — SignatureHash switch has default: returning zero hash. "
                                "Invalid sighash type falls through to zero hash → signature forgery. " + fn +
                                "@" + tu->file_path + ". Version: " + rel + "." + cb.rationale();
                            f.execution_path = {"Attacker crafts tx with invalid sighash type",
                                "Switch falls through to default: returning uint256(0)",
                                "Any signature validates against zero hash",
                                "Arbitrary transaction forgery enabled"};
                            f.fix_recommendation = "Return error on unknown sighash type; never return zero hash from default case";
                            findings.push_back(f);
                        }
                    }
                }
            }
        }

        // TVA-2: Script cache flag subset check
        {
            size_t cache_pos = rc.find("scriptExecutionCache");
            if (cache_pos == std::string::npos) cache_pos = rc.find("CScriptCheck");
            if (cache_pos != std::string::npos) {
                size_t wend = std::min(cache_pos + 3000, rc.size());
                std::string window = rc.substr(cache_pos, wend - cache_pos);
                bool has_flag_check = window.find("flags") != std::string::npos &&
                    (window.find("==") != std::string::npos || window.find("& ") != std::string::npos);
                bool has_witness = window.find("SCRIPT_VERIFY_WITNESS") != std::string::npos;
                if (has_flag_check && has_witness) {
                    // Check if cached flags are verified to be superset
                    bool checks_subset = window.find("IsSubset") != std::string::npos ||
                        window.find("cached_flags & required_flags") != std::string::npos ||
                        window.find("(flags & ~") != std::string::npos;
                    if (!checks_subset) {
                        std::string fn = extract_enclosing_function_name(rc, cache_pos);
                        ConfidenceBuilder cb; cb.set_base_dfg_only(); cb.set_attacker_direct();
                        Finding f;
                        f.finding_id = IDGenerator::instance().next(); f.release = rel;
                        f.file = tu->file_path; f.function_name = fn;
                        f.issue_type = IssueType::ConsensusDoubleSpend;
                        f.classification = cb.auto_classify();
                        f.severity = Severity::Critical; f.confidence = cb.build();
                        f.reachability = "p2p";
                        f.attacker_input = "Transaction that hits cache with weaker flags than required";
                        f.evidence = "TVA-2: SCRIPT CACHE FLAG BYPASS — cache at " + fn + "@" + tu->file_path +
                            " does not verify cached flags are superset of required flags. "
                            "SCRIPT_VERIFY_WITNESS absent from cache → segwit tx skips validation. " + cb.rationale();
                        f.fix_recommendation = "Verify (cached_flags & required_flags) == required_flags before cache hit";
                        findings.push_back(f);
                    }
                }
            }
        }

        // TVA-3: Coinbase maturity check
        {
            if (rc.find("COINBASE_MATURITY") != std::string::npos || rc.find("coinbase") != std::string::npos) {
                size_t cpos = rc.find("IsCoinBase");
                if (cpos != std::string::npos) {
                    size_t fn_start = rc.rfind('{', cpos);
                    size_t fn_end = (fn_start != std::string::npos) ? find_matching_scope_end(rc, fn_start) : std::string::npos;
                    if (fn_end != std::string::npos) {
                        std::string body = rc.substr(fn_start, std::min(fn_end - fn_start, (size_t)5000));
                        bool checks_maturity = body.find("COINBASE_MATURITY") != std::string::npos ||
                            body.find("100") != std::string::npos;
                        bool spends_coinbase = body.find("IsCoinBase()") != std::string::npos &&
                            (body.find("nValue") != std::string::npos || body.find("GetCredit") != std::string::npos);
                        if (spends_coinbase && !checks_maturity) {
                            std::string fn = extract_enclosing_function_name(rc, cpos);
                            ConfidenceBuilder cb; cb.set_base_ast_pattern(); cb.set_attacker_direct();
                            Finding f;
                            f.finding_id = IDGenerator::instance().next(); f.release = rel;
                            f.file = tu->file_path; f.function_name = fn;
                            f.issue_type = IssueType::ConsensusDoubleSpend;
                            f.classification = cb.auto_classify();
                            f.severity = Severity::High; f.confidence = cb.build();
                            f.reachability = "p2p"; f.attacker_input = "Transaction spending immature coinbase";
                            f.evidence = "TVA-3: COINBASE MATURITY — " + fn + " accesses coinbase output value "
                                "without COINBASE_MATURITY check. Immature coinbase spend possible." + cb.rationale();
                            f.fix_recommendation = "Add (spend_height - coinbase_height) >= COINBASE_MATURITY check before spend";
                            findings.push_back(f);
                        }
                    }
                }
            }
        }

        return findings;
    }
};




// ═══════════════════════════════════════════════════════════════════
// §1.0 New-Module Adaptive Detectors (MuSig2, txgraph, BIP324, etc.)
// ═══════════════════════════════════════════════════════════════════
class NewModuleDetector {
public:
    std::vector<Finding> detect(const std::shared_ptr<TranslationUnit>& tu, const std::string& rel) {
        std::vector<Finding> findings;
        if (!tu || tu->raw_content.empty()) return findings;
        const std::string& rc = tu->raw_content;
        const std::string& fp = tu->file_path;

        // ── MuSig2: nonce generation + session wipe ──
        if (fp.find("musig") != std::string::npos) {
            // Check RFC6979 deterministic nonces
            if (rc.find("nonce") != std::string::npos) {
                bool has_rfc6979 = rc.find("RFC6979") != std::string::npos || rc.find("rfc6979") != std::string::npos ||
                    rc.find("deterministic") != std::string::npos || rc.find("hmac_drbg") != std::string::npos;
                bool has_random = rc.find("GetRandBytes") != std::string::npos || rc.find("rand()") != std::string::npos;
                if (!has_rfc6979 && has_random) {
                    auto f = make_finding(tu, rel, "nonce", IssueType::HeapRetainedPrivateKey, Severity::Critical,
                        "MUSIG-1: MuSig2 nonce in " + fp + " uses non-deterministic randomness instead of RFC6979. "
                        "Non-deterministic nonces in multi-party signing enable nonce extraction attacks.",
                        {"MuSig2 signing session created", "Nonce generated with GetRandBytes/rand()",
                         "Attacker observes two signatures with related nonces", "Private key extracted via lattice attack"},
                        "p2p", "Replace with RFC6979 deterministic nonce generation");
                    findings.push_back(f);
                }
            }
            // Check session data wipe
            if (rc.find("session") != std::string::npos || rc.find("Session") != std::string::npos) {
                bool has_wipe = rc.find("memory_cleanse") != std::string::npos || rc.find("OPENSSL_cleanse") != std::string::npos;
                if (!has_wipe) {
                    auto f = make_finding(tu, rel, "session", IssueType::IncompleteZeroization, Severity::High,
                        "MUSIG-2: MuSig2 session data in " + fp + " not wiped after signing. "
                        "Session secrets (partial nonces, key coefficients) persist in heap.",
                        {"MuSig2 session completes", "Session struct not zeroed", "Heap dump captures partial nonces",
                         "Combined with another session → key recovery"}, "local",
                        "Add memory_cleanse() to session destructor and all exit paths");
                    findings.push_back(f);
                }
            }
        }

        // ── txgraph: unbounded growth + use-after-free ──
        if (fp.find("txgraph") != std::string::npos) {
            // Unbounded graph growth
            if (rc.find("insert") != std::string::npos || rc.find("emplace") != std::string::npos) {
                bool has_limit = rc.find("MAX_") != std::string::npos || rc.find("max_size") != std::string::npos ||
                    rc.find("limit") != std::string::npos || rc.find("size() >") != std::string::npos;
                if (!has_limit) {
                    auto f = make_finding(tu, rel, "insert", IssueType::DoS, Severity::High,
                        "TXGRAPH-1: Transaction graph in " + fp + " allows unbounded insertion without size limit. "
                        "Peer can flood mempool with transactions creating O(N^2) graph edges → OOM.",
                        {"Attacker submits thousands of interconnected transactions", "Graph grows without bound",
                         "Node exhausts memory", "Node crashes → DoS"}, "p2p",
                        "Add MAX_GRAPH_NODES limit; evict lowest-feerate subgraphs when exceeded");
                    findings.push_back(f);
                }
            }
            // Use-after-free on removal
            if (rc.find("erase") != std::string::npos || rc.find("remove") != std::string::npos) {
                bool has_invalidation = rc.find("invalidat") != std::string::npos || rc.find("nullptr") != std::string::npos ||
                    rc.find("weak_ptr") != std::string::npos;
                if (!has_invalidation) {
                    auto f = make_finding(tu, rel, "erase", IssueType::RaceCondition, Severity::Critical,
                        "TXGRAPH-2: Transaction removal in " + fp + " may leave dangling edges. "
                        "Reorg during graph traversal → use-after-free → crash or memory corruption.",
                        {"Transaction removed from mempool during reorg", "Graph edge still references freed node",
                         "Traversal dereferences dangling pointer", "Crash or memory corruption"}, "p2p",
                        "Use weak_ptr for graph edges; validate all edge targets before traversal");
                    findings.push_back(f);
                }
            }
        }

        // ── BIP324: session key cleanup + side-channel ──
        if (fp.find("bip324") != std::string::npos || fp.find("v2transport") != std::string::npos) {
            // Session key cleanup after handshake
            std::vector<std::string> key_tokens = {"session_key", "send_key", "recv_key", "ecdh_secret", "shared_secret"};
            for (auto& kt : key_tokens) {
                size_t pos = rc.find(kt);
                if (pos == std::string::npos) continue;
                size_t scope_end = find_enclosing_scope_end(rc, pos);
                if (scope_end == std::string::npos) scope_end = std::min(pos + 2000, rc.size());
                std::string scope = rc.substr(pos, scope_end - pos);
                bool wiped = scope.find("memory_cleanse") != std::string::npos || scope.find("cleanse") != std::string::npos;
                if (!wiped) {
                    auto f = make_finding(tu, rel, kt, IssueType::IncompleteZeroization, Severity::High,
                        "BIP324-1: v2 transport key '" + kt + "' in " + fp + " not cleansed after handshake. "
                        "Session encryption keys persist in heap after negotiation completes.",
                        {"BIP324 v2 handshake completes", kt + " remains in heap", "Heap dump captures session keys",
                         "All past and future messages on this connection decryptable"}, "p2p",
                        "memory_cleanse(" + kt + ") immediately after deriving send/recv keys");
                    findings.push_back(f); break;
                }
            }
            // Elligator swift timing side-channel
            if (rc.find("elligator") != std::string::npos || rc.find("EllSwift") != std::string::npos) {
                bool has_ct = rc.find("constant_time") != std::string::npos || rc.find("ct_") != std::string::npos ||
                    rc.find("VERIFY_CHECK") != std::string::npos;
                if (!has_ct) {
                    auto f = make_finding(tu, rel, "elligator", IssueType::HeapRetainedPrivateKey, Severity::Medium,
                        "BIP324-2: ElligatorSwift encoding in " + fp + " may not be constant-time. "
                        "Timing variations in encoding leak bits of the ephemeral secret.",
                        {"v2 handshake initiated", "ElligatorSwift encoding runs with data-dependent branches",
                         "Attacker measures timing across many connections", "Ephemeral key bits recovered"},
                        "p2p", "Ensure all ElligatorSwift operations use constant-time primitives");
                    findings.push_back(f);
                }
            }
        }

        // ── headerssync: memory exhaustion from header flood ──
        if (fp.find("headerssync") != std::string::npos) {
            if (rc.find("push_back") != std::string::npos || rc.find("emplace_back") != std::string::npos) {
                bool has_limit = rc.find("MAX_HEADERS") != std::string::npos || rc.find("m_max") != std::string::npos ||
                    rc.find("size() >") != std::string::npos;
                if (!has_limit) {
                    auto f = make_finding(tu, rel, "push_back", IssueType::DoS, Severity::High,
                        "HDRSYNC-1: Header sync in " + fp + " stores headers without limit. "
                        "Malicious peer sends millions of low-work headers → OOM.",
                        {"Peer initiates header sync", "Sends millions of valid-PoW-but-low-work headers",
                         "Node stores all in memory without eviction", "OOM crash → DoS"}, "p2p",
                        "Limit stored headers; use commit-checkpoint strategy per headerssync design");
                    findings.push_back(f);
                }
            }
        }

        return findings;
    }

private:
    Finding make_finding(const std::shared_ptr<TranslationUnit>& tu, const std::string& rel,
                          const std::string& token, IssueType it, Severity sev,
                          const std::string& evidence, std::vector<std::string> path,
                          const std::string& reach, const std::string& fix) {
        size_t pos = tu->raw_content.find(token);
        std::string fn = extract_enclosing_function_name(tu->raw_content, pos != std::string::npos ? pos : 0);
        ConfidenceBuilder cb;
        cb.set_base_ast_pattern();
        if (reach == "p2p") cb.set_attacker_direct(); else cb.set_attacker_physical();
        Finding f;
        f.finding_id = IDGenerator::instance().next(); f.release = rel;
        f.file = tu->file_path; f.function_name = fn;
        f.issue_type = it; f.classification = cb.auto_classify();
        f.severity = sev; f.confidence = cb.build();
        f.reachability = reach; f.review_tier = sev == Severity::Critical ? "immediate" : "scheduled";
        f.novelty_tag = "InconclusiveNovel"; f.reproducible = true; f.manual_review_required = true;
        f.evidence = evidence + cb.rationale();
        f.execution_path = path; f.fix_recommendation = fix;
        f.secret_material_type = (it == IssueType::HeapRetainedPrivateKey || it == IssueType::IncompleteZeroization)
            ? SecretMaterialType::PrivateKey : SecretMaterialType::None;
        return f;
    }
};

// ═══════════════════════════════════════════════════════════════════
// §1.3 Mempool Policy Detector (RBF, Package Race, TOCTOU)
// ═══════════════════════════════════════════════════════════════════
class MempoolPolicyDetector {
public:
    std::vector<Finding> detect(const std::shared_ptr<TranslationUnit>& tu, const std::string& rel) {
        std::vector<Finding> findings;
        if (!tu || tu->raw_content.empty()) return findings;
        const std::string& rc = tu->raw_content;

        // Only analyze mempool/validation files
        if (rc.find("CTxMemPool") == std::string::npos && rc.find("AcceptToMemoryPool") == std::string::npos &&
            rc.find("ConnectBlock") == std::string::npos) return findings;

        // MPD-1: RBF fee-rate check before conflicting tx removal
        if (rc.find("BIP125") != std::string::npos || rc.find("nSequence") != std::string::npos) {
            size_t rbf_pos = rc.find("removeConflicts");
            if (rbf_pos == std::string::npos) rbf_pos = rc.find("RemoveConflicting");
            if (rbf_pos == std::string::npos) rbf_pos = rc.find("replac");
            if (rbf_pos != std::string::npos) {
                size_t before_start = (rbf_pos > 1000) ? rbf_pos - 1000 : 0;
                std::string before = rc.substr(before_start, rbf_pos - before_start);
                bool has_fee_check = before.find("PaysForRBF") != std::string::npos ||
                    before.find("GetModifiedFee") != std::string::npos ||
                    before.find("nModifiedFees") != std::string::npos ||
                    before.find("fee_delta") != std::string::npos;
                if (!has_fee_check) {
                    ConfidenceBuilder cb; cb.set_base_dfg_only(); cb.set_attacker_direct();
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = rel;
                    f.file = tu->file_path;
                    f.function_name = extract_enclosing_function_name(rc, rbf_pos);
                    f.issue_type = IssueType::ConsensusDoubleSpend;
                    f.classification = cb.auto_classify();
                    f.severity = Severity::Critical; f.confidence = cb.build();
                    f.reachability = "p2p"; f.attacker_input = "Conflicting transaction via P2P with lower fee";
                    f.evidence = "MPD-1: RBF POLICY BYPASS — conflicting tx removal at " + f.function_name +
                        " without fee-rate check (PaysForRBF/GetModifiedFee). Attacker replaces "
                        "victim's tx with lower-fee version. " + cb.rationale();
                    f.execution_path = {"Victim broadcasts tx with fee F", "Attacker submits conflicting tx with fee < F",
                        "No fee-rate comparison before removal", "Original tx evicted, replacement accepted",
                        "Victim's payment reversed"};
                    f.fix_recommendation = "Call PaysForRBF() and verify fee_delta > 0 before removeConflicts()";
                    findings.push_back(f);
                }
            }
        }

        // MPD-2: Package acceptance TOCTOU
        if (rc.find("AcceptPackage") != std::string::npos || rc.find("ProcessNewPackage") != std::string::npos ||
            rc.find("submitpackage") != std::string::npos) {
            size_t pkg_pos = rc.find("AcceptPackage");
            if (pkg_pos == std::string::npos) pkg_pos = rc.find("ProcessNewPackage");
            if (pkg_pos != std::string::npos) {
                size_t fn_end = find_enclosing_scope_end(rc, pkg_pos);
                if (fn_end == std::string::npos) fn_end = std::min(pkg_pos + 5000, rc.size());
                std::string body = rc.substr(pkg_pos, fn_end - pkg_pos);
                // Check for lock release between UTXO check and insertion
                bool has_unlock_relock = body.find("UNLOCK") != std::string::npos ||
                    (body.find("cs_main") != std::string::npos &&
                     body.find("LOCK(") != std::string::npos &&
                     body.rfind("LOCK(") > body.find("cs_main"));
                bool checks_utxo = body.find("HaveCoins") != std::string::npos || body.find("GetCoin") != std::string::npos;
                bool inserts = body.find("addUnchecked") != std::string::npos || body.find("InsertEntry") != std::string::npos;
                if (checks_utxo && inserts) {
                    ConfidenceBuilder cb; cb.set_base_ast_pattern(); cb.set_attacker_direct();
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = rel;
                    f.file = tu->file_path;
                    f.function_name = extract_enclosing_function_name(rc, pkg_pos);
                    f.issue_type = IssueType::ConsensusDoubleSpend;
                    f.classification = cb.auto_classify();
                    f.severity = Severity::High; f.confidence = cb.build();
                    f.reachability = "p2p"; f.attacker_input = "Package where parent conflicts with confirmed tx";
                    f.evidence = "MPD-2: PACKAGE TOCTOU — " + f.function_name + " checks UTXO existence and inserts "
                        "into mempool in " + tu->file_path + ". If lock is released between check and insert, "
                        "a conflicting block can confirm between, causing double-spend. " + cb.rationale();
                    f.execution_path = {"Submit package: parent + child", "UTXO check passes (parent inputs unspent)",
                        "Lock released momentarily", "Competing block confirms spending same UTXO",
                        "Package inserted into mempool with stale UTXO state"};
                    f.fix_recommendation = "Hold cs_main atomically from HaveCoins() through addUnchecked()";
                    findings.push_back(f);
                }
            }
        }

        // MPD-3: CheckSequenceLocks integer overflow
        if (rc.find("CheckSequenceLocks") != std::string::npos || rc.find("SequenceLocks") != std::string::npos) {
            size_t sl_pos = rc.find("CheckSequenceLocks");
            if (sl_pos == std::string::npos) sl_pos = rc.find("SequenceLocks");
            if (sl_pos != std::string::npos) {
                size_t scope_end = find_enclosing_scope_end(rc, sl_pos);
                if (scope_end == std::string::npos) scope_end = std::min(sl_pos + 3000, rc.size());
                std::string body = rc.substr(sl_pos, scope_end - sl_pos);
                bool has_overflow_check = body.find("overflow") != std::string::npos ||
                    body.find("INT_MAX") != std::string::npos || body.find("numeric_limits") != std::string::npos ||
                    body.find("SafeAdd") != std::string::npos;
                bool has_addition = body.find("+ ") != std::string::npos || body.find("+=") != std::string::npos;
                if (has_addition && !has_overflow_check) {
                    ConfidenceBuilder cb; cb.set_base_ast_pattern(); cb.set_attacker_direct();
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = rel;
                    f.file = tu->file_path;
                    f.function_name = extract_enclosing_function_name(rc, sl_pos);
                    f.issue_type = IssueType::IntegerOverflow;
                    f.classification = cb.auto_classify();
                    f.severity = Severity::High; f.confidence = cb.build();
                    f.reachability = "p2p"; f.attacker_input = "Transaction with extreme nSequence values";
                    f.evidence = "MPD-3: SEQUENCE LOCK OVERFLOW — arithmetic in " + f.function_name +
                        " adds nSequence to block height/time without overflow check. " +
                        "INT64 overflow wraps lock time, bypassing BIP68 relative timelocks. " + cb.rationale();
                    f.execution_path = {"Attacker crafts tx with nSequence near INT64_MAX",
                        "Addition overflows when combined with current block height",
                        "Wrapped value passes lock check", "Transaction accepted before timelock expiry"};
                    f.fix_recommendation = "Use checked arithmetic (SafeAdd) for all sequence lock calculations";
                    findings.push_back(f);
                }
            }
        }

        return findings;
    }
};

// ═══════════════════════════════════════════════════════════════════
// §1.4 Enhanced Inflation Detector (BIP30, subsidy, fee ordering)
// ═══════════════════════════════════════════════════════════════════
class EnhancedInflationDetector {
public:
    std::vector<Finding> detect(const std::shared_ptr<TranslationUnit>& tu, const std::string& rel) {
        std::vector<Finding> findings;
        if (!tu || tu->raw_content.empty()) return findings;
        const std::string& rc = tu->raw_content;

        // EID-1: BIP30 duplicate coinbase txid check
        if (rc.find("CheckBlock") != std::string::npos || rc.find("ConnectBlock") != std::string::npos) {
            bool has_bip30 = rc.find("BIP30") != std::string::npos || rc.find("bip30") != std::string::npos ||
                rc.find("duplicate") != std::string::npos;
            bool has_coinbase = rc.find("IsCoinBase") != std::string::npos;
            if (has_coinbase && !has_bip30) {
                ConfidenceBuilder cb; cb.set_base_ast_pattern(); cb.set_attacker_direct();
                Finding f;
                f.finding_id = IDGenerator::instance().next(); f.release = rel;
                f.file = tu->file_path;
                f.function_name = extract_enclosing_function_name(rc, rc.find("CheckBlock"));
                f.issue_type = IssueType::ConsensusInflation;
                f.classification = cb.auto_classify();
                f.severity = Severity::Critical; f.confidence = cb.build();
                f.reachability = "p2p"; f.attacker_input = "Block with duplicate coinbase txid";
                f.evidence = "EID-1: BIP30 MISSING — " + tu->file_path +
                    " handles coinbase without BIP30 duplicate txid check. "
                    "Miner can reuse a previous coinbase txid to overwrite UTXO entries. " + cb.rationale();
                f.fix_recommendation = "Enforce BIP30: reject blocks with txids matching existing unspent outputs";
                findings.push_back(f);
            }
        }

        // EID-2: Fee collection ordering in block assembly
        if (rc.find("CreateNewBlock") != std::string::npos || rc.find("BlockAssembler") != std::string::npos) {
            size_t create_pos = rc.find("CreateNewBlock");
            if (create_pos == std::string::npos) create_pos = rc.find("BlockAssembler");
            if (create_pos != std::string::npos) {
                size_t scope_end = find_enclosing_scope_end(rc, create_pos);
                if (scope_end == std::string::npos) scope_end = std::min(create_pos + 8000, rc.size());
                std::string body = rc.substr(create_pos, scope_end - create_pos);
                size_t fee_pos = body.find("nFees");
                size_t coinbase_pos = body.find("coinbaseTx");
                if (coinbase_pos == std::string::npos) coinbase_pos = body.find("coinbase");
                if (fee_pos != std::string::npos && coinbase_pos != std::string::npos && fee_pos > coinbase_pos) {
                    ConfidenceBuilder cb; cb.set_base_dfg_only(); cb.set_attacker_indirect();
                    Finding f;
                    f.finding_id = IDGenerator::instance().next(); f.release = rel;
                    f.file = tu->file_path;
                    f.function_name = extract_enclosing_function_name(rc, create_pos);
                    f.issue_type = IssueType::ConsensusInflation;
                    f.classification = cb.auto_classify();
                    f.severity = Severity::High; f.confidence = cb.build();
                    f.reachability = "local";
                    f.evidence = "EID-2: LATE FEE INCLUSION — nFees collected AFTER coinbase constructed in " +
                        f.function_name + ". Fees added post-coinbase may not be included in output value check. " +
                        cb.rationale();
                    f.fix_recommendation = "Collect all fees before constructing coinbase transaction output";
                    findings.push_back(f);
                }
            }
        }

        // EID-3: Coinbase scriptSig size limit
        if (rc.find("coinbase") != std::string::npos && rc.find("scriptSig") != std::string::npos) {
            size_t pos = rc.find("scriptSig");
            size_t wend = std::min(pos + 500, rc.size());
            std::string window = rc.substr(pos, wend - pos);
            bool has_size_check = window.find("100") != std::string::npos || window.find("MAX_COINBASE") != std::string::npos ||
                window.find("size() >") != std::string::npos || window.find("size() <") != std::string::npos;
            if (!has_size_check && rc.find("CheckBlock") != std::string::npos) {
                ConfidenceBuilder cb; cb.set_base_ast_pattern(); cb.set_attacker_direct();
                Finding f;
                f.finding_id = IDGenerator::instance().next(); f.release = rel;
                f.file = tu->file_path;
                f.function_name = extract_enclosing_function_name(rc, pos);
                f.issue_type = IssueType::DoS;
                f.classification = cb.auto_classify();
                f.severity = Severity::Medium; f.confidence = cb.build();
                f.reachability = "p2p";
                f.evidence = "EID-3: COINBASE SCRIPTSIG UNLIMITED — no 100-byte size limit on coinbase scriptSig "
                    "near " + f.function_name + ". " + cb.rationale();
                f.fix_recommendation = "Enforce coinbase scriptSig size <= 100 bytes per consensus rules";
                findings.push_back(f);
            }
        }

        return findings;
    }
};



void NoveltyExpansionOrchestrator::run(const std::vector<Release>& releases, std::vector<Finding>& all_findings) {
    Logger::instance().info("NoveltyExpansionOrchestrator::run: starting comprehensive audit across all releases");
    
    auto start_time = std::chrono::steady_clock::now();
    
    // Scan ALL provided releases — no hardcoded version list
    Logger::instance().info("NoveltyExpansionOrchestrator: scanning " + std::to_string(releases.size()) + " release(s)");
    
    for (const auto& target_ref : releases) {
        const Release* target_release = &target_ref;
        std::string version = target_release->name;
        Logger::instance().info("NoveltyExpansionOrchestrator: processing version " + version +
            " (" + std::to_string(target_release->translation_units.size()) + " TUs)");
        
        for (const auto& tu_entry : target_release->translation_units) {
            auto& tu = tu_entry;
            // Pre-scan filter: skip dead directories and files with no security keywords
            if (should_skip_file(tu.file_path)) {
                Logger::instance().info("  [skip] " + tu.file_path);
                continue;
            }
            if (!has_security_relevant_content(tu.raw_content)) {
                Logger::instance().info("  [no-keywords] " + tu.file_path);
                continue;
            }
            PatternLibrary pattern_lib;
            pattern_lib.load_patterns();
            pattern_lib.extend_patterns_from_source(tu.raw_content, tu.release_name);

            PackageRelayDoubleSpendAnalyzer pdsa;
            auto f1 = pdsa.analyze(const_cast<TranslationUnit*>(&tu));
            all_findings.insert(all_findings.end(), f1.begin(), f1.end());

            DynamicDoubleSpendEngine ddse;
            auto f_ds = ddse.analyze(const_cast<TranslationUnit*>(&tu), pattern_lib);
            all_findings.insert(all_findings.end(), f_ds.begin(), f_ds.end());

            DynamicInflationEngine die;
            auto f_inf = die.analyze(const_cast<TranslationUnit*>(&tu), pattern_lib);
            all_findings.insert(all_findings.end(), f_inf.begin(), f_inf.end());

            DynamicSecretLeakageEngine dsle;
            auto f_kl = dsle.analyze(const_cast<TranslationUnit*>(&tu), pattern_lib);
            all_findings.insert(all_findings.end(), f_kl.begin(), f_kl.end());
            
            UTXOCacheDivergenceDetector ucd;
            auto f2 = ucd.analyze(const_cast<TranslationUnit*>(&tu));
            all_findings.insert(all_findings.end(), f2.begin(), f2.end());
            
            ReorgSpendReplayDetector rsr;
            auto f3 = rsr.analyze(const_cast<TranslationUnit*>(&tu));
            all_findings.insert(all_findings.end(), f3.begin(), f3.end());
            
            ValueAccountingTracer vat;
            auto f4 = vat.analyze(const_cast<TranslationUnit*>(&tu));
            all_findings.insert(all_findings.end(), f4.begin(), f4.end());
            
            WitnessAccountingInflationDetector waid;
            auto f5 = waid.detect_witness_weight_undercount(const_cast<TranslationUnit*>(&tu));
            if (f5.confidence > 0.0) all_findings.push_back(f5);
            
            WalletSecretLifetimeTracker wslt;
            auto f6 = wslt.analyze(const_cast<TranslationUnit*>(&tu));
            all_findings.insert(all_findings.end(), f6.begin(), f6.end());

            // C1: AssumeUTXO snapshot poisoning
            AssumeUTXOPoisoningDetector autxo_det;
            auto tu_sp_autxo = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){}); auto f_autxo = autxo_det.detect(tu_sp_autxo, target_release->name);
            all_findings.insert(all_findings.end(), f_autxo.begin(), f_autxo.end());

            // C2: Tapscript resource exhaustion
            TapscriptResourceExhaustionDetector tapscript_det;
            auto tu_sp_tap = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){}); auto f_tap = tapscript_det.detect(tu_sp_tap, target_release->name);
            all_findings.insert(all_findings.end(), f_tap.begin(), f_tap.end());

            // C3: BIP324 encrypted transport key residency
            EncryptedTransportAnalyzer bip324_det;
            auto tu_sp_bip = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){}); auto f_bip324 = bip324_det.detect(tu_sp_bip, target_release->name);
            all_findings.insert(all_findings.end(), f_bip324.begin(), f_bip324.end());

            // C4: Silent payment key aggregation leakage
            SilentPaymentAnalyzer sp_det;
            auto tu_sp_sp = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){}); auto f_sp = sp_det.detect(tu_sp_sp, target_release->name);
            all_findings.insert(all_findings.end(), f_sp.begin(), f_sp.end());

            // C5: Miniscript policy bypass
            MiniscriptAnalyzer ms_det;
            auto tu_sp_ms = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){}); auto f_ms = ms_det.detect(tu_sp_ms, target_release->name);
            all_findings.insert(all_findings.end(), f_ms.begin(), f_ms.end());

            // RPCAuthGuardAnalyzer
            RPCAuthGuardAnalyzer raga;
            auto tu_sp_raga = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){});
            auto f_raga = raga.analyze(tu_sp_raga, target_release->name);
            all_findings.insert(all_findings.end(), f_raga.begin(), f_raga.end());

            // CounterfeitMintingDetector
            CounterfeitMintingDetector cmd_det;
            auto tu_sp_cmd = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){});
            auto f_cmd = cmd_det.analyze(tu_sp_cmd, target_release->name);
            all_findings.insert(all_findings.end(), f_cmd.begin(), f_cmd.end());

            // TransactionValidityAnalyzer: sighash, cache bypass, maturity
            TransactionValidityAnalyzer tva;
            auto tu_sp_tva = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){});
            auto f_tva = tva.analyze(tu_sp_tva, target_release->name);
            all_findings.insert(all_findings.end(), f_tva.begin(), f_tva.end());

            // IntegerRangeAnalyzer: CAmount overflow without MoneyRange
            IntegerRangeAnalyzer ira;
            auto tu_sp_ira = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){});
            auto f_ira = ira.analyze(tu_sp_ira, target_release->name);
            all_findings.insert(all_findings.end(), f_ira.begin(), f_ira.end());

            // ConsensusBugDetector: stack bounds, merkle, cs_main, BIP66
            ConsensusBugDetector cbd;
            auto tu_sp_cbd = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){});
            auto f_cbd = cbd.detect(tu_sp_cbd, target_release->name);
            all_findings.insert(all_findings.end(), f_cbd.begin(), f_cbd.end());

            // NewModuleDetector: MuSig2, txgraph, BIP324, headerssync
            NewModuleDetector nmd;
            auto tu_sp_nmd = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){});
            auto f_nmd = nmd.detect(tu_sp_nmd, target_release->name);
            all_findings.insert(all_findings.end(), f_nmd.begin(), f_nmd.end());

            // MempoolPolicyDetector: RBF bypass, package TOCTOU, sequence overflow
            MempoolPolicyDetector mpd;
            auto tu_sp_mpd = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){});
            auto f_mpd = mpd.detect(tu_sp_mpd, target_release->name);
            all_findings.insert(all_findings.end(), f_mpd.begin(), f_mpd.end());

            // EnhancedInflationDetector: BIP30, fee ordering, coinbase scriptSig
            EnhancedInflationDetector eid;
            auto tu_sp_eid = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){});
            auto f_eid = eid.detect(tu_sp_eid, target_release->name);
            all_findings.insert(all_findings.end(), f_eid.begin(), f_eid.end());

            // NovelBugHunter: type narrowing, assert in consensus, vector DoS, weak RNG
            NovelBugHunter nbh;
            auto tu_sp_nbh = std::shared_ptr<TranslationUnit>(const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){});
            auto f_nbh = nbh.hunt(tu_sp_nbh, target_release->name);
            all_findings.insert(all_findings.end(), f_nbh.begin(), f_nbh.end());

            // IterationCountFingerprintEngine: KDF analysis via WalletOraclePoCGenerator
        }
    }
    
    Logger::instance().info("NoveltyExpansionOrchestrator: collected " + std::to_string(all_findings.size()) + " raw findings");

    // Wire PristineVerificationEngine â mandatory second-pass verification
    Logger::instance().info(
        "NoveltyExpansionOrchestrator: running PristineVerificationEngine "
        "over " + std::to_string(all_findings.size()) + " findings");
    PristineVerificationEngine pve;
    std::string combined_content;
    for (const auto& release : releases) {
        for (const auto& tu : release.translation_units) {
            combined_content += tu.raw_content + "\n";
        }
    }
    PatternLibrary pve_pl;
    pve_pl.load_patterns();
    pve.run_verification_pass(all_findings, combined_content, pve_pl);
    Logger::instance().info(
        "NoveltyExpansionOrchestrator: PristineVerificationEngine complete");

    // Wire BackCheckEngine â structural back-checks on survivors
    {
        BackCheckEngine bce;
        PatternLibrary bce_pl;
        bce_pl.load_patterns();
        for (auto& f : all_findings) {
            if (f.classification == Classification::FalsePositive) continue;
            std::string raw;
            for (const auto& rel : releases) {
                for (const auto& tu : rel.translation_units) {
                    if (tu.file_path == f.file) { raw = tu.raw_content; break; }
                }
                if (!raw.empty()) break;
            }
            bool suppress = bce.back_check(f, raw, bce_pl);
            if (suppress) {
                f.classification = Classification::FalsePositive;
                f.evidence += " [Suppressed by BackCheckEngine]";
            }
        }
    }

    // IMP14: Assign review_tier before novelty classification
    for (auto& finding : all_findings) {
        if (finding.severity == Severity::Critical) finding.review_tier = "immediate";
        else if (finding.severity == Severity::High) finding.review_tier = "scheduled";
        else finding.review_tier = "informational";
    }

    NoveltyClassifier nc;
    for (auto& finding : all_findings) {
        auto score = nc.classify_finding(finding);
        finding.novelty_tag = novelty_status_to_string(score.status);
        
        if (score.status == NoveltyClassifier::NoveltyStatus::DesignBehavior || score.status == NoveltyClassifier::NoveltyStatus::Noise) {
            finding.classification = Classification::NonExploitable;
            continue;
        }
    }
    
    HistoricalIssueDatabase hdb;
    for (auto& finding : all_findings) {
        if (hdb.is_known_vulnerability(finding)) {
            finding.novelty_tag = "HistoricallyKnown";
        }
    }
    
    Logger::instance().info("NoveltyExpansionOrchestrator: collapsing duplicates");
    DuplicateRootCauseCollapser drcc;
    auto collapsed = drcc.collapse_findings(all_findings);
    
    Logger::instance().info("NoveltyExpansionOrchestrator: scoring novelty confidence");
    NoveltyConfidenceScorer ncs;
    for (auto& f : collapsed) {
        ncs.score_finding(f);
    }
    
    Logger::instance().info("NoveltyExpansionOrchestrator: analyzing cross-version evolution");
    DifferentialVersionAnalyzer dva;
    for (auto& f : collapsed) {
        dva.classify_finding_evolution(f, std::vector<Finding>{}, std::vector<Finding>{});
    }
    
    Logger::instance().info("NoveltyExpansionOrchestrator: generating oracle PoC");
    WalletOraclePoCGenerator poc_gen;
    auto analysis = poc_gen.analyze_wallet_for_oracle(releases);
    
    if (analysis.oracle_viable) {
        std::string script = poc_gen.generate_poc_script(analysis);
        std::ofstream poc_file("poc_padding_oracle.py");
        poc_file << script;
        poc_file.close();
        Logger::instance().info("NoveltyExpansionOrchestrator: PoC script written to poc_padding_oracle.py");
    }

    // ═══ CONSOLIDATED PoC: one script per category ═══
    Logger::instance().info("Generating consolidated PoC scripts (one per type)");
    PocDoubleSpendEngine     poc_ds;
    PocInflationEngine       poc_inf;
    PocCounterfeitEngine     poc_ctft;
    PocKeyLeakageEngine      poc_kl;
    PocPasswordLeakageEngine poc_pw;

    // Pick first finding of each type as representative
    Finding ds_rep, inf_rep, ctft_rep, kl_rep, pw_rep;
    bool has_ds=false, has_inf=false, has_ctft=false, has_kl=false, has_pw=false;
    for (const auto& cf : collapsed) {
        if (!has_ds && cf.issue_type == IssueType::ConsensusDoubleSpend) { ds_rep = cf; has_ds = true; }
        if (cf.issue_type == IssueType::ConsensusInflation) {
            bool ic = cf.evidence.find("phantom")!=std::string::npos || cf.evidence.find("AddCoin")!=std::string::npos;
            if (ic && !has_ctft) { ctft_rep = cf; has_ctft = true; }
            if (!ic && !has_inf) { inf_rep = cf; has_inf = true; }
        }
        if (!has_kl && (cf.issue_type == IssueType::HeapRetainedPrivateKey || cf.issue_type == IssueType::StaleDecryptedKey ||
            cf.issue_type == IssueType::IncompleteZeroization || cf.issue_type == IssueType::HDSeedExposure))
            { kl_rep = cf; has_kl = true; }
        if (!has_pw && (cf.issue_type == IssueType::RPCPasswordExposure || cf.issue_type == IssueType::LoggingExposure))
            { pw_rep = cf; has_pw = true; }
    }
    if (has_ds) { auto s=poc_ds.generate(ds_rep,releases); if(!s.empty()){std::ofstream("poc_double_spend.py")<<s;
        Logger::instance().info("Consolidated: poc_double_spend.py");} }
    if (has_inf||has_ctft) { auto s=has_ctft?poc_ctft.generate(ctft_rep,releases):poc_inf.generate(inf_rep,releases);
        if(!s.empty()){std::ofstream("poc_counterfeit_inflation.py")<<s;
        Logger::instance().info("Consolidated: poc_counterfeit_inflation.py");} }
    if (has_kl) { auto s=poc_kl.generate(kl_rep,releases); if(!s.empty()){std::ofstream("poc_key_leakage.py")<<s;
        Logger::instance().info("Consolidated: poc_key_leakage.py");} }
    if (has_pw) { auto s=poc_pw.generate(pw_rep,releases); if(!s.empty()){std::ofstream("poc_password_leakage.py")<<s;
        Logger::instance().info("Consolidated: poc_password_leakage.py");} }


    // ══════════════ PRE-PROCESSING ══════════════
    // §1.9: Lock-order analysis
    {
        std::vector<std::shared_ptr<TranslationUnit>> all_tus_lock;
        for (auto& r : releases) for (auto& tu : r.translation_units)
            all_tus_lock.push_back(std::shared_ptr<TranslationUnit>(
                const_cast<TranslationUnit*>(&tu), [](TranslationUnit*){}));
        LockOrderAnalyzer loa;
        auto lock_findings = loa.analyze_lock_order(all_tus_lock, releases.empty() ? "" : releases[0].name);
        all_findings.insert(all_findings.end(), lock_findings.begin(), lock_findings.end());
        Logger::instance().info("LockOrderAnalyzer: " + std::to_string(lock_findings.size()) + " inversions found");
    }

    // §3.1: Dominance wipe verification
    DominanceWipeVerifier dwv;
    dwv.verify(all_findings, releases);

    // §3.4: Impossible state elimination
    ImpossibleStateEliminator ise;
    ise.eliminate(all_findings);

    BackCheckEnhanced bce;
    bce.filter_false_positives(all_findings, releases);
    
    CrossVersionDifferentialAmplifier cvda;
    cvda.amplify(all_findings);

    // ══════════════ STREAM 2 IMPROVEMENTS ══════════════
    // IMP12: Taint flow analysis
    {
        std::vector<std::shared_ptr<TranslationUnit>> all_tus;
        for (const auto& rel : releases) {
            for (const auto& tu : rel.translation_units) {
                all_tus.push_back(std::make_shared<TranslationUnit>(tu));
            }
        }
        TaintFlowAnalyzer tfa;
        auto flows = tfa.trace_key_flows(all_tus);
        tfa.apply_taint_to_findings(all_findings, flows);
        Logger::instance().info("TaintFlowAnalyzer: " + std::to_string(flows.size()) + " flows traced");

        // IMP11: Concurrency mutex verification
        ConcurrencyMutexVerifier cmv;
        cmv.verify_mutex_coverage(all_tus, all_findings);

        // IMP10: RPC access control modelling
        RPCAccessControlModeller racm;
        auto rpc_models = racm.model_rpc_layer(all_tus);
        racm.apply_models_to_findings(all_findings, rpc_models);
        Logger::instance().info("RPCAccessControlModeller: " + std::to_string(rpc_models.size()) + " endpoints");
    }

    // IMP7: Deduplication
    DeduplicationEngine dedup_eng;
    auto dedup_result = dedup_eng.deduplicate(all_findings);
    Logger::instance().info("DeduplicationEngine: " + std::to_string(dedup_result.raw_count) + " -> " + std::to_string(dedup_result.unique_count));

    // IMP6: Exploit path severity rescoring
    ExploitPathWeightedScorer epws;
    epws.rescore_all_findings(all_findings);

    // IMP1: Compiler wipe verification
    CompilerWipeVerifier cwv;
    {
        std::vector<Finding> wipe_copy(collapsed.begin(), collapsed.end());
        auto wr = cwv.verify_wipe_findings(wipe_copy, ".");
        Logger::instance().info("CompilerWipeVerifier: " + cwv.generate_wipe_verification_report(wr));
    }

    // IMP2: Runtime analysis integrator
    RuntimeAnalysisIntegrator rai;
    {
        std::string harness = rai.generate_sanitizer_harness(all_findings, ".");
        std::ofstream sh_out("run_sanitizer_audit.sh"); sh_out << harness;
        Logger::instance().info("RuntimeAnalysisIntegrator: run_sanitizer_audit.sh written");
    }

    // IMP3+4: BDB walker and iteration scorer
    BDBPageWalker bpw_walker;
    WalletIterationScorer wis_scorer;
    for (const auto& rel : releases) {
        for (const auto& wh : {"wallet.dat", "test/data/wallet.dat"}) {
            std::string wp = rel.name + "/" + wh;
            if (std::filesystem::exists(wp)) {
                auto bdb_analysis = bpw_walker.analyze_wallet_file(wp);
                if (bdb_analysis.confirmed_vulnerable)
                    all_findings.push_back(bpw_walker.create_confirmed_bdb_finding(bdb_analysis, rel.name));
                auto iter_score = wis_scorer.score_wallet(wp);
                all_findings.push_back(wis_scorer.create_iteration_finding(iter_score, rel.name));
                Logger::instance().info("BDBPageWalker+WalletIterationScorer: " + wp);
            }
        }
    }

    // IMP5: Cross-version diff
    CrossVersionDiffEngine cvde;
    auto diffs = cvde.compute_diffs(all_findings);
    {
        std::ofstream diff_f("cross_version_diff.txt");
        diff_f << cvde.generate_diff_report(diffs);
        Logger::instance().info("CrossVersionDiffEngine: " + std::to_string(diffs.size()) + " diffs");
    }

    // IMP8: Environment profile resolver
    EnvironmentProfileResolver epr;
    auto env_profile = epr.detect_current_environment();
    epr.resolve_crash_dump_findings(all_findings, env_profile);
    Logger::instance().info("EnvironmentProfileResolver: OS=" + env_profile.os_name);

    // IMP9: Automated fixture generator
    AutomatedWalletFixtureGenerator awfg;
    {
        std::ofstream ev_sh("generate_poc_evidence.sh");
        ev_sh << awfg.generate_fixture_harness(all_findings, "bitcoind");
        system("chmod +x generate_poc_evidence.sh 2>/dev/null");
        Logger::instance().info("AutomatedWalletFixtureGenerator: generate_poc_evidence.sh written");
    }

    // STREAM 1: Exploit runner
    ExploitRunner exploit_runner;
    exploit_runner.run(all_findings);
    Logger::instance().info("ExploitRunner: complete");

    auto end_time = std::chrono::steady_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::seconds>(end_time - start_time);
    int minutes = duration.count() / 60;
    int seconds = duration.count() % 60;
    
    Logger::instance().info("NoveltyExpansionOrchestrator: running chunked deduplication pipeline");

    // Collect all version names for deduplication
    std::vector<std::string> all_version_names;
    for (auto& r : releases) all_version_names.push_back(r.name);

    // Chunked processing: 500 findings at a time, write partial files
    int chunk_id = 0;
    std::filesystem::create_directories("report_chunks");
    size_t raw_total = all_findings.size();
    Logger::instance().info("Chunked pipeline: " + std::to_string(raw_total) +
        " raw findings → " + std::to_string((raw_total + 499) / 500) + " chunks");

    std::vector<CanonicalDeduplicator::CanonicalFinding> all_canonical;
    CanonicalDeduplicator global_dedup;
    std::vector<Finding> master_deduped;

    for (size_t chunk_start = 0; chunk_start < all_findings.size(); chunk_start += 500) {
        auto t_chunk = std::chrono::steady_clock::now();
        size_t chunk_end = std::min(chunk_start + 500, all_findings.size());
        std::vector<Finding> chunk(all_findings.begin() + chunk_start, all_findings.begin() + chunk_end);
        
        // Write chunk partial file
        ChunkedPipeline::write_chunk(chunk, chunk_id, "report_chunks");
        
        // Accumulate into master
        for (auto& f : chunk) master_deduped.push_back(f);
        
        auto t_elapsed_chunk = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - t_chunk).count();
        Logger::instance().info("[chunk " + std::to_string(chunk_id+1) + "/" +
            std::to_string((raw_total + 499) / 500) + "] processed " +
            std::to_string(chunk.size()) + " findings, " +
            std::to_string(t_elapsed_chunk) + "ms elapsed");
        chunk_id++;
    }

    // Final deduplication pass across all chunks
    auto canonical_findings = global_dedup.deduplicate(master_deduped, all_version_names);
    Logger::instance().info("Deduplication: " + std::to_string(raw_total) + " raw → " +
        std::to_string(canonical_findings.size()) + " unique (dedup ratio " +
        std::to_string(raw_total > 0 ? raw_total / std::max((size_t)1, canonical_findings.size()) : 1) + ":1)");

    // Emit v2 report
    auto end_time2 = std::chrono::steady_clock::now();
    double total_elapsed = std::chrono::duration_cast<std::chrono::seconds>(end_time2 - start_time).count();
    ReportV2Emitter rv2;
    rv2.emit(canonical_findings, all_version_names, static_cast<int>(raw_total), total_elapsed, "report_v1.json");

    // Also emit legacy report for backward compat
    Logger::instance().info("NoveltyExpansionOrchestrator: emitting enhanced report");
    EnhancedReportEmitter ere;
    auto summary = ere.compute_summary(collapsed);
    ere.set_summary(summary);
    long long gpu_est = (analysis.iteration_count > 0) ? (1000000000LL / analysis.iteration_count) : 100000LL;
    ere.set_oracle_analysis(
        analysis.oracle_viable,
        analysis.kdf_method,
        analysis.iteration_count,
        gpu_est,
        analysis.recommended_attack,
        4096LL
    );
    ere.set_analysis_time(minutes, seconds);
    ere.emit_json_report(collapsed);
    ere.log_completion_block();
    
    Logger::instance().info("NoveltyExpansionOrchestrator::run: complete");
}

std::string NoveltyExpansionOrchestrator::novelty_status_to_string(NoveltyClassifier::NoveltyStatus status) {
    switch (status) {
        case NoveltyClassifier::NoveltyStatus::GenuinelyNovel: return "Novel";
        case NoveltyClassifier::NoveltyStatus::KnownVariant: return "KnownVariant";
        case NoveltyClassifier::NoveltyStatus::DesignBehavior: return "DesignBehavior";
        case NoveltyClassifier::NoveltyStatus::Noise: return "Noise";
        case NoveltyClassifier::NoveltyStatus::HistoricalIssue: return "HistoricalCVE";
        case NoveltyClassifier::NoveltyStatus::InconclusiveNovel: return "InconclusiveNovel";
        case NoveltyClassifier::NoveltyStatus::NovelHighPriority: return "NovelHighPriority";
        default: return "Unknown";
    }
}


