    // ================================================================
    // APPENDIX C: Synchronization Dependency Graph
    // ================================================================
    void emit_appendix_c(std::ofstream& out, const std::vector<Finding>& findings) {
        out << "\n================================================================\n";
        out << "APPENDIX C: SYNCHRONIZATION DEPENDENCY GRAPH\n";
        out << "================================================================\n\n";
        out << "This appendix maps mutex dependencies and lock ordering\n";
        out << "constraints across the Bitcoin Core codebase.\n\n";

        // Known lock hierarchy
        out << "LOCK HIERARCHY (documented order):\n\n";
        out << "  Level 0 (outermost):\n";
        out << "    cs_main          - Global validation state\n";
        out << "    g_cs_orphans     - Orphan transaction pool\n\n";
        out << "  Level 1:\n";
        out << "    cs_wallet        - Wallet state (per-wallet)\n";
        out << "    cs_vNodes        - Network peer list\n";
        out << "    cs_mapLocalHost  - Local address mapping\n\n";
        out << "  Level 2:\n";
        out << "    cs_KeyStore      - Key storage (per-wallet)\n";
        out << "    cs_SpendableCoins - Spendable coin cache\n";
        out << "    cs_totalBytesRecv - Network statistics\n\n";
        out << "  Level 3 (innermost):\n";
        out << "    cs_vSend         - Per-peer send buffer\n";
        out << "    cs_vRecv         - Per-peer recv buffer\n";
        out << "    cs_hSocket       - Per-peer socket\n\n";

        // Lock ordering constraints
        out << "ORDERING CONSTRAINTS:\n\n";
        out << "  cs_main BEFORE cs_wallet          (validation before wallet update)\n";
        out << "  cs_main BEFORE cs_vNodes           (validation before peer state)\n";
        out << "  cs_wallet BEFORE cs_KeyStore       (wallet before key ops)\n";
        out << "  cs_vNodes BEFORE cs_vSend          (peer list before send buffer)\n";
        out << "  cs_vNodes BEFORE cs_vRecv           (peer list before recv buffer)\n\n";

        // Potential inversions from findings
        out << "DETECTED LOCK PATTERNS FROM ANALYSIS:\n\n";
        int lock_finding_count = 0;
        for (const auto& f : findings) {
            if (f.issue_type == IssueType::RaceCondition ||
                f.detailed_description.find("lock") != std::string::npos ||
                f.detailed_description.find("mutex") != std::string::npos ||
                f.detailed_description.find("concurrent") != std::string::npos) {
                out << "  [" << f.finding_id << "] " << f.file << ":" << f.location.line;
                out << " - " << f.detailed_description.substr(0, 80) << "\n";
                lock_finding_count++;
                if (lock_finding_count >= 50) {
                    out << "  ... additional lock-related findings omitted\n";
                    break;
                }
            }
        }
        if (lock_finding_count == 0) out << "  No lock ordering violations detected in current analysis.\n";

        out << "\nDEPENDENCY GRAPH (DOT format):\n\n";
        out << "  digraph lock_order {\n";
        out << "    rankdir=TB;\n";
        out << "    node [shape=box, style=filled, fillcolor=\"#e8e8e8\"];\n";
        out << "    cs_main -> cs_wallet;\n";
        out << "    cs_main -> cs_vNodes;\n";
        out << "    cs_main -> g_cs_orphans;\n";
        out << "    cs_wallet -> cs_KeyStore;\n";
        out << "    cs_wallet -> cs_SpendableCoins;\n";
        out << "    cs_vNodes -> cs_vSend;\n";
        out << "    cs_vNodes -> cs_vRecv;\n";
        out << "    cs_vNodes -> cs_hSocket;\n";
        out << "    cs_main -> cs_mapLocalHost;\n";
        out << "  }\n\n";
    }

