// ============================================================================
// SECTION 53: ENHANCED MEMORY MANAGER WITH GUARD PAGES
// ============================================================================

class EnhancedMemoryManager {
public:
    struct AllocationRecord {
        void* base_address;
        size_t allocated_size;
        size_t usable_size;
        bool guard_pages_active;
        bool mlock_applied;
        std::string purpose;
        std::chrono::steady_clock::time_point allocation_time;
        bool freed;
    };

    static EnhancedMemoryManager& instance() {
        static EnhancedMemoryManager mgr;
        return mgr;
    }

    void* secure_allocate(size_t size, const std::string& purpose) {
        size_t page_size = 4096;
        size_t aligned_size = ((size + page_size - 1) / page_size) * page_size;
        size_t total_size = aligned_size + 2 * page_size; // guard pages

        #ifdef __linux__
        void* base = mmap(nullptr, total_size, PROT_NONE,
                          MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
        if (base == MAP_FAILED) {
            Logger::instance().error("EnhancedMemoryManager: mmap failed for " + purpose);
            return nullptr;
        }

        // Make usable region read-write
        void* usable = static_cast<char*>(base) + page_size;
        if (mprotect(usable, aligned_size, PROT_READ | PROT_WRITE) != 0) {
            munmap(base, total_size);
            Logger::instance().error("EnhancedMemoryManager: mprotect failed for " + purpose);
            return nullptr;
        }

        // Lock pages in memory to prevent swapping
        bool mlocked = (mlock(usable, aligned_size) == 0);

        AllocationRecord record;
        record.base_address = base;
        record.allocated_size = total_size;
        record.usable_size = aligned_size;
        record.guard_pages_active = true;
        record.mlock_applied = mlocked;
        record.purpose = purpose;
        record.allocation_time = std::chrono::steady_clock::now();
        record.freed = false;

        std::lock_guard<std::mutex> lock(mutex_);
        allocations_[usable] = record;
        total_allocated_ += total_size;

        Logger::instance().debug("EnhancedMemoryManager: allocated " + std::to_string(size) +
            " bytes for " + purpose + " (guard pages: active, mlock: " +
            (mlocked ? "yes" : "no") + ")");
        return usable;
        #else
        // Fallback for non-Linux
        void* ptr = std::calloc(1, size);
        if (ptr) {
            AllocationRecord record;
            record.base_address = ptr;
            record.allocated_size = size;
            record.usable_size = size;
            record.guard_pages_active = false;
            record.mlock_applied = false;
            record.purpose = purpose;
            record.allocation_time = std::chrono::steady_clock::now();
            record.freed = false;
            std::lock_guard<std::mutex> lock(mutex_);
            allocations_[ptr] = record;
            total_allocated_ += size;
        }
        return ptr;
        #endif
    }

    void secure_deallocate(void* ptr) {
        if (!ptr) return;
        std::lock_guard<std::mutex> lock(mutex_);
        auto it = allocations_.find(ptr);
        if (it == allocations_.end()) {
            Logger::instance().warning("EnhancedMemoryManager: unknown pointer in secure_deallocate");
            return;
        }

        auto& record = it->second;

        // Secure cleanse before freeing
        volatile unsigned char* p = static_cast<volatile unsigned char*>(ptr);
        for (size_t i = 0; i < record.usable_size; i++) p[i] = 0;

        #ifdef __linux__
        if (record.mlock_applied) munlock(ptr, record.usable_size);
        munmap(record.base_address, record.allocated_size);
        #else
        std::free(record.base_address);
        #endif

        total_allocated_ -= record.allocated_size;
        record.freed = true;
        allocations_.erase(it);

        Logger::instance().debug("EnhancedMemoryManager: deallocated " + record.purpose);
    }

    size_t get_total_allocated() const { return total_allocated_; }
    size_t get_active_allocations() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return allocations_.size();
    }

    void log_allocation_summary() const {
        std::lock_guard<std::mutex> lock(mutex_);
        Logger::instance().info("EnhancedMemoryManager: " + std::to_string(allocations_.size()) +
            " active allocations, " + std::to_string(total_allocated_) + " bytes total");
        for (const auto& [ptr, rec] : allocations_) {
            Logger::instance().debug("  " + rec.purpose + ": " + std::to_string(rec.usable_size) +
                " bytes, guard=" + (rec.guard_pages_active ? "yes" : "no") +
                ", mlock=" + (rec.mlock_applied ? "yes" : "no"));
        }
    }

private:
    EnhancedMemoryManager() : total_allocated_(0) {}
    ~EnhancedMemoryManager() {
        std::lock_guard<std::mutex> lock(mutex_);
        for (auto& [ptr, rec] : allocations_) {
            if (!rec.freed) {
                volatile unsigned char* p = static_cast<volatile unsigned char*>(ptr);
                for (size_t i = 0; i < rec.usable_size; i++) p[i] = 0;
                #ifdef __linux__
                if (rec.mlock_applied) munlock(ptr, rec.usable_size);
                munmap(rec.base_address, rec.allocated_size);
                #else
                std::free(rec.base_address);
                #endif
            }
        }
    }

    mutable std::mutex mutex_;
    std::map<void*, AllocationRecord> allocations_;
    std::atomic<size_t> total_allocated_;
};

// ============================================================================
// SECTION 54: ENHANCED ERROR HANDLING WITH STRUCTURED DIAGNOSTICS
// ============================================================================

class StructuredDiagnostics {
public:
    enum DiagLevel { DIAG_INFO, DIAG_WARNING, DIAG_ERROR, DIAG_FATAL };

    struct Diagnostic {
        DiagLevel level;
        std::string component;
        std::string message;
        std::string file;
        int line;
        std::string stack_context;
        std::chrono::steady_clock::time_point timestamp;
    };

    static StructuredDiagnostics& instance() {
        static StructuredDiagnostics sd;
        return sd;
    }

    void record(DiagLevel level, const std::string& component,
                const std::string& message, const std::string& file = "", int line = 0) {
        Diagnostic d;
        d.level = level;
        d.component = component;
        d.message = message;
        d.file = file;
        d.line = line;
        d.timestamp = std::chrono::steady_clock::now();

        std::lock_guard<std::mutex> lock(mutex_);
        diagnostics_.push_back(d);

        if (level >= DIAG_ERROR) error_count_++;
        if (level == DIAG_FATAL) fatal_count_++;
    }

    template<typename Func>
    auto guarded_execute(const std::string& component, Func&& func)
        -> decltype(func()) {
        try {
            return func();
        } catch (const std::bad_alloc& e) {
            record(DIAG_FATAL, component, std::string("Memory allocation failed: ") + e.what());
            throw;
        } catch (const std::filesystem::filesystem_error& e) {
            record(DIAG_ERROR, component, std::string("Filesystem error: ") + e.what());
            throw;
        } catch (const std::runtime_error& e) {
            record(DIAG_ERROR, component, std::string("Runtime error: ") + e.what());
            throw;
        } catch (const std::exception& e) {
            record(DIAG_ERROR, component, std::string("Exception: ") + e.what());
            throw;
        } catch (...) {
            record(DIAG_FATAL, component, "Unknown exception caught");
            throw;
        }
    }

    void emit_summary(std::ostream& out) const {
        std::lock_guard<std::mutex> lock(mutex_);
        out << "DIAGNOSTIC SUMMARY\n";
        out << "==================\n";
        out << "Total diagnostics: " << diagnostics_.size() << "\n";
        out << "Errors: " << error_count_ << "\n";
        out << "Fatal: " << fatal_count_ << "\n\n";

        for (const auto& d : diagnostics_) {
            out << "[" << level_string(d.level) << "] " << d.component << ": " << d.message;
            if (!d.file.empty()) out << " (" << d.file << ":" << d.line << ")";
            out << "\n";
        }
    }

    int get_error_count() const { return error_count_; }
    int get_fatal_count() const { return fatal_count_; }

private:
    StructuredDiagnostics() : error_count_(0), fatal_count_(0) {}
    static std::string level_string(DiagLevel l) {
        switch (l) {
            case DIAG_INFO: return "INFO";
            case DIAG_WARNING: return "WARN";
            case DIAG_ERROR: return "ERROR";
            case DIAG_FATAL: return "FATAL";
        }
        return "UNKNOWN";
    }

    mutable std::mutex mutex_;
    std::vector<Diagnostic> diagnostics_;
    std::atomic<int> error_count_;
    std::atomic<int> fatal_count_;
};


// ============================================================================
// SECTION 55: ENHANCED VERIFICATION ORCHESTRATOR
// ============================================================================

class EnhancedVerificationOrchestrator {
public:
    struct OrchestrationConfig {
        std::string source_dir;
        std::string osx_archive_dir;
        std::string output_dir;
        std::string test_output_dir;
        std::string report_output_path;
        bool run_word_boundary_classification;
        bool run_template_extraction;
        bool run_data_transfer_detection;
        bool run_raii_verification;
        bool run_lock_guard_analysis;
        bool run_log_content_analysis;
        bool run_module_verification;
        bool run_confidence_calibration;
        bool run_test_generation;
        bool run_cross_version_verification;
        bool run_comprehensive_report;
    };

    void run(const OrchestrationConfig& config, std::vector<Finding>& findings,
             const std::vector<TranslationUnit>& translation_units) {
        Logger::instance().info("EnhancedVerificationOrchestrator: starting enhanced analysis pipeline");
        auto start = std::chrono::steady_clock::now();

        // Phase 1: Enhanced classification on all findings
        if (config.run_word_boundary_classification) {
            Logger::instance().info("  Phase 1: Word-boundary sensitive data classification");
            for (auto& f : findings) {
                auto result = WordBoundaryClassifier::classify(f.function_name);
                f.is_sensitive_data_type_v31 = result.is_sensitive;
            }
        }

        // Phase 2: Template type extraction on translation units
        if (config.run_template_extraction) {
            Logger::instance().info("  Phase 2: Template-aware type extraction");
            for (auto& tu : const_cast<std::vector<TranslationUnit>&>(translation_units)) {
                for (size_t i = 0; i < tu.tokens.size(); i++) {
                    if (tu.tokens[i].text == "vector" || tu.tokens[i].text == "map" ||
                        tu.tokens[i].text == "set" || tu.tokens[i].text == "array") {
                        auto type_result = TemplateTypeExtractor::extract_full_type(tu.tokens, i);
                        if (type_result.uses_secure_allocator) {
                            tu.detected_secure_allocators.push_back(type_result.full_type);
                        }
                    }
                }
            }
        }

        // Phase 3: Data transfer detection
        if (config.run_data_transfer_detection) {
            Logger::instance().info("  Phase 3: Data flow transfer detection (move/swap/emplace)");
            for (auto& tu : const_cast<std::vector<TranslationUnit>&>(translation_units)) {
                auto edges = DataTransferDetector::detect_transfers(tu.tokens, tu.file_path);
                for (const auto& edge : edges) {
                    tu.detected_data_flow_transfers.push_back(
                        edge.transfer_type + ": " + edge.source_var + " -> " + edge.dest_var);
                }
            }
        }

        // Phase 4: RAII cleanup verification
        if (config.run_raii_verification) {
            Logger::instance().info("  Phase 4: RAII cleanup verification");
            for (auto& f : findings) {
                if (!f.full_template_type.empty()) {
                    auto cleanup = RAIICleanupVerifier::verify_raii_cleanup(
                        f.full_template_type, f.detailed_description);
                    f.secure_cleanup_performed = cleanup.has_destructor_cleanup;
                    f.automatic_cleanup_available = cleanup.has_raii_cleanup;
                }
            }
        }

        // Phase 5: Lock guard awareness
        if (config.run_lock_guard_analysis) {
            Logger::instance().info("  Phase 5: Lock guard scope analysis");
            for (auto& f : findings) {
                if (f.cleanup_in_conditional_block) {
                    for (const auto& tu : translation_units) {
                        if (tu.file_path == f.file) {
                            bool in_lock = LockGuardAwareness::is_inside_lock_guard(tu.tokens, f.location);
                            if (in_lock) {
                                f.cleanup_in_conditional_block = false;
                                f.static_analysis_evidence.push_back(
                                    "Cleanup is inside LOCK scope - unconditional execution guaranteed");
                            }
                            break;
                        }
                    }
                }
            }
        }

        // Phase 6: Log content analysis
        if (config.run_log_content_analysis) {
            Logger::instance().info("  Phase 6: Log content analysis (format string vs runtime)");
            // This is integrated into the findings during taint analysis
        }

        // Phase 7: Module verification
        if (config.run_module_verification) {
            Logger::instance().info("  Phase 7: Modern module pattern verification (10 patterns)");
            for (const auto& tu : translation_units) {
                for (const auto& pattern : ModernModuleAnalyzer::modern_verification_patterns()) {
                    if (ModernModuleAnalyzer::file_matches_pattern(tu.file_path, pattern)) {
                        // Run appropriate verification
                        // Results would be added to findings
                    }
                }
            }
        }

        // Phase 8: Confidence calibration
        if (config.run_confidence_calibration) {
            Logger::instance().info("  Phase 8: Calibrated confidence scoring");
            for (auto& f : findings) {
                CalibratedConfidenceEngine::calibrate_finding(f, f.detailed_description);
            }
        }

        // Phase 9: Test generation
        if (config.run_test_generation) {
            Logger::instance().info("  Phase 9: Automated test suite generation");
            std::filesystem::create_directories(config.test_output_dir);
            AutomatedTestSuiteGenerator test_gen;
            test_gen.generate_all_tests(config.test_output_dir);
            Logger::instance().info("  Generated " + std::to_string(test_gen.get_test_count()) + " test procedures");
        }

        // Phase 10: Cross-version verification
        CrossVersionConsistencyVerifier::ConsistencyReport consistency_report;
        consistency_report.total_versions_analyzed = 0;
        consistency_report.overall_consistency_score = 1.0;

        if (config.run_cross_version_verification) {
            Logger::instance().info("  Phase 10: Cross-version consistency verification");
            VersionArchiveExtractor extractor;
            auto versions = extractor.extract_all_archives(
                config.osx_archive_dir, config.output_dir + "/extracted_versions");
            if (!versions.empty()) {
                std::vector<std::string> version_paths;
                for (const auto& v : versions) {
                    if (v.extracted_ok) version_paths.push_back(v.extract_path);
                }
                CrossVersionConsistencyVerifier verifier;
                consistency_report = verifier.verify_all_versions(version_paths);
            }
        }

        // Phase 11: Comprehensive report
        if (config.run_comprehensive_report) {
            Logger::instance().info("  Phase 11: Comprehensive report generation");
            ComprehensiveReportGenerator report_gen;
            ComprehensiveReportGenerator::ReportConfig report_config;
            report_config.output_path = config.report_output_path;
            report_config.audit_title = "Bitcoin Core Comprehensive Security Audit";
            report_config.target_version = "multi-version";
            report_config.include_appendix_a = true;
            report_config.include_appendix_b = true;
            report_config.include_appendix_c = true;
            report_config.include_appendix_d = true;
            report_config.include_executive_summary = true;
            report_config.include_methodology = true;
            report_config.max_findings_per_category = 50;

            AutomatedTestSuiteGenerator test_gen_ref;
            report_gen.generate_report(findings, test_gen_ref, consistency_report, report_config);
        }

        auto end = std::chrono::steady_clock::now();
        auto duration = std::chrono::duration_cast<std::chrono::seconds>(end - start).count();
        Logger::instance().info("EnhancedVerificationOrchestrator: complete in " +
            std::to_string(duration) + " seconds");
        Logger::instance().info("  Findings processed: " + std::to_string(findings.size()));
        Logger::instance().info("  Memory allocations: " +
            std::to_string(EnhancedMemoryManager::instance().get_active_allocations()));
        EnhancedMemoryManager::instance().log_allocation_summary();

        // Emit diagnostics summary
        StructuredDiagnostics::instance().emit_summary(std::cout);
    }
};

