// Phase 2 - Section A: Recursive Path Explorer & Call Site Analyzer
// ============================================================================

// --- A.1: Call Site Analysis Data Structure ---

struct CallSiteAnalysis {
    std::string caller_function;
    std::string callee_function;
    int call_line;
    std::vector<std::string> arguments_passed;
    std::vector<bool> argument_is_sensitive;
    bool has_return_value_check;
    bool is_inside_lock;
    std::string active_lock;
    bool is_inside_try_block;
    bool has_corresponding_catch;
    int control_flow_complexity;
};

// --- A.2: Call Graph Path Explorer ---

class CallGraphPathExplorer {
public:
    struct CallGraphNode {
        std::string function_name;
        std::string file_path;
        int line_number;
        std::vector<CallGraphNode*> callees;
        std::vector<CallGraphNode*> callers;
        bool is_sensitive_function;
        bool is_bridge_function;
        std::string module_name;
        int cyclomatic_complexity;
    };

    struct ExplorationPath {
        std::vector<CallGraphNode*> nodes;
        std::set<std::string> visited_functions;
        int depth;
        bool reached_sensitive_operation;
        std::vector<std::string> guard_conditions;
        std::vector<std::string> locks_held;
        double risk_score;
    };

    static constexpr int MAX_CALL_DEPTH = 50;

private:
    std::unordered_map<std::string, std::unique_ptr<CallGraphNode>> nodes_;
    std::set<std::string> sensitive_functions_;
    std::set<std::string> public_entry_points_;
    mutable std::mutex mutex_;

    static const std::set<std::string>& default_sensitive_functions() {
        static const std::set<std::string> funcs = {
            "GenerateNewKey", "DeriveNewChildKey", "GetKey", "GetPrivKey",
            "SignCompact", "Sign", "Decrypt", "Encrypt",
            "SetKeyFromPassphrase", "ChangeWalletPassphrase",
            "AddKeyPubKey", "LoadKey", "LoadCryptedKey",
            "CreateTransaction", "CommitTransaction", "SignTransaction",
            "AcceptToMemoryPool", "CheckBlock", "ConnectBlock", "DisconnectBlock",
            "ActivateBestChain", "InvalidateBlock", "RewindBlockIndex",
            "ProcessNewBlock", "ProcessNewBlockHeaders",
            "GetBalance", "AvailableCoins", "SelectCoins",
            "IsMine", "HaveKey", "GetKeyFromPool",
            "TopUpKeyPool", "EncryptWallet", "UnlockWallet",
            "memory_cleanse", "OPENSSL_cleanse", "SecureErase",
            "GetRandBytes", "GetStrongRandBytes", "GenRandomKey",
            "DeriveKeys", "ComputeMerkleRoot", "CheckProofOfWork",
            "ImportPrivKey", "DumpPrivKey", "BackupWallet"
        };
        return funcs;
    }

    static const std::set<std::string>& default_entry_points() {
        static const std::set<std::string> entries = {
            "main", "AppInit2", "AppInitMain", "AppInitBasicSetup",
            "ProcessMessage", "ProcessGetData", "ProcessHeadersMessage",
            "getnewaddress", "sendtoaddress", "signrawtransactionwithwallet",
            "importprivkey", "dumpprivkey", "walletpassphrase", "walletlock",
            "encryptwallet", "getbalance", "listunspent", "listtransactions",
            "submitblock", "getblocktemplate", "generateblock", "generatetoaddress",
            "getblock", "getblockheader", "gettxout", "getrawtransaction",
            "CreateNewBlock", "IncrementExtraNonce",
            "ThreadSocketHandler", "ThreadOpenConnections",
            "ThreadMessageHandler", "ThreadDNSAddressSeed",
            "PeerManagerImpl::ProcessMessage", "NetEventsInterface::ProcessMessages"
        };
        return entries;
    }

public:
    CallGraphPathExplorer() {
        sensitive_functions_ = default_sensitive_functions();
        public_entry_points_ = default_entry_points();
    }

    void add_sensitive_function(const std::string& func_name) {
        sensitive_functions_.insert(func_name);
    }

    void add_entry_point(const std::string& func_name) {
        public_entry_points_.insert(func_name);
    }

    // Build call graph from translation unit token stream
    void build_call_graph(const TranslationUnit& tu) {
        Logger::instance().info("CallGraphPathExplorer: building call graph from " + tu.file_path);

        std::string current_function;
        int brace_depth = 0;
        bool in_function = false;
        int function_start_brace = 0;

        for (size_t i = 0; i < tu.tokens.size(); i++) {
            const auto& tok = tu.tokens[i];

            // Detect function definition: identifier ( params ) {
            if (tok.type == TokenType::Identifier && i + 1 < tu.tokens.size() &&
                tu.tokens[i + 1].text == "(") {
                int paren_depth = 0;
                bool found_body = false;
                size_t j = i + 1;
                while (j < tu.tokens.size() && j < i + 200) {
                    if (tu.tokens[j].text == "(") paren_depth++;
                    else if (tu.tokens[j].text == ")") {
                        paren_depth--;
                        if (paren_depth == 0) {
                            for (size_t k = j + 1; k < tu.tokens.size() && k < j + 10; k++) {
                                if (tu.tokens[k].text == "{") { found_body = true; break; }
                                if (tu.tokens[k].text == ";") break;
                            }
                            break;
                        }
                    }
                    j++;
                }

                if (found_body && brace_depth == 0) {
                    // Resolve qualified name: Class::Method
                    std::string func_name = tok.text;
                    if (i >= 2 && tu.tokens[i - 1].text == "::" &&
                        tu.tokens[i - 2].type == TokenType::Identifier) {
                        func_name = tu.tokens[i - 2].text + "::" + tok.text;
                    }
                    current_function = func_name;
                    ensure_node(current_function, tu.file_path, tok.location.line);
                }
            }

            // Track brace depth
            if (tok.text == "{") {
                if (!current_function.empty() && !in_function) {
                    in_function = true;
                    function_start_brace = brace_depth;
                }
                brace_depth++;
            } else if (tok.text == "}") {
                brace_depth--;
                if (brace_depth == function_start_brace && in_function) {
                    in_function = false;
                    current_function.clear();
                }
            }

            // Detect function calls within a body
            if (in_function && !current_function.empty() &&
                tok.type == TokenType::Identifier && i + 1 < tu.tokens.size() &&
                tu.tokens[i + 1].text == "(") {
                std::string callee = tok.text;
                // Skip control-flow keywords and casts
                static const std::set<std::string> skip = {
                    "if", "for", "while", "switch", "return", "sizeof",
                    "static_cast", "dynamic_cast", "reinterpret_cast",
                    "const_cast", "decltype", "alignof", "noexcept",
                    "throw", "catch", "delete"
                };
                if (skip.count(callee) || callee == current_function) continue;

                // Resolve qualified name
                std::string full_callee = callee;
                if (i >= 2 && tu.tokens[i - 1].text == "::" &&
                    tu.tokens[i - 2].type == TokenType::Identifier) {
                    full_callee = tu.tokens[i - 2].text + "::" + callee;
                }

                auto* callee_node = ensure_node(full_callee, tu.file_path, tok.location.line);
                auto* caller_node = ensure_node(current_function, tu.file_path, 0);
                add_edge(caller_node, callee_node);
            }
        }

        // Post-process: mark sensitive functions and bridge functions
        for (auto& [name, node] : nodes_) {
            node->is_sensitive_function = sensitive_functions_.count(name) > 0;
            node->module_name = detect_module(name);
            node->is_bridge_function = false;
        }
        // Bridge detection: function whose callers are in a different module than its callees
        for (auto& [name, node] : nodes_) {
            if (node->callees.empty() || node->callers.empty()) continue;
            std::string caller_mod = detect_dominant_module(node->callers);
            std::string callee_mod = detect_dominant_module(node->callees);
            if (!caller_mod.empty() && !callee_mod.empty() && caller_mod != callee_mod)
                node->is_bridge_function = true;
        }

        Logger::instance().info("CallGraphPathExplorer: " + std::to_string(nodes_.size()) +
            " nodes, " + std::to_string(count_edges()) + " edges");
    }

    // Explore all paths from entry_function forward to any sensitive operation
    std::vector<ExplorationPath> explore_from_source(
            const std::string& entry_function,
            const std::set<std::string>& sensitive_operations) const {
        std::vector<ExplorationPath> results;
        auto it = nodes_.find(entry_function);
        if (it == nodes_.end()) return results;

        ExplorationPath initial;
        initial.depth = 0;
        initial.reached_sensitive_operation = false;
        initial.risk_score = 0.0;
        depth_first_explore(it->second.get(), initial, results, sensitive_operations, 0);
        return results;
    }

    // Trace backward from vulnerable_operation to all known entry points
    std::vector<ExplorationPath> trace_to_entry_points(
            const std::string& vulnerable_operation) const {
        std::vector<ExplorationPath> results;
        auto it = nodes_.find(vulnerable_operation);
        if (it == nodes_.end()) return results;

        ExplorationPath initial;
        initial.depth = 0;
        initial.reached_sensitive_operation = true;
        initial.risk_score = 0.0;
        reverse_explore(it->second.get(), initial, results, public_entry_points_, 0);
        return results;
    }

    // Find paths to sensitive_operation that lack all required_guards
    std::vector<ExplorationPath> find_unguarded_paths(
            const std::string& sensitive_operation,
            const std::set<std::string>& required_guards) {
        std::vector<ExplorationPath> all_paths = trace_to_entry_points(sensitive_operation);
        std::vector<ExplorationPath> unguarded;
        for (const auto& path : all_paths) {
            bool all_present = true;
            for (const auto& guard : required_guards) {
                if (!path_has_guard(path, guard)) {
                    all_present = false;
                    break;
                }
            }
            if (!all_present) unguarded.push_back(path);
        }
        return unguarded;
    }

    // Find paths crossing module boundaries
    std::vector<ExplorationPath> find_cross_module_paths(
            const std::string& source_module,
            const std::string& target_module) {
        std::vector<ExplorationPath> results;
        for (const auto& [name, node] : nodes_) {
            if (detect_module(name) != source_module) continue;
            for (auto* callee : node->callees) {
                if (detect_module(callee->function_name) == target_module) {
                    ExplorationPath path;
                    path.nodes = {node.get(), callee};
                    path.depth = 1;
                    path.reached_sensitive_operation = callee->is_sensitive_function;
                    path.risk_score = callee->is_sensitive_function ? 0.8 : 0.3;
                    results.push_back(path);
                }
            }
        }
        return results;
    }

    // Generate findings for all unguarded paths to sensitive operations
    std::vector<Finding> generate_unguarded_path_findings() {
        std::vector<Finding> findings;

        // Map of sensitive operations to their required guards
        std::map<std::string, std::set<std::string>> sensitive_guards = {
            {"SignCompact", {"cs_wallet", "EnsureWalletIsUnlocked"}},
            {"GetKey", {"cs_KeyStore"}},
            {"GetPrivKey", {"cs_KeyStore"}},
            {"CommitTransaction", {"cs_wallet", "cs_main"}},
            {"AcceptToMemoryPool", {"cs_main"}},
            {"ConnectBlock", {"cs_main"}},
            {"DisconnectBlock", {"cs_main"}},
            {"EncryptWallet", {"cs_wallet"}},
            {"ImportPrivKey", {"cs_wallet"}},
            {"DumpPrivKey", {"cs_wallet", "EnsureWalletIsUnlocked"}},
            {"ProcessNewBlock", {"cs_main"}},
            {"ActivateBestChain", {"cs_main"}},
        };

        for (const auto& [op, guards] : sensitive_guards) {
            auto unguarded = find_unguarded_paths(op, guards);
            for (const auto& path : unguarded) {
                Finding f;
                f.finding_id = IDGenerator::instance().next();
                f.function_name = op;
                f.issue_type = IssueType::RaceCondition;
                f.severity = Severity::High;
                f.confidence = 0.70;
                f.classification = Classification::ConfirmedStatic;
                f.detailed_description = "Unguarded path to sensitive operation '" + op +
                    "' reachable from entry point '" +
                    (path.nodes.empty() ? "unknown" : path.nodes.front()->function_name) +
                    "' at depth=" + std::to_string(path.depth) +
                    " without required guard(s): ";
                // List missing guards
                for (const auto& g : guards) {
                    if (!path_has_guard(path, g))
                        f.detailed_description += g + " ";
                }
                if (!path.nodes.empty()) {
                    f.file = path.nodes.front()->file_path;
                    f.location = SourceLocation(f.file, path.nodes.front()->line_number, 1);
                }
                f.static_analysis_evidence.push_back(
                    "call-graph path depth: " + std::to_string(path.depth));
                f.static_analysis_evidence.push_back(
                    "risk score: " + std::to_string(path.risk_score));
                f.code_path_trace.reserve(path.nodes.size());
                for (auto* n : path.nodes) f.code_path_trace.push_back(n->function_name);
                findings.push_back(f);
            }
        }
        return findings;
    }

    size_t node_count() const { return nodes_.size(); }
    size_t count_edges() const {
        size_t edges = 0;
        for (const auto& [name, node] : nodes_) edges += node->callees.size();
        return edges;
    }

    std::string serialize_path(const ExplorationPath& path) const {
        std::ostringstream oss;
        for (size_t i = 0; i < path.nodes.size(); i++) {
            if (i > 0) oss << " -> ";
            oss << path.nodes[i]->function_name;
            if (path.nodes[i]->is_sensitive_function) oss << " [SENSITIVE]";
            if (path.nodes[i]->is_bridge_function) oss << " [BRIDGE]";
        }
        oss << " (depth=" << path.depth << ", risk=" << std::fixed
            << std::setprecision(2) << path.risk_score << ")";
        return oss.str();
    }

private:
    CallGraphNode* ensure_node(const std::string& name, const std::string& file, int line) {
        auto it = nodes_.find(name);
        if (it != nodes_.end()) return it->second.get();
        auto node = std::make_unique<CallGraphNode>();
        node->function_name = name;
        node->file_path = file;
        node->line_number = line;
        node->is_sensitive_function = false;
        node->is_bridge_function = false;
        node->cyclomatic_complexity = 0;
        auto* ptr = node.get();
        nodes_[name] = std::move(node);
        return ptr;
    }

    void add_edge(CallGraphNode* caller, CallGraphNode* callee) {
        for (auto* existing : caller->callees)
            if (existing == callee) return;
        caller->callees.push_back(callee);
        callee->callers.push_back(caller);
    }

    void depth_first_explore(
            CallGraphNode* current,
            ExplorationPath& current_path,
            std::vector<ExplorationPath>& results,
            const std::set<std::string>& targets,
            int depth) const {
        if (depth > MAX_CALL_DEPTH) return;
        if (current_path.visited_functions.count(current->function_name)) return;

        current_path.nodes.push_back(current);
        current_path.visited_functions.insert(current->function_name);
        current_path.depth = depth;

        // Track lock acquisitions along the path
        if (current->function_name.find("LOCK") != std::string::npos ||
            current->function_name.find("lock_guard") != std::string::npos ||
            current->function_name.find("AssertLockHeld") != std::string::npos)
            current_path.locks_held.push_back(current->function_name);

        // Track guard conditions
        if (current->function_name.find("Ensure") != std::string::npos ||
            current->function_name.find("Assert") != std::string::npos ||
            current->function_name.find("Check") != std::string::npos ||
            current->function_name.find("Verify") != std::string::npos)
            current_path.guard_conditions.push_back(current->function_name);

        // Check if we reached a sensitive target
        if (targets.count(current->function_name)) {
            current_path.reached_sensitive_operation = true;
            current_path.risk_score = compute_path_risk(current_path);
            results.push_back(current_path);
            // Don't return - continue exploring through the target
        }

        // Recurse into callees
        for (auto* callee : current->callees) {
            ExplorationPath branch = current_path;
            depth_first_explore(callee, branch, results, targets, depth + 1);
        }

        current_path.nodes.pop_back();
        current_path.visited_functions.erase(current->function_name);
    }

    void reverse_explore(
            CallGraphNode* current,
            ExplorationPath& current_path,
            std::vector<ExplorationPath>& results,
            const std::set<std::string>& entry_points,
            int depth) const {
        if (depth > MAX_CALL_DEPTH) return;
        if (current_path.visited_functions.count(current->function_name)) return;

        current_path.nodes.push_back(current);
        current_path.visited_functions.insert(current->function_name);
        current_path.depth = depth;

        // Track locks and guards along reverse path
        if (current->function_name.find("LOCK") != std::string::npos ||
            current->function_name.find("lock_guard") != std::string::npos)
            current_path.locks_held.push_back(current->function_name);
        if (current->function_name.find("Ensure") != std::string::npos ||
            current->function_name.find("Check") != std::string::npos)
            current_path.guard_conditions.push_back(current->function_name);

        if (entry_points.count(current->function_name)) {
            current_path.risk_score = compute_path_risk(current_path);
            results.push_back(current_path);
        }

        for (auto* caller : current->callers) {
            ExplorationPath branch = current_path;
            reverse_explore(caller, branch, results, entry_points, depth + 1);
        }

        current_path.nodes.pop_back();
        current_path.visited_functions.erase(current->function_name);
    }

    bool path_has_guard(const ExplorationPath& path, const std::string& guard) const {
        for (auto* n : path.nodes)
            if (n->function_name.find(guard) != std::string::npos) return true;
        for (const auto& g : path.guard_conditions)
            if (g.find(guard) != std::string::npos) return true;
        for (const auto& l : path.locks_held)
            if (l.find(guard) != std::string::npos) return true;
        return false;
    }

    double compute_path_risk(const ExplorationPath& path) const {
        double risk = 0.05 * path.depth;
        int sensitive_count = 0;
        int bridge_count = 0;
        for (auto* n : path.nodes) {
            if (n->is_sensitive_function) { risk += 0.25; sensitive_count++; }
            if (n->is_bridge_function) { risk += 0.15; bridge_count++; }
        }
        if (path.locks_held.empty()) risk += 0.4;
        if (path.guard_conditions.empty()) risk += 0.2;
        // Penalize paths with many module crossings
        if (bridge_count > 2) risk += 0.1 * (bridge_count - 2);
        return std::min(1.0, risk);
    }

    std::string detect_module(const std::string& func_name) const {
        if (func_name.find("wallet") != std::string::npos ||
            func_name.find("Wallet") != std::string::npos ||
            func_name.find("CWallet") != std::string::npos) return "wallet";
        if (func_name.find("Connect") != std::string::npos ||
            func_name.find("Disconnect") != std::string::npos ||
            func_name.find("Block") != std::string::npos ||
            func_name.find("Chain") != std::string::npos ||
            func_name.find("UTXO") != std::string::npos) return "validation";
        if (func_name.find("Process") != std::string::npos ||
            func_name.find("Message") != std::string::npos ||
            func_name.find("Peer") != std::string::npos ||
            func_name.find("Socket") != std::string::npos ||
            func_name.find("Net") != std::string::npos) return "net";
        if (func_name.find("RPC") != std::string::npos ||
            func_name.find("rpc") != std::string::npos ||
            func_name.find("HTTP") != std::string::npos) return "rpc";
        if (func_name.find("Sign") != std::string::npos ||
            func_name.find("Key") != std::string::npos ||
            func_name.find("Encrypt") != std::string::npos ||
            func_name.find("Decrypt") != std::string::npos ||
            func_name.find("Hash") != std::string::npos) return "crypto";
        if (func_name.find("Script") != std::string::npos ||
            func_name.find("Eval") != std::string::npos) return "script";
        if (func_name.find("mempool") != std::string::npos ||
            func_name.find("Mempool") != std::string::npos ||
            func_name.find("CTxMemPool") != std::string::npos) return "mempool";
        return "core";
    }

    std::string detect_dominant_module(const std::vector<CallGraphNode*>& nodes) const {
        std::map<std::string, int> counts;
        for (auto* n : nodes) counts[detect_module(n->function_name)]++;
        std::string best;
        int best_count = 0;
        for (const auto& [mod, count] : counts)
            if (count > best_count) { best_count = count; best = mod; }
        return best;
    }
};

// --- A.3: Call Site Analyzer ---

class CallSiteAnalyzer {
public:
    // Analyze every call site within function_name for security properties
    std::vector<CallSiteAnalysis> analyze_all_call_sites(
            const std::string& function_name,
            const std::vector<Token>& tokens) {
        std::vector<CallSiteAnalysis> results;
        bool in_target = false;
        int brace_depth = 0;
        int target_brace = 0;
        std::string current_lock;
        bool in_try = false;
        int try_brace = 0;

        for (size_t i = 0; i < tokens.size(); i++) {
            const auto& tok = tokens[i];

            // Find the target function body
            if (!in_target && tok.type == TokenType::Identifier &&
                tok.text == function_name && i + 1 < tokens.size() &&
                tokens[i + 1].text == "(") {
                size_t j = i + 1;
                int pd = 0;
                while (j < tokens.size()) {
                    if (tokens[j].text == "(") pd++;
                    else if (tokens[j].text == ")") { pd--; if (pd == 0) break; }
                    j++;
                }
                if (j + 1 < tokens.size()) {
                    for (size_t k = j + 1; k < tokens.size() && k < j + 8; k++) {
                        if (tokens[k].text == "{") {
                            in_target = true;
                            target_brace = brace_depth;
                            i = k;
                            break;
                        }
                    }
                }
                continue;
            }

            if (!in_target) continue;

            // Track braces
            if (tok.text == "{") brace_depth++;
            else if (tok.text == "}") {
                brace_depth--;
                if (brace_depth <= target_brace) break;
            }

            // Track lock state
            if (tok.text == "LOCK" || tok.text == "LOCK2" || tok.text == "lock_guard" ||
                tok.text == "unique_lock" || tok.text == "scoped_lock") {
                if (i + 2 < tokens.size() && tokens[i + 1].text == "(")
                    current_lock = tokens[i + 2].text;
            }

            // Track try blocks
            if (tok.text == "try") { in_try = true; try_brace = brace_depth; }
            if (tok.text == "catch" && in_try && brace_depth <= try_brace) in_try = false;

            // Detect function calls
            if (tok.type == TokenType::Identifier && i + 1 < tokens.size() &&
                tokens[i + 1].text == "(") {
                static const std::set<std::string> skip = {
                    "if", "for", "while", "switch", "sizeof", "return",
                    "static_cast", "dynamic_cast", "reinterpret_cast", "const_cast"
                };
                if (skip.count(tok.text)) continue;

                CallSiteAnalysis csa;
                csa.caller_function = function_name;
                csa.callee_function = tok.text;
                csa.call_line = tok.location.line;
                csa.is_inside_lock = !current_lock.empty();
                csa.active_lock = current_lock;
                csa.is_inside_try_block = in_try;
                csa.control_flow_complexity = brace_depth - target_brace;

                // Extract arguments
                int arg_paren = 0;
                std::string current_arg;
                for (size_t j = i + 1; j < tokens.size(); j++) {
                    if (tokens[j].text == "(") { arg_paren++; if (arg_paren == 1) continue; }
                    else if (tokens[j].text == ")") {
                        arg_paren--;
                        if (arg_paren == 0) {
                            if (!current_arg.empty()) {
                                csa.arguments_passed.push_back(current_arg);
                                csa.argument_is_sensitive.push_back(
                                    WordBoundaryClassifier::classify(current_arg).is_sensitive);
                            }
                            break;
                        }
                    } else if (tokens[j].text == "," && arg_paren == 1) {
                        if (!current_arg.empty()) {
                            csa.arguments_passed.push_back(current_arg);
                            csa.argument_is_sensitive.push_back(
                                WordBoundaryClassifier::classify(current_arg).is_sensitive);
                        }
                        current_arg.clear();
                        continue;
                    }
                    if (tokens[j].type == TokenType::Identifier)
                        current_arg = tokens[j].text;
                }

                // Check if return value is used
                csa.has_return_value_check = false;
                if (i >= 2) {
                    if (tokens[i - 1].text == "=" || tokens[i - 1].text == "!" ||
                        tokens[i - 1].text == "assert" ||
                        tokens[i - 2].text == "if" || tokens[i - 2].text == "auto" ||
                        tokens[i - 2].text == "bool" || tokens[i - 2].text == "int" ||
                        tokens[i - 2].text == "CAmount" || tokens[i - 2].text == "std")
                        csa.has_return_value_check = true;
                }

                // Check for catch block
                csa.has_corresponding_catch = false;
                if (csa.is_inside_try_block) {
                    for (size_t j = i; j < tokens.size() && j < i + 300; j++) {
                        if (tokens[j].text == "catch") { csa.has_corresponding_catch = true; break; }
                    }
                }

                results.push_back(csa);
            }
        }
        return results;
    }

    // Find call sites where sensitive data is passed without sanitization
    std::vector<CallSiteAnalysis> find_unchecked_sensitive_passing(
            const std::string& function_name,
            const std::vector<Token>& tokens) {
        auto all = analyze_all_call_sites(function_name, tokens);
        std::vector<CallSiteAnalysis> unchecked;
        for (const auto& site : all) {
            for (size_t j = 0; j < site.argument_is_sensitive.size(); j++) {
                if (site.argument_is_sensitive[j]) {
                    unchecked.push_back(site);
                    break;
                }
            }
        }
        return unchecked;
    }

    // Find critical function calls whose return value is not checked
    std::vector<CallSiteAnalysis> find_unchecked_return_values(
            const std::string& function_name,
            const std::vector<Token>& tokens,
            const std::set<std::string>& critical_functions) {
        auto all = analyze_all_call_sites(function_name, tokens);
        std::vector<CallSiteAnalysis> unchecked;
        for (const auto& site : all) {
            if (critical_functions.count(site.callee_function) && !site.has_return_value_check)
                unchecked.push_back(site);
        }
        return unchecked;
    }
};


// ============================================================================
// SECTION 57: INTER-PROCEDURAL DATA FLOW MERGER
// Phase 2 - Section B: Cross-Function Taint Propagation & Global State Analysis
// ============================================================================

// --- B.1: Inter-Procedural Data Flow ---

class InterProceduralDataFlow {
public:
    struct FunctionSummary {
        std::string function_name;
        std::string file_path;
        std::set<std::string> parameters_that_taint_return;
        std::set<int> parameter_indices_that_taint_other_params;
        std::set<std::string> global_variables_read;
        std::set<std::string> global_variables_modified;
        bool returns_sensitive_data;
        bool writes_sensitive_to_global;
        bool calls_sensitive_function;
        std::set<std::string> sensitive_callees;
        int taint_complexity;
    };

private:
    std::unordered_map<std::string, FunctionSummary> function_summaries_;
    mutable std::mutex mutex_;

    static const std::set<std::string>& known_globals() {
        static const std::set<std::string> globals = {
            "cs_main", "g_chainman", "g_connman", "mapBlockIndex",
            "pindexBestHeader", "nTimeBestReceived", "g_best_block",
            "mempool", "g_txindex", "g_chainstate", "g_rpc_node",
            "g_signals", "pwalletMain", "vNodes", "mapLocalHost",
            "cs_vNodes", "cs_wallet", "cs_KeyStore",
            "nConnectTimeout", "nMaxConnections", "nLocalServices",
            "fReindex", "fPruneMode", "fIBD"
        };
        return globals;
    }

    static const std::set<std::string>& sensitive_callees() {
        static const std::set<std::string> funcs = {
            "GetKey", "GetPrivKey", "SignCompact", "Sign", "Decrypt",
            "DeriveNewChildKey", "GenerateNewKey", "GetRandBytes",
            "GetStrongRandBytes", "GenRandomKey", "memory_cleanse",
            "OPENSSL_cleanse", "SecureErase", "DeriveKeys",
            "ComputeMerkleRoot", "CheckProofOfWork"
        };
        return funcs;
    }

public:
    // Build per-function summaries of taint flow behaviour
    void build_function_summaries(const TranslationUnit& tu) {
        Logger::instance().info("InterProceduralDataFlow: building summaries for " + tu.file_path);

        std::string current_function;
        int brace_depth = 0;
        bool in_function = false;
        int func_brace_start = 0;
        std::vector<std::string> current_params;
        FunctionSummary current_summary;

        for (size_t i = 0; i < tu.tokens.size(); i++) {
            const auto& tok = tu.tokens[i];

            // Detect function definition
            if (!in_function && tok.type == TokenType::Identifier &&
                i + 1 < tu.tokens.size() && tu.tokens[i + 1].text == "(") {

                // Extract parameter names
                size_t j = i + 1;
                int pd = 0;
                current_params.clear();
                while (j < tu.tokens.size() && j < i + 200) {
                    if (tu.tokens[j].text == "(") pd++;
                    else if (tu.tokens[j].text == ")") {
                        pd--;
                        if (pd == 0) break;
                    }
                    // Parameter name: identifier followed by , or )
                    if (pd == 1 && tu.tokens[j].type == TokenType::Identifier &&
                        j + 1 < tu.tokens.size() &&
                        (tu.tokens[j + 1].text == "," || tu.tokens[j + 1].text == ")"))
                        current_params.push_back(tu.tokens[j].text);
                    j++;
                }

                // Confirm function body exists
                bool found_body = false;
                for (size_t k = j + 1; k < tu.tokens.size() && k < j + 10; k++) {
                    if (tu.tokens[k].text == "{") { found_body = true; break; }
                    if (tu.tokens[k].text == ";") break;
                }

                if (found_body && brace_depth == 0) {
                    std::string func_name = tok.text;
                    if (i >= 2 && tu.tokens[i - 1].text == "::" &&
                        tu.tokens[i - 2].type == TokenType::Identifier)
                        func_name = tu.tokens[i - 2].text + "::" + tok.text;

                    current_function = func_name;
                    current_summary = FunctionSummary();
                    current_summary.function_name = current_function;
                    current_summary.file_path = tu.file_path;
                    current_summary.returns_sensitive_data = false;
                    current_summary.writes_sensitive_to_global = false;
                    current_summary.calls_sensitive_function = false;
                    current_summary.taint_complexity = 0;
                }
            }

            if (tok.text == "{") {
                if (!current_function.empty() && !in_function) {
                    in_function = true;
                    func_brace_start = brace_depth;
                }
                brace_depth++;
            } else if (tok.text == "}") {
                brace_depth--;
                if (brace_depth == func_brace_start && in_function) {
                    // Finalise and store this function summary
                    std::lock_guard<std::mutex> lock(mutex_);
                    function_summaries_[current_function] = current_summary;
                    in_function = false;
                    current_function.clear();
                }
            }

            if (!in_function || current_function.empty()) continue;

            // Track return statements returning sensitive data
            if (tok.text == "return" && i + 1 < tu.tokens.size()) {
                std::string return_expr;
                for (size_t j = i + 1; j < tu.tokens.size() && tu.tokens[j].text != ";"; j++) {
                    if (tu.tokens[j].type == TokenType::Identifier) return_expr = tu.tokens[j].text;
                }
                auto cls = WordBoundaryClassifier::classify(return_expr);
                if (cls.is_sensitive) current_summary.returns_sensitive_data = true;

                // Check if return value comes from a parameter
                for (const auto& param : current_params) {
                    if (return_expr == param)
                        current_summary.parameters_that_taint_return.insert(param);
                }
            }

            // Track calls to known sensitive functions
            if (tok.type == TokenType::Identifier && i + 1 < tu.tokens.size() &&
                tu.tokens[i + 1].text == "(") {
                if (sensitive_callees().count(tok.text)) {
                    current_summary.calls_sensitive_function = true;
                    current_summary.sensitive_callees.insert(tok.text);
                }
            }

            // Track global variable access patterns
            if (tok.type == TokenType::Identifier && known_globals().count(tok.text)) {
                current_summary.global_variables_read.insert(tok.text);
                // Detect writes: assignment operators following the global
                if (i + 1 < tu.tokens.size()) {
                    const auto& next = tu.tokens[i + 1].text;
                    if (next == "=" || next == "+=" || next == "-=" ||
                        next == "*=" || next == "/=" || next == "&=" ||
                        next == "|=" || next == "^=" || next == "<<=" ||
                        next == ">>=" || next == "." || next == "->") {
                        current_summary.global_variables_modified.insert(tok.text);
                        // Check if writing sensitive data to a global
                        if (i + 2 < tu.tokens.size()) {
                            auto val_cls = WordBoundaryClassifier::classify(tu.tokens[i + 2].text);
                            if (val_cls.is_sensitive)
                                current_summary.writes_sensitive_to_global = true;
                        }
                    }
                }
            }

            current_summary.taint_complexity++;
        }

        Logger::instance().info("InterProceduralDataFlow: " +
            std::to_string(function_summaries_.size()) + " function summaries built");
    }

    // Propagate taint across function call boundaries using call graph
    void propagate_taint_across_calls(
            std::vector<Finding>& findings,
            const CallGraphPathExplorer& call_graph) {
        Logger::instance().info("InterProceduralDataFlow: propagating taint across call boundaries");
        int propagation_count = 0;
        int cross_function_taints = 0;

        for (auto& f : findings) {
            if (!f.is_sensitive_data_type_v31) continue;

            auto it = function_summaries_.find(f.function_name);
            if (it == function_summaries_.end()) continue;
            const auto& summary = it->second;

            // If function returns sensitive data, taint propagates to all callers
            if (summary.returns_sensitive_data) {
                auto paths = call_graph.trace_to_entry_points(f.function_name);
                for (const auto& path : paths) {
                    if (path.nodes.size() > 1) {
                        f.data_origin_points.push_back(
                            "taint propagated through return value to " +
                            path.nodes.back()->function_name +
                            " (depth=" + std::to_string(path.depth) + ")");
                        propagation_count++;
                    }
                }
            }

            // If function writes sensitive data to a global
            if (summary.writes_sensitive_to_global) {
                for (const auto& global_var : summary.global_variables_modified) {
                    f.data_origin_points.push_back(
                        "sensitive data written to global: " + global_var +
                        " by function: " + f.function_name);
                    propagation_count++;

                    // Find all functions that read this global
                    for (const auto& [func_name, other_summary] : function_summaries_) {
                        if (other_summary.global_variables_read.count(global_var)) {
                            f.data_origin_points.push_back(
                                "global taint '" + global_var + "' read by: " + func_name);
                            cross_function_taints++;
                        }
                    }
                }
            }

            // Transitive: if function calls sensitive callees
            if (summary.calls_sensitive_function) {
                for (const auto& callee : summary.sensitive_callees) {
                    f.data_origin_points.push_back(
                        "calls sensitive function: " + callee);
                }
            }
        }

        Logger::instance().info("InterProceduralDataFlow: " +
            std::to_string(propagation_count) + " taint propagations, " +
            std::to_string(cross_function_taints) + " cross-function taints");
    }

    // Detect taint paths reaching public entry points without sanitisation
    std::vector<Finding> find_exposed_taint_paths(
            const std::vector<std::string>& public_entry_points,
            const CallGraphPathExplorer& call_graph) {
        std::vector<Finding> findings;

        for (const auto& [func_name, summary] : function_summaries_) {
            if (!summary.returns_sensitive_data && !summary.writes_sensitive_to_global)
                continue;

            for (const auto& entry : public_entry_points) {
                auto paths = call_graph.explore_from_source(entry,
                    std::set<std::string>{func_name});
                for (const auto& path : paths) {
                    if (!path.reached_sensitive_operation) continue;

                    Finding f;
                    f.finding_id = IDGenerator::instance().next();
                    f.function_name = func_name;
                    f.issue_type = IssueType::InformationDisclosure;
                    f.severity = Severity::Medium;
                    f.confidence = 0.55;
                    f.classification = Classification::Inconclusive;
                    f.detailed_description =
                        "Public entry point '" + entry +
                        "' can reach function '" + func_name +
                        "' which " +
                        (summary.returns_sensitive_data ? "returns sensitive data" : "") +
                        (summary.returns_sensitive_data && summary.writes_sensitive_to_global ? " and " : "") +
                        (summary.writes_sensitive_to_global ? "writes sensitive data to global state" : "");
                    f.is_sensitive_data_type_v31 = true;
                    f.code_path_trace.push_back(entry);
                    for (auto* n : path.nodes)
                        f.code_path_trace.push_back(n->function_name);
                    f.static_analysis_evidence.push_back(
                        "path depth: " + std::to_string(path.depth));
                    findings.push_back(f);
                }
            }
        }

        Logger::instance().info("InterProceduralDataFlow: found " +
            std::to_string(findings.size()) + " exposed taint paths");
        return findings;
    }

    const FunctionSummary* get_summary(const std::string& func) const {
        auto it = function_summaries_.find(func);
        return (it != function_summaries_.end()) ? &it->second : nullptr;
    }

    size_t summary_count() const { return function_summaries_.size(); }
};

// --- B.2: Global State Flow Analyzer ---

class GlobalStateAnalyzer {
public:
    struct GlobalVariable {
        std::string name;
        std::string type;
        bool is_sensitive;
        std::string mutex_protecting;
        std::set<std::string> functions_that_read;
        std::set<std::string> functions_that_write;
        bool has_atomic_access;
        SourceLocation declaration_location;
    };

private:
    std::vector<GlobalVariable> globals_;

    static const std::map<std::string, std::string>& known_global_mutexes() {
        static const std::map<std::string, std::string> mapping = {
            {"g_chainman", "cs_main"},
            {"mapBlockIndex", "cs_main"},
            {"pindexBestHeader", "cs_main"},
            {"g_best_block", "cs_main"},
            {"mempool", "cs_main"},
            {"g_txindex", "cs_main"},
            {"g_chainstate", "cs_main"},
            {"g_connman", "cs_vNodes"},
            {"vNodes", "cs_vNodes"},
            {"mapLocalHost", "cs_mapLocalHost"},
            {"pwalletMain", "cs_wallet"},
            {"fReindex", "cs_main"},
        };
        return mapping;
    }

public:
    // Discover global variables and their access patterns
    std::vector<GlobalVariable> analyze_global_variables(const TranslationUnit& tu) {
        Logger::instance().info("GlobalStateAnalyzer: analyzing globals in " + tu.file_path);
        globals_.clear();

        int brace_depth = 0;
        std::string current_function;

        for (size_t i = 0; i < tu.tokens.size(); i++) {
            const auto& tok = tu.tokens[i];
            if (tok.text == "{") brace_depth++;
            else if (tok.text == "}") {
                brace_depth--;
                if (brace_depth == 0) current_function.clear();
            }

            // At file scope (brace_depth == 0), detect variable declarations
            if (brace_depth == 0 && tok.type == TokenType::Identifier) {
                if (i + 1 < tu.tokens.size() &&
                    tu.tokens[i + 1].type == TokenType::Identifier &&
                    i + 2 < tu.tokens.size() &&
                    (tu.tokens[i + 2].text == ";" || tu.tokens[i + 2].text == "=" ||
                     tu.tokens[i + 2].text == "(" || tu.tokens[i + 2].text == "{")) {
                    // Skip type keywords, control flow, declarations
                    static const std::set<std::string> skip_keywords = {
                        "class", "struct", "namespace", "enum", "using", "typedef",
                        "template", "extern", "static", "return", "const", "volatile",
                        "virtual", "explicit", "friend", "inline", "constexpr",
                        "mutable", "register", "thread_local", "decltype", "auto"
                    };
                    if (skip_keywords.count(tok.text)) continue;

                    GlobalVariable gv;
                    gv.type = tok.text;
                    gv.name = tu.tokens[i + 1].text;
                    gv.declaration_location = tok.location;
                    gv.is_sensitive = WordBoundaryClassifier::classify(gv.name).is_sensitive;
                    gv.has_atomic_access = (gv.type.find("atomic") != std::string::npos ||
                                            gv.type.find("Atomic") != std::string::npos);
                    auto mutex_it = known_global_mutexes().find(gv.name);
                    gv.mutex_protecting = (mutex_it != known_global_mutexes().end()) ?
                        mutex_it->second : "";
                    globals_.push_back(gv);
                }
            }

            // Inside functions, track reads/writes to known globals
            if (brace_depth > 0 && tok.type == TokenType::Identifier) {
                for (auto& gv : globals_) {
                    if (tok.text == gv.name) {
                        if (!current_function.empty()) {
                            gv.functions_that_read.insert(current_function);
                            if (i + 1 < tu.tokens.size()) {
                                const auto& next = tu.tokens[i + 1].text;
                                if (next == "=" || next == "+=" || next == "-=" ||
                                    next == "." || next == "->" || next == "[")
                                    gv.functions_that_write.insert(current_function);
                            }
                        }
                    }
                }
            }

            // Track current function name at file scope transitions
            if (brace_depth == 0 && tok.type == TokenType::Identifier &&
                i + 1 < tu.tokens.size() && tu.tokens[i + 1].text == "(") {
                size_t j = i + 2;
                int pd = 1;
                while (j < tu.tokens.size() && pd > 0) {
                    if (tu.tokens[j].text == "(") pd++;
                    else if (tu.tokens[j].text == ")") pd--;
                    j++;
                }
                if (j < tu.tokens.size()) {
                    for (size_t k = j; k < tu.tokens.size() && k < j + 8; k++) {
                        if (tu.tokens[k].text == "{") { current_function = tok.text; break; }
                        if (tu.tokens[k].text == ";") break;
                    }
                }
            }
        }

        Logger::instance().info("GlobalStateAnalyzer: found " +
            std::to_string(globals_.size()) + " global variables");
        return globals_;
    }

    // Find globals accessed by multiple writers without mutex protection
    std::vector<std::pair<GlobalVariable, std::vector<std::string>>>
    find_unprotected_concurrent_access() {
        std::vector<std::pair<GlobalVariable, std::vector<std::string>>> results;
        for (const auto& gv : globals_) {
            if (gv.mutex_protecting.empty() && !gv.has_atomic_access &&
                gv.functions_that_write.size() > 0 &&
                (gv.functions_that_read.size() + gv.functions_that_write.size()) > 1) {
                std::vector<std::string> accessors;
                for (const auto& f : gv.functions_that_read) accessors.push_back("read:" + f);
                for (const auto& f : gv.functions_that_write) accessors.push_back("write:" + f);
                results.push_back({gv, accessors});
            }
        }
        return results;
    }

    // Find sensitive data stored in global scope
    std::vector<GlobalVariable> find_sensitive_globals() {
        std::vector<GlobalVariable> results;
        for (const auto& gv : globals_)
            if (gv.is_sensitive) results.push_back(gv);
        return results;
    }

    // Generate findings for unprotected global access
    std::vector<Finding> generate_global_access_findings() {
        std::vector<Finding> findings;
        auto unprotected = find_unprotected_concurrent_access();
        for (const auto& [gv, accessors] : unprotected) {
            Finding f;
            f.finding_id = IDGenerator::instance().next();
            f.function_name = gv.name;
            f.file = gv.declaration_location.file_path;
            f.location = gv.declaration_location;
            f.issue_type = IssueType::RaceCondition;
            f.severity = gv.is_sensitive ? Severity::High : Severity::Medium;
            f.confidence = 0.60;
            f.classification = Classification::Inconclusive;
            f.detailed_description = "Global variable '" + gv.name +
                "' (type: " + gv.type + ") accessed by " +
                std::to_string(accessors.size()) + " functions without mutex protection";
            for (const auto& accessor : accessors)
                f.static_analysis_evidence.push_back(accessor);
            findings.push_back(f);
        }
        return findings;
    }
};


// ============================================================================
// SECTION 58: LIVE CHAIN STATE MONITORING & INSTRUMENTATION
// Phase 2 - Section C: Real-Time State Observer & Dynamic Instrumentation
// ============================================================================

// --- C.1: Chain State Monitor ---

class ChainStateMonitor {
public:
    struct BlockEvent {
        std::string block_hash;
        int height;
        int64_t time;
        std::vector<std::string> transaction_ids;
        int64_t coinbase_value;
        int64_t total_fees;
        int num_transactions;
        int block_weight;
        int block_size;
        std::string miner_tag;
    };

    struct TransactionEvent {
        std::string txid;
        bool accepted_to_mempool;
        bool included_in_block;
        std::string rejection_reason;
        int64_t fee;
        size_t vsize;
        size_t weight;
        int num_inputs;
        int num_outputs;
        bool is_segwit;
        bool is_rbf_signaling;
    };

    struct ChainSnapshot {
        int height;
        std::string best_block_hash;
        int64_t total_supply_satoshis;
        int mempool_size;
        int64_t mempool_bytes;
        std::vector<std::string> mempool_txids;
        int64_t median_time_past;
        int64_t snapshot_timestamp;
    };

    struct SnapshotDiff {
        int height_change;
        int64_t supply_change;
        int mempool_size_change;
        int64_t mempool_bytes_change;
        std::vector<std::string> new_blocks;
        std::vector<std::string> added_to_mempool;
        std::vector<std::string> removed_from_mempool;
        bool chain_reorg_detected;
        int reorg_depth;
    };

private:
    std::deque<BlockEvent> recent_blocks_;
    std::deque<TransactionEvent> recent_transactions_;
    std::function<void(const BlockEvent&)> block_callback_;
    std::function<void(const TransactionEvent&)> tx_callback_;
    mutable std::mutex mutex_;
    static constexpr size_t MAX_BLOCK_HISTORY = 2016;
    static constexpr size_t MAX_TX_HISTORY = 10000;
    bool monitoring_active_;

    static constexpr int64_t SUBSIDY_HALVING_INTERVAL = 210000;
    static constexpr int64_t INITIAL_SUBSIDY = 5000000000LL;
    static constexpr int64_t MAX_MONEY = 2100000000000000LL;
    static constexpr int MAX_BLOCK_WEIGHT = 4000000;

public:
    ChainStateMonitor() : monitoring_active_(false) {}

    void start_monitoring() { monitoring_active_ = true; }
    void stop_monitoring() { monitoring_active_ = false; }
    bool is_monitoring() const { return monitoring_active_; }

    void on_new_block(std::function<void(const BlockEvent&)> callback) {
        block_callback_ = std::move(callback);
    }

    void on_transaction_result(std::function<void(const TransactionEvent&)> callback) {
        tx_callback_ = std::move(callback);
    }

    void record_block(const BlockEvent& block) {
        std::lock_guard<std::mutex> lock(mutex_);
        recent_blocks_.push_back(block);
        while (recent_blocks_.size() > MAX_BLOCK_HISTORY) recent_blocks_.pop_front();
        if (block_callback_) block_callback_(block);
    }

    void record_transaction(const TransactionEvent& tx) {
        std::lock_guard<std::mutex> lock(mutex_);
        recent_transactions_.push_back(tx);
        while (recent_transactions_.size() > MAX_TX_HISTORY) recent_transactions_.pop_front();
        if (tx_callback_) tx_callback_(tx);
    }

    // Compute block subsidy at a given height
    int64_t get_current_subsidy(int height) const {
        int halvings = height / static_cast<int>(SUBSIDY_HALVING_INTERVAL);
        if (halvings >= 64) return 0;
        return INITIAL_SUBSIDY >> halvings;
    }

    // Compute cumulative supply up to a given height
    int64_t compute_total_supply(int height) const {
        int64_t total = 0;
        int64_t subsidy = INITIAL_SUBSIDY;
        int remaining = height;
        while (remaining > 0 && subsidy > 0) {
            int blocks_at_level = std::min(remaining,
                static_cast<int>(SUBSIDY_HALVING_INTERVAL));
            total += subsidy * blocks_at_level;
            remaining -= blocks_at_level;
            subsidy >>= 1;
        }
        if (total > MAX_MONEY) total = MAX_MONEY;
        return total;
    }

    ChainSnapshot take_snapshot() const {
        std::lock_guard<std::mutex> lock(mutex_);
        ChainSnapshot snap;
        if (!recent_blocks_.empty()) {
            const auto& last = recent_blocks_.back();
            snap.height = last.height;
            snap.best_block_hash = last.block_hash;
            snap.total_supply_satoshis = compute_total_supply(last.height);
        } else {
            snap.height = 0;
            snap.best_block_hash = "";
            snap.total_supply_satoshis = 0;
        }
        snap.mempool_size = 0;
        snap.mempool_bytes = 0;
        for (const auto& tx : recent_transactions_) {
            if (tx.accepted_to_mempool && !tx.included_in_block) {
                snap.mempool_txids.push_back(tx.txid);
                snap.mempool_size++;
                snap.mempool_bytes += static_cast<int64_t>(tx.vsize);
            }
        }
        snap.snapshot_timestamp = std::chrono::duration_cast<std::chrono::seconds>(
            std::chrono::system_clock::now().time_since_epoch()).count();
        snap.median_time_past = 0;
        if (recent_blocks_.size() >= 11) {
            std::vector<int64_t> times;
            auto it = recent_blocks_.end();
            for (int k = 0; k < 11 && it != recent_blocks_.begin(); k++) {
                --it;
                times.push_back(it->time);
            }
            std::sort(times.begin(), times.end());
            snap.median_time_past = times[times.size() / 2];
        }
        return snap;
    }

    SnapshotDiff compare_snapshots(const ChainSnapshot& before,
                                    const ChainSnapshot& after) const {
        SnapshotDiff diff;
        diff.height_change = after.height - before.height;
        diff.supply_change = after.total_supply_satoshis - before.total_supply_satoshis;
        diff.mempool_size_change = after.mempool_size - before.mempool_size;
        diff.mempool_bytes_change = after.mempool_bytes - before.mempool_bytes;
        diff.chain_reorg_detected = (diff.height_change < 0 ||
            (after.best_block_hash != before.best_block_hash && diff.height_change == 0));
        diff.reorg_depth = diff.chain_reorg_detected ? std::abs(diff.height_change) : 0;

        std::set<std::string> before_mp(before.mempool_txids.begin(), before.mempool_txids.end());
        std::set<std::string> after_mp(after.mempool_txids.begin(), after.mempool_txids.end());
        for (const auto& txid : after_mp)
            if (!before_mp.count(txid)) diff.added_to_mempool.push_back(txid);
        for (const auto& txid : before_mp)
            if (!after_mp.count(txid)) diff.removed_from_mempool.push_back(txid);

        return diff;
    }

    // Verify block consistency against consensus rules
    std::vector<std::string> verify_block_consistency(const BlockEvent& block) const {
        std::vector<std::string> violations;

        int64_t expected_subsidy = get_current_subsidy(block.height);
        if (block.coinbase_value > expected_subsidy + block.total_fees) {
            violations.push_back("CRITICAL: Coinbase value (" +
                std::to_string(block.coinbase_value) + " sat) exceeds subsidy (" +
                std::to_string(expected_subsidy) + ") + fees (" +
                std::to_string(block.total_fees) + ") at height " +
                std::to_string(block.height));
        }

        if (block.block_weight > MAX_BLOCK_WEIGHT) {
            violations.push_back("CRITICAL: Block weight (" +
                std::to_string(block.block_weight) + ") exceeds MAX_BLOCK_WEIGHT (" +
                std::to_string(MAX_BLOCK_WEIGHT) + ") at height " +
                std::to_string(block.height));
        }

        if (block.num_transactions == 0) {
            violations.push_back("ERROR: Empty block (no transactions including coinbase) at height " +
                std::to_string(block.height));
        }

        if (block.coinbase_value < 0) {
            violations.push_back("CRITICAL: Negative coinbase value at height " +
                std::to_string(block.height));
        }

        // Check supply invariant
        int64_t supply_at_height = compute_total_supply(block.height);
        if (supply_at_height > MAX_MONEY) {
            violations.push_back("CRITICAL: Total supply exceeds MAX_MONEY at height " +
                std::to_string(block.height));
        }

        return violations;
    }

    size_t block_history_size() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return recent_blocks_.size();
    }

    size_t tx_history_size() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return recent_transactions_.size();
    }

    // Get block at specific height from history
    const BlockEvent* get_block_at_height(int height) const {
        std::lock_guard<std::mutex> lock(mutex_);
        for (const auto& b : recent_blocks_)
            if (b.height == height) return &b;
        return nullptr;
    }
};

// --- C.2: Runtime Instrumentation Hook System ---

class InstrumentationHooks {
public:
    struct HookPoint {
        std::string location;
        std::string condition;
        std::string description;
        bool is_active;
        std::atomic<int> hit_count;
        std::chrono::steady_clock::time_point last_hit;

        HookPoint() : is_active(false), hit_count(0) {}
        HookPoint(const HookPoint& o)
            : location(o.location), condition(o.condition),
              description(o.description), is_active(o.is_active),
              hit_count(o.hit_count.load()), last_hit(o.last_hit) {}
    };

    struct LockEvent {
        std::string lock_name;
        std::string function_name;
        int thread_id;
        std::chrono::steady_clock::time_point timestamp;
        bool is_acquisition;
    };

    struct MemoryEvent {
        std::string variable_name;
        size_t size;
        bool is_allocation;
        bool cleanup_performed;
        std::chrono::steady_clock::time_point timestamp;
    };

    struct ValueCheckEvent {
        std::string description;
        int64_t value;
        int64_t expected_min;
        int64_t expected_max;
        bool passed;
    };

    struct ConsensusCheckEvent {
        std::string rule_name;
        bool passed;
        std::string detail;
        int block_height;
    };

    struct InstrumentationReport {
        std::vector<std::string> lock_order_violations;
        std::vector<std::string> missing_cleanup_calls;
        std::vector<std::string> value_range_violations;
        std::vector<std::string> consensus_check_failures;
        int total_hook_hits;
        int total_violations;
        int total_lock_events;
        int total_memory_events;
        int total_value_checks;
        int total_consensus_checks;
        std::chrono::seconds monitoring_duration;
    };

private:
    std::vector<HookPoint> hooks_;
    std::vector<LockEvent> lock_events_;
    std::vector<MemoryEvent> memory_events_;
    std::vector<ValueCheckEvent> value_checks_;
    std::vector<ConsensusCheckEvent> consensus_checks_;
    mutable std::mutex mutex_;
    std::chrono::steady_clock::time_point start_time_;

    // Per-thread lock stacks for order violation detection
    std::map<int, std::vector<std::string>> thread_lock_stacks_;
    std::set<std::pair<std::string, std::string>> observed_lock_order_;
    std::vector<std::string> lock_order_violations_;

public:
    InstrumentationHooks() : start_time_(std::chrono::steady_clock::now()) {}

    // --- Lock instrumentation ---

    void instrument_lock_acquisition(const std::string& lock_name,
                                      const std::string& function_name,
                                      int thread_id) {
        std::lock_guard<std::mutex> lock(mutex_);
        LockEvent ev;
        ev.lock_name = lock_name;
        ev.function_name = function_name;
        ev.thread_id = thread_id;
        ev.timestamp = std::chrono::steady_clock::now();
        ev.is_acquisition = true;
        lock_events_.push_back(ev);

        // Lock order violation detection
        auto& stack = thread_lock_stacks_[thread_id];
        for (const auto& held : stack) {
            auto order_pair = std::make_pair(held, lock_name);
            auto reverse_pair = std::make_pair(lock_name, held);
            if (observed_lock_order_.count(reverse_pair)) {
                std::string violation = "Lock order violation: thread " +
                    std::to_string(thread_id) + " acquired '" + lock_name +
                    "' while holding '" + held + "' in " + function_name +
                    ", but reverse order seen elsewhere";
                lock_order_violations_.push_back(violation);
            }
            observed_lock_order_.insert(order_pair);
        }
        stack.push_back(lock_name);
    }

    void instrument_lock_release(const std::string& lock_name, int thread_id) {
        std::lock_guard<std::mutex> lock(mutex_);
        LockEvent ev;
        ev.lock_name = lock_name;
        ev.thread_id = thread_id;
        ev.timestamp = std::chrono::steady_clock::now();
        ev.is_acquisition = false;
        lock_events_.push_back(ev);

        auto& stack = thread_lock_stacks_[thread_id];
        auto it = std::find(stack.begin(), stack.end(), lock_name);
        if (it != stack.end()) stack.erase(it);
    }

    // --- Memory instrumentation ---

    void instrument_memory_allocation(const std::string& variable_name, size_t size) {
        std::lock_guard<std::mutex> lock(mutex_);
        MemoryEvent ev;
        ev.variable_name = variable_name;
        ev.size = size;
        ev.is_allocation = true;
        ev.cleanup_performed = false;
        ev.timestamp = std::chrono::steady_clock::now();
        memory_events_.push_back(ev);
    }

    void instrument_memory_cleanup(const std::string& variable_name) {
        std::lock_guard<std::mutex> lock(mutex_);
        // Match against most recent unmatched allocation
        for (auto it = memory_events_.rbegin(); it != memory_events_.rend(); ++it) {
            if (it->variable_name == variable_name && it->is_allocation && !it->cleanup_performed) {
                it->cleanup_performed = true;
                break;
            }
        }
        MemoryEvent ev;
        ev.variable_name = variable_name;
        ev.size = 0;
        ev.is_allocation = false;
        ev.cleanup_performed = true;
        ev.timestamp = std::chrono::steady_clock::now();
        memory_events_.push_back(ev);
    }

    // --- Value range instrumentation ---

    void instrument_value_check(const std::string& description, int64_t value,
                                 int64_t expected_min, int64_t expected_max) {
        std::lock_guard<std::mutex> lock(mutex_);
        ValueCheckEvent ev;
        ev.description = description;
        ev.value = value;
        ev.expected_min = expected_min;
        ev.expected_max = expected_max;
        ev.passed = (value >= expected_min && value <= expected_max);
        value_checks_.push_back(ev);
    }

    // --- Consensus check instrumentation ---

    void instrument_consensus_check(const std::string& rule_name, bool passed,
                                      const std::string& detail, int block_height) {
        std::lock_guard<std::mutex> lock(mutex_);
        ConsensusCheckEvent ev;
        ev.rule_name = rule_name;
        ev.passed = passed;
        ev.detail = detail;
        ev.block_height = block_height;
        consensus_checks_.push_back(ev);
    }

    // --- Report generation ---

    InstrumentationReport generate_report() const {
        std::lock_guard<std::mutex> lock(mutex_);
        InstrumentationReport report;
        report.monitoring_duration = std::chrono::duration_cast<std::chrono::seconds>(
            std::chrono::steady_clock::now() - start_time_);
        report.total_lock_events = static_cast<int>(lock_events_.size());
        report.total_memory_events = static_cast<int>(memory_events_.size());
        report.total_value_checks = static_cast<int>(value_checks_.size());
        report.total_consensus_checks = static_cast<int>(consensus_checks_.size());

        // Lock order violations
        report.lock_order_violations = lock_order_violations_;

        // Missing cleanup calls for sensitive allocations
        std::map<std::string, bool> alloc_cleanup;
        for (const auto& ev : memory_events_) {
            if (ev.is_allocation) {
                auto cls = WordBoundaryClassifier::classify(ev.variable_name);
                if (cls.is_sensitive) alloc_cleanup[ev.variable_name] = false;
            } else if (ev.cleanup_performed) {
                alloc_cleanup[ev.variable_name] = true;
            }
        }
        for (const auto& [name, cleaned] : alloc_cleanup) {
            if (!cleaned)
                report.missing_cleanup_calls.push_back(
                    "Sensitive allocation '" + name + "' not securely cleaned");
        }

        // Value range violations
        for (const auto& vc : value_checks_) {
            if (!vc.passed)
                report.value_range_violations.push_back(
                    vc.description + ": value=" + std::to_string(vc.value) +
                    " outside expected range [" + std::to_string(vc.expected_min) +
                    ", " + std::to_string(vc.expected_max) + "]");
        }

        // Consensus check failures
        for (const auto& cc : consensus_checks_) {
            if (!cc.passed)
                report.consensus_check_failures.push_back(
                    cc.rule_name + " FAILED at height " + std::to_string(cc.block_height) +
                    ": " + cc.detail);
        }

        report.total_hook_hits = report.total_lock_events + report.total_memory_events +
            report.total_value_checks + report.total_consensus_checks;
        report.total_violations = static_cast<int>(
            report.lock_order_violations.size() + report.missing_cleanup_calls.size() +
            report.value_range_violations.size() + report.consensus_check_failures.size());

        return report;
    }

    void reset() {
        std::lock_guard<std::mutex> lock(mutex_);
        lock_events_.clear();
        memory_events_.clear();
        value_checks_.clear();
        consensus_checks_.clear();
        thread_lock_stacks_.clear();
        observed_lock_order_.clear();
        lock_order_violations_.clear();
        start_time_ = std::chrono::steady_clock::now();
    }
};


// ============================================================================
// SECTION 59: CONCURRENT EXECUTION & RESOURCE SCHEDULING
// Phase 2 - Section D: Parallel Test Scheduler & Resource-Aware Allocator
// ============================================================================

// --- D.1: Concurrent Test Execution Scheduler ---

class ConcurrentTestScheduler {
public:
    enum class TestJobStatus {
        Pending, Queued, Running, Completed, Failed, TimedOut, Cancelled
    };

    struct TestJob {
        std::string test_name;
        std::string test_command;
        int required_memory_mb;
        int estimated_duration_seconds;
        std::vector<std::string> dependencies;
        TestJobStatus status;
        int exit_code;
        std::string stdout_output;
        std::string stderr_output;
        std::chrono::steady_clock::time_point start_time;
        std::chrono::steady_clock::time_point end_time;
        int actual_duration_seconds;
        int retry_count;
    };

    struct SchedulerStats {
        int total_jobs;
        int completed_jobs;
        int failed_jobs;
        int timed_out_jobs;
        int active_jobs;
        int pending_jobs;
        int64_t total_wall_seconds;
        int64_t total_cpu_seconds;
        int peak_memory_used_mb;
    };

private:
    std::vector<TestJob> job_queue_;
    std::map<std::string, TestJob> completed_jobs_;
    int max_parallel_jobs_;
    int max_total_memory_mb_;
    int current_memory_used_mb_;
    int peak_memory_used_mb_;
    mutable std::mutex mutex_;
    std::condition_variable cv_;
    std::atomic<bool> shutdown_requested_;
    std::atomic<int> active_jobs_;
    std::vector<std::thread> worker_threads_;
    std::chrono::steady_clock::time_point scheduler_start_;

public:
    ConcurrentTestScheduler()
        : max_parallel_jobs_(4), max_total_memory_mb_(4096),
          current_memory_used_mb_(0), peak_memory_used_mb_(0),
          shutdown_requested_(false), active_jobs_(0) {}

    ~ConcurrentTestScheduler() {
        shutdown_requested_ = true;
        cv_.notify_all();
        for (auto& t : worker_threads_)
            if (t.joinable()) t.join();
    }

    void configure_from_system_resources(double max_cpu_fraction = 0.75,
                                          double max_memory_fraction = 0.50) {
        unsigned int cores = std::thread::hardware_concurrency();
        if (cores == 0) cores = 4;
        max_parallel_jobs_ = std::max(1, static_cast<int>(cores * max_cpu_fraction));

        int64_t system_memory_mb = 8192;
        #ifdef __linux__
        std::ifstream meminfo("/proc/meminfo");
        std::string line;
        while (std::getline(meminfo, line)) {
            if (line.find("MemTotal:") == 0) {
                std::istringstream iss(line);
                std::string label;
                int64_t kb;
                iss >> label >> kb;
                system_memory_mb = kb / 1024;
                break;
            }
        }
        #endif
        max_total_memory_mb_ = static_cast<int>(system_memory_mb * max_memory_fraction);

        Logger::instance().info("ConcurrentTestScheduler: " +
            std::to_string(max_parallel_jobs_) + " workers, " +
            std::to_string(max_total_memory_mb_) + "MB budget (" +
            std::to_string(system_memory_mb) + "MB system)");
    }

    void submit_job(const TestJob& job) {
        std::lock_guard<std::mutex> lock(mutex_);
        TestJob j = job;
        j.status = TestJobStatus::Pending;
        j.exit_code = -1;
        j.actual_duration_seconds = 0;
        j.retry_count = 0;
        job_queue_.push_back(j);
    }

    void submit_jobs(const std::vector<TestJob>& jobs) {
        for (const auto& j : jobs) submit_job(j);
    }

    void execute_all(std::function<void(const TestJob&)> on_complete = nullptr) {
        Logger::instance().info("ConcurrentTestScheduler: executing " +
            std::to_string(job_queue_.size()) + " jobs");

        scheduler_start_ = std::chrono::steady_clock::now();
        shutdown_requested_ = false;

        while (!all_complete() && !shutdown_requested_) {
            std::vector<TestJob*> ready = get_ready_jobs();

            for (auto* job : ready) {
                if (active_jobs_ >= max_parallel_jobs_) break;
                if (current_memory_used_mb_ + job->required_memory_mb > max_total_memory_mb_)
                    continue;

                job->status = TestJobStatus::Running;
                job->start_time = std::chrono::steady_clock::now();
                {
                    std::lock_guard<std::mutex> lock(mutex_);
                    current_memory_used_mb_ += job->required_memory_mb;
                    if (current_memory_used_mb_ > peak_memory_used_mb_)
                        peak_memory_used_mb_ = current_memory_used_mb_;
                }
                active_jobs_++;

                std::string cmd = job->test_command;
                std::string name = job->test_name;
                int mem = job->required_memory_mb;
                int timeout = std::max(10, job->estimated_duration_seconds * 3);

                worker_threads_.emplace_back([this, cmd, name, mem, timeout, on_complete]() {
                    TestJob result;
                    result.test_name = name;
                    result.start_time = std::chrono::steady_clock::now();

                    std::string full_cmd = "timeout " + std::to_string(timeout) +
                        " bash -c '" + cmd + "' 2>&1";
                    FILE* pipe = popen(full_cmd.c_str(), "r");
                    if (pipe) {
                        char buffer[4096];
                        while (fgets(buffer, sizeof(buffer), pipe))
                            result.stdout_output += buffer;
                        int raw_status = pclose(pipe);
                        result.exit_code = WEXITSTATUS(raw_status);
                        if (result.exit_code == 124)
                            result.status = TestJobStatus::TimedOut;
                        else if (result.exit_code == 0)
                            result.status = TestJobStatus::Completed;
                        else
                            result.status = TestJobStatus::Failed;
                    } else {
                        result.status = TestJobStatus::Failed;
                        result.exit_code = -1;
                    }

                    result.end_time = std::chrono::steady_clock::now();
                    result.actual_duration_seconds = static_cast<int>(
                        std::chrono::duration_cast<std::chrono::seconds>(
                            result.end_time - result.start_time).count());

                    {
                        std::lock_guard<std::mutex> lk(mutex_);
                        completed_jobs_[name] = result;
                        current_memory_used_mb_ -= mem;
                        active_jobs_--;
                        for (auto& j : job_queue_) {
                            if (j.test_name == name) {
                                j.status = result.status;
                                j.exit_code = result.exit_code;
                                j.stdout_output = result.stdout_output;
                                j.actual_duration_seconds = result.actual_duration_seconds;
                                break;
                            }
                        }
                    }
                    if (on_complete) on_complete(result);
                    cv_.notify_all();
                });
            }

            if (active_jobs_ >= max_parallel_jobs_ || ready.empty()) {
                std::unique_lock<std::mutex> lock(mutex_);
                cv_.wait_for(lock, std::chrono::seconds(1));
            }
        }

        for (auto& t : worker_threads_)
            if (t.joinable()) t.join();
        worker_threads_.clear();

        auto wall = std::chrono::duration_cast<std::chrono::seconds>(
            std::chrono::steady_clock::now() - scheduler_start_).count();
        Logger::instance().info("ConcurrentTestScheduler: finished in " +
            std::to_string(wall) + "s");
    }

    SchedulerStats get_stats() const {
        std::lock_guard<std::mutex> lock(mutex_);
        SchedulerStats stats;
        stats.total_jobs = static_cast<int>(job_queue_.size());
        stats.completed_jobs = 0;
        stats.failed_jobs = 0;
        stats.timed_out_jobs = 0;
        stats.pending_jobs = 0;
        stats.active_jobs = active_jobs_;
        stats.total_cpu_seconds = 0;
        for (const auto& j : job_queue_) {
            switch (j.status) {
                case TestJobStatus::Completed: stats.completed_jobs++; break;
                case TestJobStatus::Failed: stats.failed_jobs++; break;
                case TestJobStatus::TimedOut: stats.timed_out_jobs++; break;
                case TestJobStatus::Pending: stats.pending_jobs++; break;
                default: break;
            }
            stats.total_cpu_seconds += j.actual_duration_seconds;
        }
        stats.total_wall_seconds = std::chrono::duration_cast<std::chrono::seconds>(
            std::chrono::steady_clock::now() - scheduler_start_).count();
        stats.peak_memory_used_mb = peak_memory_used_mb_;
        return stats;
    }

    void shutdown_with_state_save(const std::string& state_file) {
        shutdown_requested_ = true;
        cv_.notify_all();

        std::ofstream out(state_file);
        if (!out.is_open()) return;
        std::lock_guard<std::mutex> lock(mutex_);
        out << "# ConcurrentTestScheduler saved state\n";
        out << "# format: name|status|exit_code|duration\n";
        for (const auto& j : job_queue_) {
            out << j.test_name << "|" << static_cast<int>(j.status) << "|"
                << j.exit_code << "|" << j.actual_duration_seconds << "\n";
        }
        Logger::instance().info("ConcurrentTestScheduler: state saved to " + state_file);
    }

    void resume_from_state(const std::string& state_file) {
        std::ifstream in(state_file);
        if (!in.is_open()) return;
        std::string line;
        int resumed = 0;
        while (std::getline(in, line)) {
            if (line.empty() || line[0] == '#') continue;
            size_t d1 = line.find('|');
            if (d1 == std::string::npos) continue;
            std::string name = line.substr(0, d1);
            size_t d2 = line.find('|', d1 + 1);
            if (d2 == std::string::npos) continue;
            int status = std::stoi(line.substr(d1 + 1, d2 - d1 - 1));
            if (status == static_cast<int>(TestJobStatus::Completed)) {
                for (auto& j : job_queue_) {
                    if (j.test_name == name) {
                        j.status = TestJobStatus::Completed;
                        resumed++;
                        break;
                    }
                }
            }
        }
        Logger::instance().info("ConcurrentTestScheduler: resumed " +
            std::to_string(resumed) + " completed jobs from state");
    }

private:
    std::vector<TestJob*> get_ready_jobs() {
        std::lock_guard<std::mutex> lock(mutex_);
        std::vector<TestJob*> ready;
        for (auto& j : job_queue_) {
            if (j.status != TestJobStatus::Pending) continue;
            bool deps_met = true;
            for (const auto& dep : j.dependencies) {
                auto it = completed_jobs_.find(dep);
                if (it == completed_jobs_.end() ||
                    it->second.status != TestJobStatus::Completed) {
                    deps_met = false;
                    break;
                }
            }
            if (deps_met) ready.push_back(&j);
        }
        return ready;
    }

    bool all_complete() const {
        std::lock_guard<std::mutex> lock(mutex_);
        for (const auto& j : job_queue_)
            if (j.status == TestJobStatus::Pending || j.status == TestJobStatus::Running)
                return false;
        return true;
    }
};

// --- D.2: Resource-Aware Memory Allocator ---

class ResourceAwareAllocator {
public:
    struct MemoryRegion {
        void* start;
        size_t size;
        bool is_guarded;
        bool is_mlocked;
        bool is_sensitive;
        std::string allocation_tag;
        std::chrono::steady_clock::time_point allocation_time;
    };

private:
    std::vector<MemoryRegion> active_regions_;
    size_t total_allocated_;
    size_t max_allowed_;
    size_t peak_allocated_;
    mutable std::mutex mutex_;

public:
    ResourceAwareAllocator()
        : total_allocated_(0), max_allowed_(0), peak_allocated_(0) {
        detect_system_memory();
    }

    void* allocate_sensitive(size_t size, const std::string& tag) {
        if (!request_memory_budget(size)) {
            Logger::instance().warning("ResourceAwareAllocator: budget exceeded for '" + tag + "'");
            return nullptr;
        }
        void* ptr = EnhancedMemoryManager::instance().secure_allocate(size, tag);
        if (ptr) {
            std::lock_guard<std::mutex> lock(mutex_);
            MemoryRegion region;
            region.start = ptr;
            region.size = size;
            region.is_guarded = true;
            region.is_mlocked = true;
            region.is_sensitive = true;
            region.allocation_tag = tag;
            region.allocation_time = std::chrono::steady_clock::now();
            active_regions_.push_back(region);
        }
        return ptr;
    }

    void* allocate_mlocked(size_t size, const std::string& tag) {
        if (!request_memory_budget(size)) return nullptr;
        void* ptr = std::malloc(size);
        if (!ptr) { release_memory_budget(size); return nullptr; }
        std::memset(ptr, 0, size);
        #ifdef __linux__
        mlock(ptr, size);
        #endif
        std::lock_guard<std::mutex> lock(mutex_);
        MemoryRegion region;
        region.start = ptr;
        region.size = size;
        region.is_guarded = false;
        region.is_mlocked = true;
        region.is_sensitive = false;
        region.allocation_tag = tag;
        region.allocation_time = std::chrono::steady_clock::now();
        active_regions_.push_back(region);
        return ptr;
    }

    void deallocate(void* ptr) {
        std::lock_guard<std::mutex> lock(mutex_);
        for (auto it = active_regions_.begin(); it != active_regions_.end(); ++it) {
            if (it->start == ptr) {
                if (it->is_sensitive)
                    EnhancedMemoryManager::instance().secure_deallocate(ptr);
                else {
                    if (it->is_mlocked) {
                        // Cleanse before free
                        volatile unsigned char* p = static_cast<volatile unsigned char*>(ptr);
                        for (size_t i = 0; i < it->size; i++) p[i] = 0;
                        #ifdef __linux__
                        munlock(ptr, it->size);
                        #endif
                    }
                    std::free(ptr);
                }
                release_memory_budget_locked(it->size);
                active_regions_.erase(it);
                return;
            }
        }
        Logger::instance().warning("ResourceAwareAllocator: unknown pointer in deallocate");
    }

    bool request_memory_budget(size_t requested) {
        std::lock_guard<std::mutex> lock(mutex_);
        if (max_allowed_ > 0 && total_allocated_ + requested > max_allowed_) return false;
        total_allocated_ += requested;
        if (total_allocated_ > peak_allocated_) peak_allocated_ = total_allocated_;
        return true;
    }

    void release_memory_budget(size_t released) {
        std::lock_guard<std::mutex> lock(mutex_);
        release_memory_budget_locked(released);
    }

    void check_memory_pressure() {
        #ifdef __linux__
        std::ifstream meminfo("/proc/meminfo");
        std::string line;
        int64_t available_kb = 0;
        while (std::getline(meminfo, line)) {
            if (line.find("MemAvailable:") == 0) {
                std::istringstream iss(line);
                std::string label;
                iss >> label >> available_kb;
                break;
            }
        }
        if (available_kb > 0 && available_kb < 512 * 1024)
            Logger::instance().warning("ResourceAwareAllocator: LOW MEMORY (" +
                std::to_string(available_kb / 1024) + "MB available)");
        #endif
    }

    std::string dump_allocation_map() const {
        std::lock_guard<std::mutex> lock(mutex_);
        std::ostringstream oss;
        oss << "ResourceAwareAllocator: " << active_regions_.size() << " regions\n";
        oss << "  Total: " << total_allocated_ << " bytes"
            << " (peak: " << peak_allocated_ << ", limit: " << max_allowed_ << ")\n";
        for (const auto& r : active_regions_) {
            oss << "  [" << r.allocation_tag << "] " << r.size << "B";
            if (r.is_sensitive) oss << " SENS";
            if (r.is_mlocked) oss << " MLOCK";
            if (r.is_guarded) oss << " GUARD";
            oss << "\n";
        }
        return oss.str();
    }

    size_t get_total_allocated() const { return total_allocated_; }
    size_t get_peak_allocated() const { return peak_allocated_; }
    size_t get_region_count() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return active_regions_.size();
    }

private:
    void release_memory_budget_locked(size_t released) {
        total_allocated_ = (released > total_allocated_) ? 0 : total_allocated_ - released;
    }

    void detect_system_memory() {
        int64_t system_bytes = 8LL * 1024 * 1024 * 1024;
        #ifdef __linux__
        std::ifstream meminfo("/proc/meminfo");
        std::string line;
        while (std::getline(meminfo, line)) {
            if (line.find("MemTotal:") == 0) {
                std::istringstream iss(line);
                std::string label;
                int64_t kb;
                iss >> label >> kb;
                system_bytes = kb * 1024;
                break;
            }
        }
        #endif
        max_allowed_ = static_cast<size_t>(system_bytes * 0.50);
        Logger::instance().info("ResourceAwareAllocator: budget=" +
            std::to_string(max_allowed_ / (1024 * 1024)) + "MB");
    }
};


