// SECTION 60: COVERAGE-GUIDED & FEEDBACK-DRIVEN TESTING
// Phase 2 - Section E: Coverage Feedback Loop & Protocol State Machine
// ============================================================================

// --- E.1: Coverage-Guided Test Evolution ---

class CoverageGuidedTestMutator {
public:
    struct CodeCoverage {
        std::string file_path;
        std::set<int> covered_lines;
        std::set<std::string> covered_branches;
        std::set<std::string> uncovered_branches;
        double coverage_percentage;
        int total_lines;
        int total_branches;
    };

    struct TestCase {
        std::string test_name;
        std::string test_script;
        CodeCoverage coverage_achieved;
        std::set<std::string> new_branches_covered;
        double fitness_score;
        int generation;
        std::string parent_test;
    };

private:
    std::vector<TestCase> test_corpus_;
    CodeCoverage cumulative_coverage_;
    int current_generation_;
    mutable std::mutex mutex_;

    enum MutationStrategy {
        ARGUMENT_FUZZ, VALUE_BOUNDARY, SEQUENCE_REORDER, CONDITION_NEGATE,
        TIMING_VARIATION, INPUT_EXPANSION, EMPTY_INPUT, MAX_INPUT_MUTATION
    };

public:
    CoverageGuidedTestMutator() : current_generation_(0) {
        cumulative_coverage_.coverage_percentage = 0.0;
        cumulative_coverage_.total_lines = 0;
        cumulative_coverage_.total_branches = 0;
    }

    // Measure coverage by running test under gcov instrumentation
    CodeCoverage measure_coverage(const std::string& test_script,
                                   const std::string& source_dir) {
        CodeCoverage coverage;
        coverage.coverage_percentage = 0.0;
        coverage.total_lines = 0;
        coverage.total_branches = 0;

        // Build with coverage instrumentation, run test, collect gcov data
        std::string gcov_cmd = "cd " + source_dir + " && "
            "make clean > /dev/null 2>&1 && "
            "CXXFLAGS='--coverage -fprofile-arcs -ftest-coverage' "
            "make -j$(nproc) > /dev/null 2>&1 && "
            "bash -c '" + test_script + "' > /dev/null 2>&1 && "
            "gcov -b src/*.cpp 2>/dev/null";

        FILE* pipe = popen(gcov_cmd.c_str(), "r");
        if (!pipe) return coverage;

        char buffer[4096];
        std::string output;
        while (fgets(buffer, sizeof(buffer), pipe)) output += buffer;
        pclose(pipe);

        // Parse gcov output
        std::istringstream iss(output);
        std::string line;
        while (std::getline(iss, line)) {
            if (line.find("File '") != std::string::npos) {
                size_t s = line.find("'") + 1;
                size_t e = line.find("'", s);
                coverage.file_path = line.substr(s, e - s);
            }
            if (line.find("Lines executed:") != std::string::npos) {
                size_t ps = line.find(':') + 1;
                size_t pe = line.find('%');
                if (ps != std::string::npos && pe != std::string::npos) {
                    try { coverage.coverage_percentage = std::stod(line.substr(ps, pe - ps)); }
                    catch (...) {}
                }
                size_t of_pos = line.find("of ");
                if (of_pos != std::string::npos) {
                    try { coverage.total_lines = std::stoi(line.substr(of_pos + 3)); }
                    catch (...) {}
                }
            }
            if (line.find("Branches executed:") != std::string::npos) {
                size_t of_pos = line.find("of ");
                if (of_pos != std::string::npos) {
                    try { coverage.total_branches = std::stoi(line.substr(of_pos + 3)); }
                    catch (...) {}
                }
            }
            // Track branch IDs
            if (line.find("branch") != std::string::npos && line.find("taken") != std::string::npos) {
                std::string branch_id = coverage.file_path + ":" + line.substr(0, line.find(':'));
                if (line.find("taken 0") != std::string::npos)
                    coverage.uncovered_branches.insert(branch_id);
                else
                    coverage.covered_branches.insert(branch_id);
            }
        }
        return coverage;
    }

    // Apply mutation strategies to generate new test variants
    std::vector<std::string> generate_mutations(
            const TestCase& base_test,
            const std::set<std::string>& target_branches,
            int num_mutations) {
        std::vector<std::string> mutations;
        for (int i = 0; i < num_mutations; i++) {
            MutationStrategy strategy = static_cast<MutationStrategy>(i % 8);
            mutations.push_back(apply_mutation(base_test.test_script, strategy, i));
        }
        return mutations;
    }

    // Select the highest-fitness tests
    std::vector<TestCase> select_best_tests(int top_n) const {
        std::lock_guard<std::mutex> lock(mutex_);
        std::vector<TestCase> sorted = test_corpus_;
        std::sort(sorted.begin(), sorted.end(),
            [](const TestCase& a, const TestCase& b) {
                return a.fitness_score > b.fitness_score;
            });
        if (static_cast<int>(sorted.size()) > top_n) sorted.resize(top_n);
        return sorted;
    }

    // Multi-generation evolutionary loop
    void evolve_test_suite(int generations, int tests_per_generation,
                            const std::string& source_dir) {
        Logger::instance().info("CoverageGuidedTestMutator: evolving over " +
            std::to_string(generations) + " generations");

        if (test_corpus_.empty()) seed_initial_corpus();

        for (int gen = 0; gen < generations; gen++) {
            current_generation_ = gen;

            auto parents = select_best_tests(
                std::max(1, static_cast<int>(test_corpus_.size()) / 2));

            int added = 0;
            for (const auto& parent : parents) {
                int mutations_per_parent = tests_per_generation /
                    std::max(1, static_cast<int>(parents.size()));
                auto mutations = generate_mutations(parent,
                    cumulative_coverage_.uncovered_branches, mutations_per_parent);

                for (const auto& mutant_script : mutations) {
                    TestCase child;
                    child.test_name = "gen" + std::to_string(gen) + "_m" +
                        std::to_string(added);
                    child.test_script = mutant_script;
                    child.generation = gen;
                    child.parent_test = parent.test_name;
                    child.coverage_achieved = measure_coverage(mutant_script, source_dir);

                    // Calculate fitness: reward new branch coverage
                    for (const auto& branch : child.coverage_achieved.covered_branches) {
                        if (!cumulative_coverage_.covered_branches.count(branch))
                            child.new_branches_covered.insert(branch);
                    }
                    child.fitness_score = child.new_branches_covered.size() * 10.0 +
                        child.coverage_achieved.coverage_percentage;

                    if (child.fitness_score > 0) {
                        std::lock_guard<std::mutex> lock(mutex_);
                        test_corpus_.push_back(child);
                        for (const auto& b : child.new_branches_covered)
                            cumulative_coverage_.covered_branches.insert(b);
                        added++;
                    }

                    if (added >= tests_per_generation) break;
                }
                if (added >= tests_per_generation) break;
            }

            Logger::instance().info("  Gen " + std::to_string(gen + 1) + ": +" +
                std::to_string(added) + " tests, corpus=" +
                std::to_string(test_corpus_.size()) + ", branches=" +
                std::to_string(cumulative_coverage_.covered_branches.size()));
        }
    }

    void seed_initial_corpus() {
        std::vector<std::pair<std::string, std::string>> seeds = {
            {"seed_blockcount", "bitcoin-cli -regtest getblockcount"},
            {"seed_mempool", "bitcoin-cli -regtest getmempoolinfo"},
            {"seed_mining", "bitcoin-cli -regtest getmininginfo"},
            {"seed_validate", "bitcoin-cli -regtest validateaddress bcrt1qw508d6qejxtdg4y5r3zarvary0c5xw7kygt080"},
            {"seed_peers", "bitcoin-cli -regtest getpeerinfo"},
            {"seed_network", "bitcoin-cli -regtest getnetworkinfo"},
            {"seed_generate", "bitcoin-cli -regtest -generate 1"},
            {"seed_listunspent", "bitcoin-cli -regtest listunspent"},
        };
        for (const auto& [name, cmd] : seeds) {
            TestCase tc;
            tc.test_name = name;
            tc.test_script = cmd;
            tc.generation = 0;
            tc.fitness_score = 1.0;
            test_corpus_.push_back(tc);
        }
    }

    size_t corpus_size() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return test_corpus_.size();
    }

    double cumulative_coverage_pct() const {
        return cumulative_coverage_.coverage_percentage;
    }

private:
    std::string apply_mutation(const std::string& script,
                                MutationStrategy strategy, int seed) {
        std::string m = script;
        switch (strategy) {
            case ARGUMENT_FUZZ:
                m += " 2>/dev/null || true";
                break;
            case VALUE_BOUNDARY: {
                // Replace first numeric-looking substring with a boundary value
                size_t pos = m.find_first_of("0123456789");
                if (pos != std::string::npos) {
                    size_t end = m.find_first_not_of("0123456789", pos);
                    std::string replacement = (seed % 2 == 0) ? "0" : "2147483647";
                    m = m.substr(0, pos) + replacement + m.substr(end);
                }
                break;
            }
            case SEQUENCE_REORDER:
                m = "sleep 0." + std::to_string(seed % 10) + " && " + m;
                break;
            case CONDITION_NEGATE:
                m = "! " + m + " && echo NEGATED || echo ORIGINAL";
                break;
            case TIMING_VARIATION:
                m = "for _i in 1 2 3; do " + m + "; done";
                break;
            case INPUT_EXPANSION:
                m += " $(python3 -c \"print('A'*1024)\" 2>/dev/null)";
                break;
            case EMPTY_INPUT:
                m += " ''";
                break;
            case MAX_INPUT_MUTATION:
                m += " $(python3 -c \"print('\\xff'*65536)\" 2>/dev/null)";
                break;
        }
        return m;
    }
};

// --- E.2: Protocol State Machine Validator ---

class ProtocolStateMachineValidator {
public:
    struct StateTransition {
        std::string from_state;
        std::string to_state;
        std::string trigger_event;
        std::vector<std::string> preconditions;
        std::vector<std::string> postconditions;
        bool is_valid_transition;
    };

    struct StateMachine {
        std::string name;
        std::set<std::string> states;
        std::string initial_state;
        std::set<std::string> accepting_states;
        std::vector<StateTransition> transitions;
    };

private:
    std::vector<StateMachine> protocol_machines_;

public:
    void define_mempool_state_machine() {
        StateMachine sm;
        sm.name = "mempool";
        sm.initial_state = "EMPTY";
        sm.states = {"EMPTY", "ACCEPTING", "FULL", "TRIMMING", "REORG_PROCESSING"};
        sm.accepting_states = {"EMPTY", "ACCEPTING"};
        sm.transitions = {
            {"EMPTY", "ACCEPTING", "FirstTxAccepted",
             {"ValidTransaction"}, {"MempoolNotEmpty"}, true},
            {"ACCEPTING", "ACCEPTING", "TxAccepted",
             {"ValidTransaction", "FeeAboveMinimum"}, {"TxInMempool"}, true},
            {"ACCEPTING", "ACCEPTING", "TxRejected",
             {"InvalidTransaction"}, {"TxNotInMempool"}, true},
            {"ACCEPTING", "FULL", "MempoolSizeExceeded",
             {"MaxMempoolSize"}, {"EvictionNeeded"}, true},
            {"FULL", "TRIMMING", "EvictionStarted",
             {"LowestFeeTxIdentified"}, {"EvictingInProgress"}, true},
            {"TRIMMING", "ACCEPTING", "EvictionComplete",
             {"BelowMaxSize"}, {"SpaceAvailable"}, true},
            {"TRIMMING", "FULL", "EvictionInsufficient",
             {"StillAboveMax"}, {"MoreEvictionNeeded"}, true},
            {"ACCEPTING", "REORG_PROCESSING", "ChainReorg",
             {"NewBestTip"}, {"MempoolInvalidated"}, true},
            {"REORG_PROCESSING", "ACCEPTING", "ReorgComplete",
             {"MempoolRevalidated"}, {"NormalOps"}, true},
            {"ACCEPTING", "EMPTY", "AllTxsMined",
             {"BlockIncludesAll"}, {"MempoolCleared"}, true},
            {"FULL", "REORG_PROCESSING", "ChainReorgWhileFull",
             {"NewBestTip"}, {"MempoolInvalidated"}, true},
            // Invalid transitions for detection
            {"EMPTY", "FULL", "DirectFull", {}, {}, false},
            {"TRIMMING", "EMPTY", "DirectEmpty", {}, {}, false},
        };
        protocol_machines_.push_back(sm);
    }

    void define_chain_validation_state_machine() {
        StateMachine sm;
        sm.name = "chain_validation";
        sm.initial_state = "INITIALIZING";
        sm.states = {
            "INITIALIZING", "IBD", "SYNCED", "VALIDATING_BLOCK",
            "CONNECTING_BLOCK", "DISCONNECTING_BLOCK", "REINDEXING",
            "SNAPSHOT_LOADING", "SNAPSHOT_VALIDATING", "ERROR"
        };
        sm.accepting_states = {"SYNCED"};
        sm.transitions = {
            {"INITIALIZING", "IBD", "StartIBD",
             {"GenesisLoaded"}, {"SyncingHeaders"}, true},
            {"INITIALIZING", "SNAPSHOT_LOADING", "LoadSnapshot",
             {"AssumeUTXOEnabled"}, {"LoadingUTXO"}, true},
            {"INITIALIZING", "REINDEXING", "ReindexOnStartup",
             {"ReindexFlag"}, {"ProcessingBlocks"}, true},
            {"IBD", "SYNCED", "IBDComplete",
             {"CaughtUp"}, {"AcceptingNewBlocks"}, true},
            {"IBD", "ERROR", "IBDFailed",
             {"CorruptionDetected"}, {"Halted"}, false},
            {"SYNCED", "VALIDATING_BLOCK", "NewBlockReceived",
             {"ValidHeader"}, {"RunningChecks"}, true},
            {"VALIDATING_BLOCK", "CONNECTING_BLOCK", "BlockValid",
             {"AllChecksPass"}, {"UpdatingUTXO"}, true},
            {"VALIDATING_BLOCK", "SYNCED", "BlockInvalid",
             {"CheckFailed"}, {"BlockRejected"}, true},
            {"CONNECTING_BLOCK", "SYNCED", "BlockConnected",
             {"UTXOUpdated"}, {"NewTip"}, true},
            {"SYNCED", "DISCONNECTING_BLOCK", "Reorg",
             {"BetterChainFound"}, {"Disconnecting"}, true},
            {"DISCONNECTING_BLOCK", "CONNECTING_BLOCK", "DisconnectDone",
             {"BlockDisconnected"}, {"Reconnecting"}, true},
            {"SNAPSHOT_LOADING", "SNAPSHOT_VALIDATING", "SnapshotLoaded",
             {"UTXOSet"}, {"Verifying"}, true},
            {"SNAPSHOT_VALIDATING", "SYNCED", "SnapshotValid",
             {"HashMatch"}, {"Operational"}, true},
            {"SNAPSHOT_VALIDATING", "ERROR", "SnapshotInvalid",
             {"HashMismatch"}, {"Corrupted"}, false},
            {"SYNCED", "REINDEXING", "ReindexRequested",
             {"UserRequest"}, {"Reindexing"}, true},
            {"REINDEXING", "SYNCED", "ReindexComplete",
             {"AllBlocksProcessed"}, {"Operational"}, true},
        };
        protocol_machines_.push_back(sm);
    }

    void define_peer_management_state_machine() {
        StateMachine sm;
        sm.name = "peer_management";
        sm.initial_state = "DISCONNECTED";
        sm.states = {
            "DISCONNECTED", "CONNECTING", "VERSION_EXCHANGE",
            "VERACK_SENT", "CONNECTED", "MISBEHAVING",
            "BANNED", "DISCONNECTING"
        };
        sm.accepting_states = {"DISCONNECTED", "CONNECTED"};
        sm.transitions = {
            {"DISCONNECTED", "CONNECTING", "Connect",
             {"AddressKnown"}, {"SocketOpened"}, true},
            {"CONNECTING", "VERSION_EXCHANGE", "SocketReady",
             {"Connected"}, {"SendVersion"}, true},
            {"CONNECTING", "DISCONNECTED", "ConnectFailed",
             {"Timeout"}, {"Cleanup"}, true},
            {"VERSION_EXCHANGE", "VERACK_SENT", "VersionReceived",
             {"Compatible"}, {"SendVerack"}, true},
            {"VERSION_EXCHANGE", "DISCONNECTING", "IncompatibleVersion",
             {"VersionMismatch"}, {"Rejecting"}, true},
            {"VERACK_SENT", "CONNECTED", "VerackReceived",
             {"HandshakeComplete"}, {"Operational"}, true},
            {"CONNECTED", "MISBEHAVING", "BadMessage",
             {"ProtocolViolation"}, {"ScoreIncreased"}, true},
            {"MISBEHAVING", "BANNED", "ScoreExceeded",
             {"BanThreshold"}, {"PeerBanned"}, true},
            {"MISBEHAVING", "CONNECTED", "ScoreBelowThreshold",
             {"MinorViolation"}, {"Continued"}, true},
            {"CONNECTED", "DISCONNECTING", "DisconnectRequested",
             {"Reason"}, {"Closing"}, true},
            {"DISCONNECTING", "DISCONNECTED", "SocketClosed",
             {"Cleanup"}, {"Done"}, true},
            {"BANNED", "DISCONNECTED", "BanExpired",
             {"TimePassed"}, {"CanReconnect"}, true},
            // Invalid transitions
            {"DISCONNECTED", "CONNECTED", "DirectConnect", {}, {}, false},
            {"BANNED", "CONNECTED", "BannedConnect", {}, {}, false},
        };
        protocol_machines_.push_back(sm);
    }

    // Find all invalid transitions across all state machines
    std::vector<StateTransition> find_invalid_transitions() const {
        std::vector<StateTransition> invalid;
        for (const auto& sm : protocol_machines_)
            for (const auto& t : sm.transitions)
                if (!t.is_valid_transition) invalid.push_back(t);
        return invalid;
    }

    // Find states not reachable from initial state via valid transitions
    std::vector<std::string> find_unreachable_states() const {
        std::vector<std::string> unreachable;
        for (const auto& sm : protocol_machines_) {
            std::set<std::string> reachable;
            std::queue<std::string> worklist;
            worklist.push(sm.initial_state);
            reachable.insert(sm.initial_state);

            while (!worklist.empty()) {
                std::string current = worklist.front();
                worklist.pop();
                for (const auto& t : sm.transitions) {
                    if (t.from_state == current && t.is_valid_transition &&
                        !reachable.count(t.to_state)) {
                        reachable.insert(t.to_state);
                        worklist.push(t.to_state);
                    }
                }
            }

            for (const auto& state : sm.states)
                if (!reachable.count(state))
                    unreachable.push_back(sm.name + "::" + state);
        }
        return unreachable;
    }

    // Generate a test sequence that visits every reachable state
    std::vector<std::string> generate_full_state_coverage_test() const {
        std::vector<std::string> test_sequence;

        for (const auto& sm : protocol_machines_) {
            test_sequence.push_back("# === State machine: " + sm.name + " ===");
            std::set<std::string> visited;
            std::string current = sm.initial_state;
            visited.insert(current);
            test_sequence.push_back("  START: " + current);

            // Greedy traversal to maximise state coverage
            bool progress = true;
            int steps = 0;
            while (progress && steps < 100) {
                progress = false;
                // Prefer transitions to unvisited states
                for (const auto& t : sm.transitions) {
                    if (t.from_state == current && t.is_valid_transition &&
                        !visited.count(t.to_state)) {
                        test_sequence.push_back("  " + t.from_state + " --[" +
                            t.trigger_event + "]--> " + t.to_state);
                        current = t.to_state;
                        visited.insert(current);
                        progress = true;
                        steps++;
                        break;
                    }
                }
                if (!progress) {
                    // Try backtracking via any valid transition to reach new states
                    for (const auto& t : sm.transitions) {
                        if (t.from_state == current && t.is_valid_transition) {
                            // Can we get to an unvisited state from t.to_state?
                            for (const auto& t2 : sm.transitions) {
                                if (t2.from_state == t.to_state && t2.is_valid_transition &&
                                    !visited.count(t2.to_state)) {
                                    test_sequence.push_back("  " + current + " --[" +
                                        t.trigger_event + "]--> " + t.to_state + " (transit)");
                                    current = t.to_state;
                                    visited.insert(current);
                                    progress = true;
                                    steps++;
                                    break;
                                }
                            }
                            if (progress) break;
                        }
                    }
                }
            }

            test_sequence.push_back("  Coverage: " + std::to_string(visited.size()) +
                "/" + std::to_string(sm.states.size()) + " states");
        }
        return test_sequence;
    }

    // Compare two versions of the same state machine
    std::vector<std::pair<StateTransition, StateTransition>>
    compare_state_machines(const StateMachine& v1, const StateMachine& v2) const {
        std::vector<std::pair<StateTransition, StateTransition>> diffs;

        // Find transitions present in v1 but changed or missing in v2
        for (const auto& t1 : v1.transitions) {
            bool found = false;
            for (const auto& t2 : v2.transitions) {
                if (t1.from_state == t2.from_state && t1.to_state == t2.to_state &&
                    t1.trigger_event == t2.trigger_event) {
                    found = true;
                    if (t1.is_valid_transition != t2.is_valid_transition ||
                        t1.preconditions != t2.preconditions ||
                        t1.postconditions != t2.postconditions)
                        diffs.push_back({t1, t2});
                    break;
                }
            }
            if (!found) {
                StateTransition removed;
                removed.from_state = t1.from_state;
                removed.to_state = t1.to_state;
                removed.trigger_event = "REMOVED_IN_V2";
                removed.is_valid_transition = false;
                diffs.push_back({t1, removed});
            }
        }

        // Find transitions in v2 not present in v1
        for (const auto& t2 : v2.transitions) {
            bool found = false;
            for (const auto& t1 : v1.transitions) {
                if (t1.from_state == t2.from_state && t1.to_state == t2.to_state &&
                    t1.trigger_event == t2.trigger_event) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                StateTransition added;
                added.from_state = t2.from_state;
                added.to_state = t2.to_state;
                added.trigger_event = "ADDED_IN_V2";
                added.is_valid_transition = false;
                diffs.push_back({added, t2});
            }
        }

        return diffs;
    }

    size_t machine_count() const { return protocol_machines_.size(); }

    const StateMachine* get_machine(const std::string& name) const {
        for (const auto& sm : protocol_machines_)
            if (sm.name == name) return &sm;
        return nullptr;
    }
};


