// --- F.1: Incremental Analysis Cache ---

class IncrementalAnalysisCache {
public:
    struct FileAnalysisSnapshot {
        std::string file_path;
        std::string file_hash;
        int64_t analysis_timestamp;
        std::vector<Finding> previous_findings;
        int line_count;
        int function_count;
    };

private:
    std::unordered_map<std::string, FileAnalysisSnapshot> cache_;
    std::string cache_directory_;
    mutable std::mutex mutex_;

    // Simple SHA256-like hash (using file content hashing)
    static std::string compute_file_hash(const std::string& file_path) {
        std::ifstream file(file_path, std::ios::binary);
        if (!file.is_open()) return "";

        // Use a simple but deterministic hash
        uint64_t h1 = 0xcbf29ce484222325ULL;
        uint64_t h2 = 0x100000001b3ULL;
        char buffer[8192];
        while (file.read(buffer, sizeof(buffer)) || file.gcount() > 0) {
            for (std::streamsize i = 0; i < file.gcount(); i++) {
                h1 ^= static_cast<uint64_t>(static_cast<unsigned char>(buffer[i]));
                h1 *= h2;
            }
        }

        std::ostringstream oss;
        oss << std::hex << std::setfill('0') << std::setw(16) << h1;
        return oss.str();
    }

public:
    void load_cache(const std::string& cache_dir) {
        cache_directory_ = cache_dir;
        std::string index_path = cache_dir + "/cache_index.txt";
        std::ifstream index(index_path);
        if (!index.is_open()) {
            Logger::instance().info("IncrementalAnalysisCache: no existing cache at " + cache_dir);
            return;
        }

        std::string line;
        int loaded = 0;
        while (std::getline(index, line)) {
            if (line.empty() || line[0] == '#') continue;
            // Format: file_path|hash|timestamp|finding_count
            std::vector<std::string> parts;
            std::istringstream iss(line);
            std::string part;
            while (std::getline(iss, part, '|')) parts.push_back(part);

            if (parts.size() >= 4) {
                FileAnalysisSnapshot snap;
                snap.file_path = parts[0];
                snap.file_hash = parts[1];
                try {
                    snap.analysis_timestamp = std::stoll(parts[2]);
                    int finding_count = std::stoi(parts[3]);

                    // Load findings from per-file cache
                    std::string findings_path = cache_dir + "/" + snap.file_hash + ".findings";
                    std::ifstream fin(findings_path);
                    if (fin.is_open()) {
                        std::string fline;
                        while (std::getline(fin, fline) &&
                               static_cast<int>(snap.previous_findings.size()) < finding_count) {
                            // Minimal finding reconstruction from cache line
                            Finding f;
                            f.detailed_description = fline;
                            f.file = snap.file_path;
                            snap.previous_findings.push_back(f);
                        }
                    }

                    cache_[snap.file_path] = snap;
                    loaded++;
                } catch (...) {
                    continue;
                }
            }
        }

        Logger::instance().info("IncrementalAnalysisCache: loaded " +
            std::to_string(loaded) + " cached analyses");
    }

    bool needs_reanalysis(const std::string& file_path) {
        std::lock_guard<std::mutex> lock(mutex_);
        auto it = cache_.find(file_path);
        if (it == cache_.end()) return true;

        std::string current_hash = compute_file_hash(file_path);
        return (current_hash != it->second.file_hash);
    }

    // Analyse only the changed portion of a file
    std::vector<Finding> analyze_delta(
            const std::string& file_path,
            const std::string& old_content,
            const std::string& new_content) {
        std::vector<Finding> delta_findings;

        // Split into lines for diff
        auto split_lines = [](const std::string& content) -> std::vector<std::string> {
            std::vector<std::string> lines;
            std::istringstream iss(content);
            std::string line;
            while (std::getline(iss, line)) lines.push_back(line);
            return lines;
        };

        auto old_lines = split_lines(old_content);
        auto new_lines = split_lines(new_content);

        // Find changed line ranges (simple LCS-based diff)
        std::set<int> changed_lines;
        size_t max_lines = std::max(old_lines.size(), new_lines.size());
        for (size_t i = 0; i < max_lines; i++) {
            if (i >= old_lines.size() || i >= new_lines.size() ||
                old_lines[i] != new_lines[i]) {
                changed_lines.insert(static_cast<int>(i + 1));
                // Include context: 5 lines before and after
                for (int ctx = -5; ctx <= 5; ctx++) {
                    int ctx_line = static_cast<int>(i + 1) + ctx;
                    if (ctx_line > 0 && ctx_line <= static_cast<int>(new_lines.size()))
                        changed_lines.insert(ctx_line);
                }
            }
        }

        // Return cached findings that are NOT in changed regions,
        // plus mark changed regions as needing fresh analysis
        auto it = cache_.find(file_path);
        if (it != cache_.end()) {
            for (const auto& f : it->second.previous_findings) {
                if (!changed_lines.count(f.location.line)) {
                    // Finding is in unchanged code — keep it
                    delta_findings.push_back(f);
                }
                // Findings in changed regions are discarded; fresh analysis will re-detect
            }
        }

        Logger::instance().info("IncrementalAnalysisCache: delta for " + file_path +
            ": " + std::to_string(changed_lines.size()) + " changed lines, " +
            std::to_string(delta_findings.size()) + " cached findings preserved");

        return delta_findings;
    }

    void update_cache(const std::string& file_path,
                       const std::vector<Finding>& new_findings) {
        std::lock_guard<std::mutex> lock(mutex_);
        FileAnalysisSnapshot snap;
        snap.file_path = file_path;
        snap.file_hash = compute_file_hash(file_path);
        snap.analysis_timestamp = std::chrono::duration_cast<std::chrono::seconds>(
            std::chrono::system_clock::now().time_since_epoch()).count();
        snap.previous_findings = new_findings;
        cache_[file_path] = snap;
    }

    void persist_cache() {
        if (cache_directory_.empty()) return;
        std::filesystem::create_directories(cache_directory_);

        std::string index_path = cache_directory_ + "/cache_index.txt";
        std::ofstream index(index_path);
        if (!index.is_open()) return;

        index << "# IncrementalAnalysisCache index\n";
        index << "# format: file_path|hash|timestamp|finding_count\n";

        std::lock_guard<std::mutex> lock(mutex_);
        for (const auto& [path, snap] : cache_) {
            index << snap.file_path << "|" << snap.file_hash << "|"
                  << snap.analysis_timestamp << "|"
                  << snap.previous_findings.size() << "\n";

            // Write per-file findings
            std::string findings_path = cache_directory_ + "/" + snap.file_hash + ".findings";
            std::ofstream fout(findings_path);
            if (fout.is_open()) {
                for (const auto& f : snap.previous_findings)
                    fout << f.detailed_description << "\n";
            }
        }

        Logger::instance().info("IncrementalAnalysisCache: persisted " +
            std::to_string(cache_.size()) + " file caches to " + cache_directory_);
    }

    // Identify findings that are new since the last analysis run
    std::vector<Finding> get_new_findings_since_last_run(
            const std::vector<Finding>& current_findings) {
        std::lock_guard<std::mutex> lock(mutex_);
        std::vector<Finding> new_findings;

        // Build a set of previous finding descriptions for fast lookup
        std::set<std::string> previous_descriptions;
        for (const auto& [path, snap] : cache_) {
            for (const auto& f : snap.previous_findings)
                previous_descriptions.insert(f.detailed_description);
        }

        for (const auto& f : current_findings) {
            if (!previous_descriptions.count(f.detailed_description))
                new_findings.push_back(f);
        }

        return new_findings;
    }

    size_t cached_file_count() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return cache_.size();
    }
};

// --- F.2: Semantic-Aware Code Differ ---

class SemanticDiffEngine {
public:
    struct SemanticChange {
        enum ChangeType {
            FUNCTION_ADDED,
            FUNCTION_REMOVED,
            FUNCTION_SIGNATURE_CHANGED,
            LOCK_ACQUISITION_ADDED,
            LOCK_ACQUISITION_REMOVED,
            CHECK_ADDED,
            CHECK_REMOVED,
            SENSITIVE_DATA_PATH_CHANGED,
            CLEANUP_CALL_ADDED,
            CLEANUP_CALL_REMOVED
        };

        ChangeType type;
        std::string location;
        std::string function_name;
        std::string old_code;
        std::string new_code;
        int security_impact;  // -10 (much worse) to +10 (much better)
        std::string explanation;
    };

private:
    // Extract function signatures from code
    static std::map<std::string, std::string> extract_function_signatures(
            const std::string& code) {
        std::map<std::string, std::string> signatures;
        std::istringstream iss(code);
        std::string line;
        int line_num = 0;
        while (std::getline(iss, line)) {
            line_num++;
            // Simple heuristic: line with '(' and '{' on same or next line
            size_t paren = line.find('(');
            if (paren != std::string::npos && paren > 0) {
                // Extract function name (last word before '(')
                size_t name_end = paren;
                while (name_end > 0 && line[name_end - 1] == ' ') name_end--;
                size_t name_start = name_end;
                while (name_start > 0 && (std::isalnum(line[name_start - 1]) ||
                       line[name_start - 1] == '_' || line[name_start - 1] == ':'))
                    name_start--;
                if (name_start < name_end) {
                    std::string func_name = line.substr(name_start, name_end - name_start);
                    if (!func_name.empty() && func_name != "if" && func_name != "for" &&
                        func_name != "while" && func_name != "switch") {
                        signatures[func_name] = line;
                    }
                }
            }
        }
        return signatures;
    }

    // Extract lock acquisitions
    static std::set<std::string> extract_lock_patterns(const std::string& code) {
        std::set<std::string> locks;
        std::istringstream iss(code);
        std::string line;
        while (std::getline(iss, line)) {
            for (const auto& pattern : {"LOCK(", "LOCK2(", "lock_guard", "unique_lock", "scoped_lock"}) {
                if (line.find(pattern) != std::string::npos)
                    locks.insert(line);
            }
        }
        return locks;
    }

    // Extract cleanup calls
    static std::set<std::string> extract_cleanup_patterns(const std::string& code) {
        std::set<std::string> cleanups;
        std::istringstream iss(code);
        std::string line;
        while (std::getline(iss, line)) {
            for (const auto& pattern : {"memory_cleanse", "OPENSSL_cleanse", "SecureErase",
                                         "cleanse", "memset_s", "explicit_bzero"}) {
                if (line.find(pattern) != std::string::npos)
                    cleanups.insert(line);
            }
        }
        return cleanups;
    }

    // Extract security checks
    static std::set<std::string> extract_check_patterns(const std::string& code) {
        std::set<std::string> checks;
        std::istringstream iss(code);
        std::string line;
        while (std::getline(iss, line)) {
            for (const auto& pattern : {"EnsureWalletIsUnlocked", "AssertLockHeld",
                                         "CheckProofOfWork", "VerifyScript",
                                         "CheckBlock", "CheckTransaction",
                                         "IsInitialBlockDownload"}) {
                if (line.find(pattern) != std::string::npos)
                    checks.insert(line);
            }
        }
        return checks;
    }

public:
    // Compute semantic diff between two code versions
    std::vector<SemanticChange> compute_semantic_diff(
            const std::string& old_code,
            const std::string& new_code) {
        std::vector<SemanticChange> changes;

        // Compare function signatures
        auto old_funcs = extract_function_signatures(old_code);
        auto new_funcs = extract_function_signatures(new_code);

        for (const auto& [name, sig] : new_funcs) {
            if (old_funcs.find(name) == old_funcs.end()) {
                SemanticChange c;
                c.type = SemanticChange::FUNCTION_ADDED;
                c.function_name = name;
                c.new_code = sig;
                c.security_impact = 0;
                c.explanation = "New function added: " + name;
                changes.push_back(c);
            } else if (old_funcs[name] != sig) {
                SemanticChange c;
                c.type = SemanticChange::FUNCTION_SIGNATURE_CHANGED;
                c.function_name = name;
                c.old_code = old_funcs[name];
                c.new_code = sig;
                c.security_impact = -2;
                c.explanation = "Function signature changed: " + name;
                changes.push_back(c);
            }
        }
        for (const auto& [name, sig] : old_funcs) {
            if (new_funcs.find(name) == new_funcs.end()) {
                SemanticChange c;
                c.type = SemanticChange::FUNCTION_REMOVED;
                c.function_name = name;
                c.old_code = sig;
                c.security_impact = -3;
                c.explanation = "Function removed: " + name;
                changes.push_back(c);
            }
        }

        // Compare lock acquisitions
        auto old_locks = extract_lock_patterns(old_code);
        auto new_locks = extract_lock_patterns(new_code);

        for (const auto& l : new_locks) {
            if (!old_locks.count(l)) {
                SemanticChange c;
                c.type = SemanticChange::LOCK_ACQUISITION_ADDED;
                c.new_code = l;
                c.security_impact = +3;
                c.explanation = "Lock acquisition added (hardening)";
                changes.push_back(c);
            }
        }
        for (const auto& l : old_locks) {
            if (!new_locks.count(l)) {
                SemanticChange c;
                c.type = SemanticChange::LOCK_ACQUISITION_REMOVED;
                c.old_code = l;
                c.security_impact = -5;
                c.explanation = "Lock acquisition removed (potential regression)";
                changes.push_back(c);
            }
        }

        // Compare cleanup calls
        auto old_cleanups = extract_cleanup_patterns(old_code);
        auto new_cleanups = extract_cleanup_patterns(new_code);

        for (const auto& c_line : new_cleanups) {
            if (!old_cleanups.count(c_line)) {
                SemanticChange c;
                c.type = SemanticChange::CLEANUP_CALL_ADDED;
                c.new_code = c_line;
                c.security_impact = +4;
                c.explanation = "Secure cleanup call added (hardening)";
                changes.push_back(c);
            }
        }
        for (const auto& c_line : old_cleanups) {
            if (!new_cleanups.count(c_line)) {
                SemanticChange c;
                c.type = SemanticChange::CLEANUP_CALL_REMOVED;
                c.old_code = c_line;
                c.security_impact = -7;
                c.explanation = "Secure cleanup call removed (REGRESSION)";
                changes.push_back(c);
            }
        }

        // Compare security checks
        auto old_checks = extract_check_patterns(old_code);
        auto new_checks = extract_check_patterns(new_code);

        for (const auto& chk : new_checks) {
            if (!old_checks.count(chk)) {
                SemanticChange c;
                c.type = SemanticChange::CHECK_ADDED;
                c.new_code = chk;
                c.security_impact = +3;
                c.explanation = "Security check added";
                changes.push_back(c);
            }
        }
        for (const auto& chk : old_checks) {
            if (!new_checks.count(chk)) {
                SemanticChange c;
                c.type = SemanticChange::CHECK_REMOVED;
                c.old_code = chk;
                c.security_impact = -6;
                c.explanation = "Security check removed (REGRESSION)";
                changes.push_back(c);
            }
        }

        return changes;
    }

    // Aggregate security impact score across all changes
    int score_security_impact(const std::vector<SemanticChange>& changes) {
        int total = 0;
        for (const auto& c : changes) total += c.security_impact;
        return total;
    }

    // Filter only regressions (negative security impact)
    std::vector<SemanticChange> find_security_regressions(
            const std::vector<SemanticChange>& changes) {
        std::vector<SemanticChange> regressions;
        for (const auto& c : changes)
            if (c.security_impact < 0) regressions.push_back(c);
        return regressions;
    }

    // Generate findings from semantic changes
    std::vector<Finding> generate_diff_findings(
            const std::vector<SemanticChange>& changes,
            const std::string& file_path) {
        std::vector<Finding> findings;
        for (const auto& c : changes) {
            if (c.security_impact >= 0) continue;  // Only negative-impact changes

            Finding f;
            f.finding_id = IDGenerator::instance().next();
            f.file = file_path;
            f.function_name = c.function_name;
            f.detailed_description = c.explanation;
            f.version_diff_detail = "old: " + c.old_code.substr(0, 100) +
                " -> new: " + c.new_code.substr(0, 100);
            f.confidence = 0.65;

            if (c.security_impact <= -5) {
                f.severity = Severity::High;
                f.issue_type = IssueType::SensitiveDataExposure;
            } else if (c.security_impact <= -3) {
                f.severity = Severity::Medium;
                f.issue_type = IssueType::ImproperCleanup;
            } else {
                f.severity = Severity::Low;
                f.issue_type = IssueType::Informational;
            }

            f.classification = Classification::Inconclusive;
            f.static_analysis_evidence.push_back(
                "semantic impact: " + std::to_string(c.security_impact));
            findings.push_back(f);
        }
        return findings;
    }
};


// ============================================================================
// SECTION 62: INTEGRATION POINTS - CONNECTING ALL PHASE 2 SYSTEMS
// Phase 2 - Section G: Enhanced Orchestrator & Main Function Updates
// ============================================================================

// --- G.1: Enhanced Verification Orchestrator Phase 2 ---
// Extends the existing 11-phase pipeline with 4 new phases (12-15)

class EnhancedVerificationOrchestrator_Phase2 : public EnhancedVerificationOrchestrator {
private:
    // Phase 2 subsystem references
    CallGraphPathExplorer call_graph_explorer_;
    CallSiteAnalyzer call_site_analyzer_;
    InterProceduralDataFlow interprocedural_df_;
    GlobalStateAnalyzer global_state_analyzer_;
    ChainStateMonitor chain_state_monitor_;
    InstrumentationHooks instrumentation_hooks_;
    ConcurrentTestScheduler test_scheduler_;
    ResourceAwareAllocator resource_allocator_;
    CoverageGuidedTestMutator coverage_mutator_;
    ProtocolStateMachineValidator state_machine_validator_;
    IncrementalAnalysisCache analysis_cache_;
    SemanticDiffEngine semantic_diff_;

    // Phase 2 findings accumulated across all new phases
    std::vector<Finding> phase2_findings_;

public:
    EnhancedVerificationOrchestrator_Phase2() = default;

    // --- Phase 12: Deep Call-Graph Exploration ---
    void phase_12_explore_call_graphs(const TranslationUnit& tu) {
        Logger::instance().info("=== Phase 12: Deep Call-Graph Exploration ===");
        auto phase_start = std::chrono::steady_clock::now();

        // Build the call graph from the translation unit
        call_graph_explorer_.build_call_graph(tu);

        Logger::instance().info("  Call graph: " +
            std::to_string(call_graph_explorer_.node_count()) + " nodes, " +
            std::to_string(call_graph_explorer_.count_edges()) + " edges");

        // Find unguarded paths to sensitive operations
        auto unguarded_findings = call_graph_explorer_.generate_unguarded_path_findings();
        Logger::instance().info("  Unguarded path findings: " +
            std::to_string(unguarded_findings.size()));

        // Analyze call sites for unchecked return values
        static const std::set<std::string> critical_return_funcs = {
            "AcceptToMemoryPool", "CheckBlock", "ConnectBlock",
            "SignCompact", "Verify", "CheckProofOfWork",
            "CreateTransaction", "GetKey", "GenerateNewKey"
        };

        // Cross-module path analysis
        std::vector<std::pair<std::string, std::string>> module_pairs = {
            {"rpc", "wallet"}, {"net", "validation"}, {"wallet", "crypto"},
            {"rpc", "validation"}, {"net", "mempool"}, {"script", "crypto"}
        };
        int cross_module_count = 0;
        for (const auto& [src, tgt] : module_pairs) {
            auto paths = call_graph_explorer_.find_cross_module_paths(src, tgt);
            cross_module_count += static_cast<int>(paths.size());
            for (const auto& path : paths) {
                if (path.risk_score > 0.6) {
                    Finding f;
                    f.finding_id = IDGenerator::instance().next();
                    f.issue_type = IssueType::Informational;
                    f.severity = Severity::Low;
                    f.confidence = 0.50;
                    f.classification = Classification::Inconclusive;
                    f.detailed_description = "High-risk cross-module path from " +
                        src + " to " + tgt + " (risk=" +
                        std::to_string(path.risk_score) + ")";
                    if (!path.nodes.empty()) {
                        f.function_name = path.nodes.front()->function_name;
                        f.file = path.nodes.front()->file_path;
                    }
                    phase2_findings_.push_back(f);
                }
            }
        }

        phase2_findings_.insert(phase2_findings_.end(),
            unguarded_findings.begin(), unguarded_findings.end());

        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - phase_start).count();
        Logger::instance().info("  Phase 12 complete: " +
            std::to_string(cross_module_count) + " cross-module paths, " +
            std::to_string(elapsed) + "ms");
    }

    // --- Phase 13: Inter-Procedural Taint Merge ---
    void phase_13_merge_interprocedural_taint(const TranslationUnit& tu,
                                               std::vector<Finding>& existing_findings) {
        Logger::instance().info("=== Phase 13: Inter-Procedural Taint Merge ===");
        auto phase_start = std::chrono::steady_clock::now();

        // Build function summaries
        interprocedural_df_.build_function_summaries(tu);
        Logger::instance().info("  Function summaries: " +
            std::to_string(interprocedural_df_.summary_count()));

        // Propagate taint across call boundaries using existing findings
        interprocedural_df_.propagate_taint_across_calls(existing_findings, call_graph_explorer_);

        // Find exposed taint paths from public entry points
        std::vector<std::string> entry_points = {
            "getnewaddress", "sendtoaddress", "signrawtransactionwithwallet",
            "importprivkey", "dumpprivkey", "walletpassphrase",
            "submitblock", "getblocktemplate", "ProcessMessage",
            "ProcessGetData", "ThreadMessageHandler"
        };
        auto exposed_paths = interprocedural_df_.find_exposed_taint_paths(
            entry_points, call_graph_explorer_);
        Logger::instance().info("  Exposed taint paths: " +
            std::to_string(exposed_paths.size()));

        // Analyse global state
        auto globals = global_state_analyzer_.analyze_global_variables(tu);
        auto global_findings = global_state_analyzer_.generate_global_access_findings();
        Logger::instance().info("  Global variables: " + std::to_string(globals.size()) +
            ", unprotected access findings: " + std::to_string(global_findings.size()));

        phase2_findings_.insert(phase2_findings_.end(),
            exposed_paths.begin(), exposed_paths.end());
        phase2_findings_.insert(phase2_findings_.end(),
            global_findings.begin(), global_findings.end());

        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - phase_start).count();
        Logger::instance().info("  Phase 13 complete: " + std::to_string(elapsed) + "ms");
    }

    // --- Phase 14: Coverage-Guided Test Evolution ---
    void phase_14_evolve_test_coverage(const std::string& source_dir,
                                        int generations = 3,
                                        int tests_per_gen = 10) {
        Logger::instance().info("=== Phase 14: Coverage-Guided Test Evolution ===");
        auto phase_start = std::chrono::steady_clock::now();

        coverage_mutator_.seed_initial_corpus();
        Logger::instance().info("  Initial corpus: " +
            std::to_string(coverage_mutator_.corpus_size()) + " tests");

        // Evolution loop (reduced iterations for integration)
        coverage_mutator_.evolve_test_suite(generations, tests_per_gen, source_dir);

        Logger::instance().info("  Final corpus: " +
            std::to_string(coverage_mutator_.corpus_size()) + " tests");

        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - phase_start).count();
        Logger::instance().info("  Phase 14 complete: " + std::to_string(elapsed) + "ms");
    }

    // --- Phase 15: Protocol State Machine Validation ---
    void phase_15_validate_protocol_states() {
        Logger::instance().info("=== Phase 15: Protocol State Machine Validation ===");
        auto phase_start = std::chrono::steady_clock::now();

        // Define all protocol state machines
        state_machine_validator_.define_mempool_state_machine();
        state_machine_validator_.define_chain_validation_state_machine();
        state_machine_validator_.define_peer_management_state_machine();

        Logger::instance().info("  State machines defined: " +
            std::to_string(state_machine_validator_.machine_count()));

        // Find invalid transitions
        auto invalid = state_machine_validator_.find_invalid_transitions();
        Logger::instance().info("  Known invalid transitions: " +
            std::to_string(invalid.size()));

        // Find unreachable states
        auto unreachable = state_machine_validator_.find_unreachable_states();
        if (!unreachable.empty()) {
            Logger::instance().warning("  Unreachable states detected:");
            for (const auto& state : unreachable) {
                Logger::instance().warning("    " + state);
                Finding f;
                f.finding_id = IDGenerator::instance().next();
                f.issue_type = IssueType::Informational;
                f.severity = Severity::Low;
                f.confidence = 0.80;
                f.classification = Classification::ConfirmedStatic;
                f.detailed_description = "Unreachable protocol state: " + state +
                    " — possible dead code or incomplete state machine specification";
                phase2_findings_.push_back(f);
            }
        }

        // Generate full coverage test sequences
        auto coverage_tests = state_machine_validator_.generate_full_state_coverage_test();
        Logger::instance().info("  State coverage test steps: " +
            std::to_string(coverage_tests.size()));

        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - phase_start).count();
        Logger::instance().info("  Phase 15 complete: " + std::to_string(elapsed) + "ms");
    }

    // --- Override: Full 15-Phase Pipeline ---
    void execute_full_pipeline(
            const TranslationUnit& tu,
            std::vector<Finding>& findings,
            const std::string& source_dir = "",
            const std::string& old_code = "",
            const std::string& new_code = "") {

        Logger::instance().info("========================================");
        Logger::instance().info("EnhancedVerificationOrchestrator_Phase2");
        Logger::instance().info("  15-Phase Verification Pipeline");
        Logger::instance().info("========================================");

        auto pipeline_start = std::chrono::steady_clock::now();

        // --- Phases 1-11: Original pipeline (skipped here; called by CompleteVerificationOrchestrator) ---
        Logger::instance().info("--- Executing original Phases 1-11 (delegated) ---");

        // --- Check incremental analysis cache ---
        bool needs_full_analysis = true;
        if (!tu.file_path.empty()) {
            analysis_cache_.load_cache("analysis_cache/");
            needs_full_analysis = analysis_cache_.needs_reanalysis(tu.file_path);
            if (!needs_full_analysis) {
                Logger::instance().info("File unchanged since last analysis — using cached results");
            }
        }

        // --- Phase 12: Call-Graph Exploration ---
        phase_12_explore_call_graphs(tu);

        // --- Phase 13: Inter-Procedural Taint ---
        phase_13_merge_interprocedural_taint(tu, findings);

        // --- Phase 14: Coverage-Guided Testing ---
        if (!source_dir.empty()) {
            phase_14_evolve_test_coverage(source_dir, 3, 10);
        } else {
            Logger::instance().info("=== Phase 14: Skipped (no source_dir) ===");
        }

        // --- Phase 15: State Machine Validation ---
        phase_15_validate_protocol_states();

        // --- Semantic Diff (if old/new code provided) ---
        if (!old_code.empty() && !new_code.empty()) {
            Logger::instance().info("--- Semantic Diff Analysis ---");
            auto semantic_changes = semantic_diff_.compute_semantic_diff(old_code, new_code);
            int impact = semantic_diff_.score_security_impact(semantic_changes);
            auto regressions = semantic_diff_.find_security_regressions(semantic_changes);
            Logger::instance().info("  Semantic changes: " +
                std::to_string(semantic_changes.size()) +
                ", impact score: " + std::to_string(impact) +
                ", regressions: " + std::to_string(regressions.size()));

            auto diff_findings = semantic_diff_.generate_diff_findings(
                semantic_changes, tu.file_path);
            phase2_findings_.insert(phase2_findings_.end(),
                diff_findings.begin(), diff_findings.end());
        }

        // --- Chain State Monitor Report ---
        if (chain_state_monitor_.block_history_size() > 0) {
            auto snapshot = chain_state_monitor_.take_snapshot();
            Logger::instance().info("--- Chain State: height=" +
                std::to_string(snapshot.height) + ", mempool=" +
                std::to_string(snapshot.mempool_size) + " ---");
        }

        // --- Instrumentation Report ---
        auto instr_report = instrumentation_hooks_.generate_report();
        if (instr_report.total_violations > 0) {
            Logger::instance().warning("--- Instrumentation Violations: " +
                std::to_string(instr_report.total_violations) + " ---");
            for (const auto& v : instr_report.lock_order_violations)
                Logger::instance().warning("  LOCK: " + v);
            for (const auto& v : instr_report.missing_cleanup_calls)
                Logger::instance().warning("  CLEANUP: " + v);
            for (const auto& v : instr_report.consensus_check_failures)
                Logger::instance().warning("  CONSENSUS: " + v);
        }

        // --- Merge Phase 2 findings into main findings vector ---
        findings.insert(findings.end(),
            phase2_findings_.begin(), phase2_findings_.end());

        // --- Update incremental cache ---
        analysis_cache_.update_cache(tu.file_path, findings);
        analysis_cache_.persist_cache();

        // --- New findings since last run ---
        auto new_findings = analysis_cache_.get_new_findings_since_last_run(findings);
        Logger::instance().info("  New findings since last run: " +
            std::to_string(new_findings.size()));

        // --- Resource summary ---
        Logger::instance().info("  Resource allocator: " +
            std::to_string(resource_allocator_.get_total_allocated()) + " bytes active, " +
            std::to_string(resource_allocator_.get_peak_allocated()) + " peak");

        auto pipeline_elapsed = std::chrono::duration_cast<std::chrono::seconds>(
            std::chrono::steady_clock::now() - pipeline_start).count();

        Logger::instance().info("========================================");
        Logger::instance().info("Pipeline Complete: " +
            std::to_string(findings.size()) + " total findings in " +
            std::to_string(pipeline_elapsed) + "s");
        Logger::instance().info("  Phase 2 findings: " +
            std::to_string(phase2_findings_.size()));
        Logger::instance().info("========================================");
    }

    // --- Accessors for subsystems ---
    CallGraphPathExplorer& get_call_graph() { return call_graph_explorer_; }
    const CallGraphPathExplorer& get_call_graph() const { return call_graph_explorer_; }
    InterProceduralDataFlow& get_interprocedural_df() { return interprocedural_df_; }
    const InterProceduralDataFlow& get_interprocedural_df() const { return interprocedural_df_; }
    ChainStateMonitor& get_chain_monitor() { return chain_state_monitor_; }
    InstrumentationHooks& get_instrumentation() { return instrumentation_hooks_; }
    ConcurrentTestScheduler& get_scheduler() { return test_scheduler_; }
    ResourceAwareAllocator& get_allocator() { return resource_allocator_; }
    const ResourceAwareAllocator& get_allocator() const { return resource_allocator_; }
    CoverageGuidedTestMutator& get_coverage_mutator() { return coverage_mutator_; }
    const CoverageGuidedTestMutator& get_coverage_mutator() const { return coverage_mutator_; }
    ProtocolStateMachineValidator& get_state_validator() { return state_machine_validator_; }
    const ProtocolStateMachineValidator& get_state_validator() const { return state_machine_validator_; }
    IncrementalAnalysisCache& get_cache() { return analysis_cache_; }
    SemanticDiffEngine& get_semantic_diff() { return semantic_diff_; }

    const std::vector<Finding>& get_phase2_findings() const { return phase2_findings_; }
};


