// --- 73.1: Complete Verification Orchestrator (20 Phases) ---

class CompleteVerificationOrchestrator_Phase3 : public EnhancedVerificationOrchestrator_Phase2 {
private:
    // Phase 3 subsystem instances
    std::unique_ptr<AnalysisPersistenceLayer> persistence_;
    std::unique_ptr<WatchdogSupervisor> watchdog_;
    SignalManager* signal_manager_;
    std::unique_ptr<ProgressReporter> progress_;
    std::unique_ptr<StructuredLogger> structured_logger_;
    std::unique_ptr<PluginManager> plugin_manager_;
    std::unique_ptr<P2PTestHarness> p2p_harness_;
    std::unique_ptr<AddrManTester> addrman_tester_;
    std::unique_ptr<WalletDeepAnalyzer> wallet_analyzer_;
    std::unique_ptr<TransactionOutputAnalyzer> tx_output_analyzer_;
    std::unique_ptr<MempoolAcceptanceTracer> mempool_tracer_;
    std::unique_ptr<MempoolPolicyConsistency> mempool_policy_;
    std::unique_ptr<ReportValidator> report_validator_;
    std::unique_ptr<AnalysisQualityScorer> quality_scorer_;
    std::unique_ptr<AnalysisCheckpoint> checkpoint_;
    std::unique_ptr<IncrementalStateUpdater> state_updater_;

    std::vector<Finding> phase3_findings_;
    int phases_completed_;
    int total_phases_;

    void initialize_phase3_subsystems() {
        Logger::instance().info("Initializing Phase 3 subsystems...");
        persistence_ = std::make_unique<AnalysisPersistenceLayer>();
        watchdog_ = std::make_unique<WatchdogSupervisor>();
        signal_manager_ = SignalManager::get_instance();
        progress_ = std::make_unique<ProgressReporter>();
        structured_logger_ = std::make_unique<StructuredLogger>();
        plugin_manager_ = std::make_unique<PluginManager>();
        p2p_harness_ = std::make_unique<P2PTestHarness>();
        addrman_tester_ = std::make_unique<AddrManTester>();
        wallet_analyzer_ = std::make_unique<WalletDeepAnalyzer>();
        tx_output_analyzer_ = std::make_unique<TransactionOutputAnalyzer>();
        mempool_tracer_ = std::make_unique<MempoolAcceptanceTracer>();
        mempool_policy_ = std::make_unique<MempoolPolicyConsistency>();
        report_validator_ = std::make_unique<ReportValidator>();
        quality_scorer_ = std::make_unique<AnalysisQualityScorer>();
        checkpoint_ = std::make_unique<AnalysisCheckpoint>();
        state_updater_ = std::make_unique<IncrementalStateUpdater>();

        // Register standard plugins
        register_standard_plugins(*plugin_manager_);

        // Configure watchdog
        WatchdogSupervisor::WatchdogConfig wdg_cfg;
        wdg_cfg.global_timeout_seconds = 14400; // 4 hours
        wdg_cfg.test_timeout_seconds = 300;
        wdg_cfg.fuzzing_timeout_seconds = 3600;
        wdg_cfg.static_analysis_timeout_seconds = 600;
        watchdog_->configure(wdg_cfg);

        // Configure checkpoints
        checkpoint_->set_directory("checkpoints/");
        checkpoint_->set_interval(300);

        // Configure structured logger
        structured_logger_->add_console_output(StructuredLogger::INFO_LVL);
        structured_logger_->add_json_output("audit_structured_log.json");

        Logger::instance().info("Phase 3 subsystems initialized: 16 components");
    }

public:
    CompleteVerificationOrchestrator_Phase3()
        : phases_completed_(0), total_phases_(20) {}

    ~CompleteVerificationOrchestrator_Phase3() {
        if (watchdog_) watchdog_->stop_monitoring();
        if (checkpoint_) checkpoint_->stop_auto_checkpoint();
    }

    // --- Phase 16: Plugin-Based Analysis ---
    void phase_16_plugin_analysis(const TranslationUnit& tu) {
        Logger::instance().info("=== Phase 16: Plugin-Based Security Analysis ===");
        structured_logger_->log_phase_start("Plugin Analysis");
        auto start = std::chrono::steady_clock::now();
        progress_->advance_phase("Plugin Analysis");

        if (!signal_manager_->is_component_enabled("plugin_analysis")) {
            Logger::instance().info("  Phase 16 skipped (degraded mode)");
            return;
        }

        auto plugin_findings = plugin_manager_->run_all_plugins(tu);
        phase3_findings_.insert(phase3_findings_.end(),
            plugin_findings.begin(), plugin_findings.end());

        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - start).count();
        structured_logger_->log_phase_complete("Plugin Analysis", elapsed);
        Logger::instance().info("  Phase 16 complete: " +
            std::to_string(plugin_findings.size()) + " findings from " +
            std::to_string(plugin_manager_->list_active_plugins().size()) +
            " plugins (" + std::to_string(elapsed) + "ms)");
        phases_completed_++;
    }

    // --- Phase 17: P2P Network Analysis ---
    void phase_17_p2p_analysis(const TranslationUnit& tu) {
        Logger::instance().info("=== Phase 17: P2P Network Analysis ===");
        structured_logger_->log_phase_start("P2P Network Analysis");
        auto start = std::chrono::steady_clock::now();
        progress_->advance_phase("P2P Network");

        if (!signal_manager_->is_component_enabled("p2p_testing")) {
            Logger::instance().info("  Phase 17 skipped (degraded mode)");
            return;
        }

        // Peer behavior verification
        auto peer_findings = p2p_harness_->verify_peer_behaviors(tu);
        phase3_findings_.insert(phase3_findings_.end(),
            peer_findings.begin(), peer_findings.end());

        // AddrMan verification
        auto addrman_findings = addrman_tester_->verify_addrman_patterns(tu);
        phase3_findings_.insert(phase3_findings_.end(),
            addrman_findings.begin(), addrman_findings.end());

        // Generate malformed message test catalog
        auto malformed = p2p_harness_->generate_malformed_messages();
        auto oversized = p2p_harness_->generate_oversized_messages();
        auto bad_checksum = p2p_harness_->generate_invalid_checksum_messages();
        Logger::instance().info("  Generated test messages: " +
            std::to_string(malformed.size()) + " malformed, " +
            std::to_string(oversized.size()) + " oversized, " +
            std::to_string(bad_checksum.size()) + " bad-checksum");

        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - start).count();
        structured_logger_->log_phase_complete("P2P Network Analysis", elapsed);
        Logger::instance().info("  Phase 17 complete: " +
            std::to_string(peer_findings.size() + addrman_findings.size()) +
            " findings (" + std::to_string(elapsed) + "ms)");
        phases_completed_++;
    }

    // --- Phase 18: Wallet Deep Analysis ---
    void phase_18_wallet_analysis(const TranslationUnit& tu) {
        Logger::instance().info("=== Phase 18: Wallet Deep Analysis ===");
        structured_logger_->log_phase_start("Wallet Deep Analysis");
        auto start = std::chrono::steady_clock::now();
        progress_->advance_phase("Wallet Analysis");

        if (!signal_manager_->is_component_enabled("wallet_analysis")) {
            Logger::instance().info("  Phase 18 skipped (degraded mode)");
            return;
        }

        auto wallet_findings = wallet_analyzer_->analyze_wallet_code(tu);
        phase3_findings_.insert(phase3_findings_.end(),
            wallet_findings.begin(), wallet_findings.end());

        auto tx_findings = tx_output_analyzer_->analyze_output_handling(tu);
        phase3_findings_.insert(phase3_findings_.end(),
            tx_findings.begin(), tx_findings.end());

        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - start).count();
        structured_logger_->log_phase_complete("Wallet Deep Analysis", elapsed);
        Logger::instance().info("  Phase 18 complete: " +
            std::to_string(wallet_findings.size() + tx_findings.size()) +
            " findings (" + std::to_string(elapsed) + "ms)");
        phases_completed_++;
    }

    // --- Phase 19: Mempool Pipeline Tracing ---
    void phase_19_mempool_tracing(const TranslationUnit& tu) {
        Logger::instance().info("=== Phase 19: Mempool Pipeline Tracing ===");
        structured_logger_->log_phase_start("Mempool Pipeline");
        auto start = std::chrono::steady_clock::now();
        progress_->advance_phase("Mempool Pipeline");

        if (!signal_manager_->is_component_enabled("mempool_tracing")) {
            Logger::instance().info("  Phase 19 skipped (degraded mode)");
            return;
        }

        // Run simulated traces
        for (int i = 0; i < 10; i++) {
            std::string txid = "sim_tx_" + std::to_string(i);
            mempool_tracer_->begin_trace(txid, 2, 2, 10000 + i * 1000, 250, i % 3 == 0);
            mempool_tracer_->trace_prevalidation(txid);
            mempool_tracer_->trace_context_free_checks();
            mempool_tracer_->trace_input_checking();
            mempool_tracer_->trace_script_verification();
            mempool_tracer_->trace_policy_checks();
            mempool_tracer_->trace_fee_validation();
            if (i % 3 == 0) mempool_tracer_->trace_rbf_validation();
            mempool_tracer_->trace_mempool_insertion();
            mempool_tracer_->complete_trace(i % 5 == 4 ? "rejected" : "accepted");
        }

        auto timing = mempool_tracer_->compute_timing_statistics();
        Logger::instance().info("  Trace timing: avg=" + std::to_string(timing.avg_us) +
            "us, p95=" + std::to_string(timing.p95_us) + "us");
        Logger::instance().info("  Bottleneck: " + mempool_tracer_->find_bottleneck_step());

        // Policy consistency
        auto policy_findings = mempool_policy_->verify_policy_consistency(tu);
        phase3_findings_.insert(phase3_findings_.end(),
            policy_findings.begin(), policy_findings.end());

        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - start).count();
        structured_logger_->log_phase_complete("Mempool Pipeline", elapsed);
        Logger::instance().info("  Phase 19 complete: " +
            std::to_string(mempool_tracer_->trace_count()) + " traces, " +
            std::to_string(policy_findings.size()) + " policy findings (" +
            std::to_string(elapsed) + "ms)");
        phases_completed_++;
    }

    // --- Phase 20: Report Validation, Quality Scoring & Finalization ---
    void phase_20_validate_and_finalize(
            const TranslationUnit& tu,
            std::vector<Finding>& all_findings,
            const std::string& output_dir) {
        Logger::instance().info("=== Phase 20: Report Validation & Finalization ===");
        structured_logger_->log_phase_start("Validation & Finalize");
        auto start = std::chrono::steady_clock::now();
        progress_->advance_phase("Finalization");

        // Merge Phase 3 findings
        all_findings.insert(all_findings.end(),
            phase3_findings_.begin(), phase3_findings_.end());

        // === Report Validation ===
        auto validation = report_validator_->validate_analysis(
            all_findings,
            {tu.file_path},
            {tu.file_path},
            phases_completed_,
            total_phases_);

        Logger::instance().info("  Validation: completeness=" +
            std::to_string(static_cast<int>(validation.completeness_score * 100)) +
            "%, accuracy=" +
            std::to_string(static_cast<int>(validation.accuracy_score * 100)) + "%");
        if (!validation.errors.empty())
            Logger::instance().warning("  Validation errors: " +
                std::to_string(validation.errors.size()));

        // Log validation details
        for (const auto& err : validation.errors)
            structured_logger_->log(StructuredLogger::ERROR_LVL, "validation", err);
        for (const auto& warn : validation.warnings)
            structured_logger_->log(StructuredLogger::WARNING_LVL, "validation", warn);

        // Gap detection
        auto gaps = report_validator_->detect_analysis_gaps();
        if (!gaps.empty()) {
            Logger::instance().info("  Analysis gaps detected: " +
                std::to_string(gaps.size()));
            for (const auto& gap : gaps) {
                if (gap.priority >= 7)
                    structured_logger_->log(StructuredLogger::WARNING_LVL, "gaps",
                        gap.category + ": " + gap.identifier + " — " + gap.reason_missed);
            }
        }

        // === Quality Scoring ===
        auto quality = quality_scorer_->compute_quality_scores(
            all_findings,
            static_cast<int>(get_call_graph().node_count()),
            static_cast<int>(get_call_graph().count_edges()),
            static_cast<int>(get_interprocedural_df().summary_count()),
            static_cast<int>(get_coverage_mutator().corpus_size()),
            static_cast<int>(get_state_validator().machine_count()),
            phases_completed_, total_phases_);

        Logger::instance().info(quality_scorer_->format_quality_report(quality));

        // === Persistence ===
        if (!output_dir.empty()) {
            std::filesystem::create_directories(output_dir);

            // Binary state
            persistence_->save_full_state(output_dir + "/state",
                all_findings, get_call_graph(), get_interprocedural_df(),
                get_cache(), get_coverage_mutator(), get_state_validator(),
                get_instrumentation(), quality.overall_quality_score);

            // JSON export
            {
                std::ofstream json_out(output_dir + "/findings.json");
                json_out << persistence_->export_findings_json(all_findings);
            }

            // Markdown report
            {
                std::ofstream md_out(output_dir + "/findings.md");
                md_out << persistence_->export_findings_markdown(all_findings);
            }

            // Sign-off report
            {
                std::ofstream signoff_out(output_dir + "/signoff.txt");
                signoff_out << report_validator_->generate_sign_off_report(validation);
            }

            // Quality report
            {
                std::ofstream quality_out(output_dir + "/quality.txt");
                quality_out << quality_scorer_->format_quality_report(quality);
            }

            // P2P test report
            {
                std::ofstream p2p_out(output_dir + "/p2p_report.txt");
                p2p_out << p2p_harness_->generate_p2p_report();
                p2p_out << addrman_tester_->generate_addrman_report();
            }

            // Mempool trace report
            {
                std::ofstream mempool_out(output_dir + "/mempool_report.txt");
                mempool_out << mempool_tracer_->generate_trace_report();
            }

            // Flamegraph data
            {
                std::ofstream fg_out(output_dir + "/mempool_flamegraph.txt");
                fg_out << mempool_tracer_->generate_flamegraph_data();
            }

            Logger::instance().info("  Reports saved to: " + output_dir);
        }

        // Final checkpoint
        checkpoint_->create_checkpoint("analysis_complete", phases_completed_);

        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - start).count();
        structured_logger_->log_phase_complete("Validation & Finalize", elapsed);
        Logger::instance().info("  Phase 20 complete (" + std::to_string(elapsed) + "ms)");
        phases_completed_++;
    }

    // --- Execute Complete 20-Phase Pipeline ---
    void execute_complete_pipeline(const TranslationUnit& tu,
                                    std::vector<Finding>& findings,
                                    const std::string& source_dir = "",
                                    const std::string& old_code = "",
                                    const std::string& new_code = "",
                                    const std::string& output_dir = "audit_output") {
        Logger::instance().info("================================================================");
        Logger::instance().info("CompleteVerificationOrchestrator: 20-Phase Security Pipeline");
        Logger::instance().info("================================================================");
        auto pipeline_start = std::chrono::steady_clock::now();

        // Initialize all subsystems
        initialize_phase3_subsystems();

        // Install signal handlers
        signal_manager_->install_all_handlers();
        signal_manager_->set_emergency_save_callback([this, &findings, &output_dir]() {
            Logger::instance().warning("EMERGENCY SAVE triggered");
            persistence_->save_full_state(output_dir + "/emergency_state",
                findings, get_call_graph(), get_interprocedural_df(),
                get_cache(), get_coverage_mutator(), get_state_validator(),
                get_instrumentation(), 0.0);
            checkpoint_->create_checkpoint("emergency_save", phases_completed_);
        });

        // Start watchdog and auto-checkpointing
        watchdog_->start_monitoring();
        checkpoint_->start_auto_checkpoint();

        // Progress registration
        progress_->register_task("complete_pipeline", "Full 20-Phase Audit",
            "orchestration", total_phases_);

        // ============================================================
        // Phases 1-15: Existing pipeline (Phase 1 + Phase 2)
        // ============================================================
        Logger::instance().info("--- Executing Phases 1-15 (existing pipeline) ---");
        execute_full_pipeline(tu, findings, source_dir, old_code, new_code);
        phases_completed_ = 15;
        progress_->update_progress("complete_pipeline", 15);

        // Create mid-pipeline checkpoint
        checkpoint_->create_checkpoint("phases_1_15_complete", 15);

        // ============================================================
        // Phase 16-20: New Phase 3 subsystems
        // ============================================================
        Logger::instance().info("--- Executing Phases 16-20 (Phase 3) ---");

        if (signal_manager_->can_continue_analysis()) {
            phase_16_plugin_analysis(tu);
            progress_->update_progress("complete_pipeline", 16);
        }

        if (signal_manager_->can_continue_analysis()) {
            phase_17_p2p_analysis(tu);
            progress_->update_progress("complete_pipeline", 17);
        }

        if (signal_manager_->can_continue_analysis()) {
            phase_18_wallet_analysis(tu);
            progress_->update_progress("complete_pipeline", 18);
        }

        if (signal_manager_->can_continue_analysis()) {
            phase_19_mempool_tracing(tu);
            progress_->update_progress("complete_pipeline", 19);
        }

        if (signal_manager_->can_continue_analysis()) {
            phase_20_validate_and_finalize(tu, findings, output_dir);
            progress_->update_progress("complete_pipeline", 20);
        }

        // ============================================================
        // Shutdown
        // ============================================================
        watchdog_->stop_monitoring();
        checkpoint_->stop_auto_checkpoint();
        signal_manager_->restore_default_handlers();
        structured_logger_->flush_all();

        auto pipeline_elapsed = std::chrono::duration_cast<std::chrono::seconds>(
            std::chrono::steady_clock::now() - pipeline_start).count();

        Logger::instance().info("================================================================");
        Logger::instance().info("Pipeline Complete: " +
            std::to_string(findings.size()) + " total findings");
        Logger::instance().info("  Phase 1 (original): " +
            std::to_string(findings.size() - phase3_findings_.size() -
                get_phase2_findings().size()) + " findings");
        Logger::instance().info("  Phase 2 (enhanced): " +
            std::to_string(get_phase2_findings().size()) + " findings");
        Logger::instance().info("  Phase 3 (complete): " +
            std::to_string(phase3_findings_.size()) + " findings");
        Logger::instance().info("  Phases completed: " +
            std::to_string(phases_completed_) + "/" + std::to_string(total_phases_));
        Logger::instance().info("  Duration: " +
            std::to_string(pipeline_elapsed) + "s");
        Logger::instance().info("================================================================");
    }

    // Accessors
    PluginManager& get_plugins() { return *plugin_manager_; }
    P2PTestHarness& get_p2p() { return *p2p_harness_; }
    WalletDeepAnalyzer& get_wallet() { return *wallet_analyzer_; }
    MempoolAcceptanceTracer& get_mempool_tracer() { return *mempool_tracer_; }
    ReportValidator& get_report_validator() { return *report_validator_; }
    AnalysisQualityScorer& get_quality_scorer() { return *quality_scorer_; }
    WatchdogSupervisor& get_watchdog() { return *watchdog_; }
    ProgressReporter& get_progress() { return *progress_; }
    AnalysisCheckpoint& get_checkpoint() { return *checkpoint_; }
    const std::vector<Finding>& get_phase3_findings() const { return phase3_findings_; }
};

// --- 73.2: Final Main Function ---

inline int run_complete_audit(int argc, char* argv[]) {
    Logger::instance().info("=== Bitcoin Core Security Audit Framework v3.0 ===");
    Logger::instance().info("  20-Phase Pipeline | Phase 1 + Phase 2 + Phase 3");
    Logger::instance().info("  Sections 1-73 fully integrated");

    // Parse arguments
    std::string target_file;
    std::string source_dir;
    std::string old_version_file;
    std::string new_version_file;
    std::string output_dir = "audit_output";
    std::string checkpoint_resume_id;
    bool verbose = false;

    for (int i = 1; i < argc; i++) {
        std::string arg = argv[i];
        if (arg == "--file" && i + 1 < argc) target_file = argv[++i];
        else if (arg == "--source-dir" && i + 1 < argc) source_dir = argv[++i];
        else if (arg == "--old-version" && i + 1 < argc) old_version_file = argv[++i];
        else if (arg == "--new-version" && i + 1 < argc) new_version_file = argv[++i];
        else if (arg == "--output" && i + 1 < argc) output_dir = argv[++i];
        else if (arg == "--resume" && i + 1 < argc) checkpoint_resume_id = argv[++i];
        else if (arg == "--verbose") verbose = true;
        else if (arg == "--help") {
            std::cout << "Bitcoin Core Security Audit Framework v3.0\n"
                      << "Usage: audit [options]\n"
                      << "  --file <path>         Target source file\n"
                      << "  --source-dir <path>   Source tree for coverage builds\n"
                      << "  --old-version <path>  Old version file for diff\n"
                      << "  --new-version <path>  New version file for diff\n"
                      << "  --output <path>       Output directory (default: audit_output)\n"
                      << "  --resume <id>         Resume from checkpoint\n"
                      << "  --verbose             Verbose output\n";
            return 0;
        }
    }

    if (target_file.empty()) {
        Logger::instance().error("No target file specified (use --file <path>)");
        return 1;
    }

    // Read target file
    std::ifstream target_stream(target_file);
    if (!target_stream.is_open()) {
        Logger::instance().error("Cannot open: " + target_file);
        return 1;
    }
    std::string file_content((std::istreambuf_iterator<char>(target_stream)),
                              std::istreambuf_iterator<char>());
    Logger::instance().info("Target: " + target_file +
        " (" + std::to_string(file_content.size()) + " bytes)");

    // Read old/new versions for diff (if provided)
    std::string old_code, new_code;
    if (!old_version_file.empty()) {
        std::ifstream f(old_version_file);
        old_code = std::string(std::istreambuf_iterator<char>(f), {});
    }
    if (!new_version_file.empty()) {
        std::ifstream f(new_version_file);
        new_code = std::string(std::istreambuf_iterator<char>(f), {});
    }

    // Build translation unit
    TranslationUnit tu;
    tu.file_path = target_file;
    tu.raw_source = file_content;
    SourceLexer lexer;
    tu.tokens = lexer.tokenize(file_content, target_file);
    Logger::instance().info("Lexer: " + std::to_string(tu.tokens.size()) + " tokens");

    // Create orchestrator and execute
    CompleteVerificationOrchestrator_Phase3 orchestrator;

    std::vector<Finding> all_findings;

    try {
        orchestrator.execute_complete_pipeline(
            tu, all_findings, source_dir, old_code, new_code, output_dir);
    } catch (const std::exception& e) {
        Logger::instance().error("Pipeline exception: " + std::string(e.what()));
        // Emergency save
        orchestrator.get_checkpoint().create_checkpoint("crash_save");
        return 2;
    }

    // Severity summary
    int critical = 0, high = 0, medium = 0, low = 0, info = 0;
    for (const auto& f : all_findings) {
        switch (f.severity) {
            case Severity::Critical: critical++; break;
            case Severity::High: high++; break;
            case Severity::Medium: medium++; break;
            case Severity::Low: low++; break;
            default: info++; break;
        }
    }

    Logger::instance().info("=== Final Severity Summary ===");
    Logger::instance().info("  Critical: " + std::to_string(critical));
    Logger::instance().info("  High:     " + std::to_string(high));
    Logger::instance().info("  Medium:   " + std::to_string(medium));
    Logger::instance().info("  Low:      " + std::to_string(low));
    Logger::instance().info("  Info:     " + std::to_string(info));
    Logger::instance().info("  Total:    " + std::to_string(all_findings.size()));

    if (verbose) {
        for (size_t i = 0; i < all_findings.size(); i++) {
            const auto& f = all_findings[i];
            Logger::instance().info("[" + std::to_string(i + 1) + "] " +
                f.function_name + " @ " + f.file + ":" +
                std::to_string(f.location.line) + " — " +
                f.detailed_description);
        }
    }

    Logger::instance().info("=== Audit Complete ===");
    Logger::instance().info("  Reports: " + output_dir);
    return (critical > 0) ? 2 : (high > 0) ? 1 : 0;
}

// ============================================================================
// SECTION 72: REPORT SELF-VALIDATION & COMPLETENESS
class ExecutionTimeline {
public:
    struct TimelineEntry {
        std::string phase_name;
        std::string sub_phase;
        std::chrono::steady_clock::time_point start;
        std::chrono::steady_clock::time_point end;
        size_t findings_before;
        size_t findings_after;
        size_t peak_memory_bytes;
        bool succeeded;
        std::string failure_reason;
    };

private:
    std::vector<TimelineEntry> entries_;
    std::mutex timeline_mutex_;
    std::chrono::steady_clock::time_point global_start_;
    std::map<std::string, std::vector<double>> phase_durations_history_;

public:
    ExecutionTimeline() : global_start_(std::chrono::steady_clock::now()) {}

    void record_phase_start(const std::string& phase, const std::string& sub_phase,
                            size_t current_findings) {
        std::lock_guard<std::mutex> lock(timeline_mutex_);
        TimelineEntry entry;
        entry.phase_name = phase;
        entry.sub_phase = sub_phase;
        entry.start = std::chrono::steady_clock::now();
        entry.findings_before = current_findings;
        entry.findings_after = current_findings;
        entry.peak_memory_bytes = 0;
        entry.succeeded = false;
        entries_.push_back(entry);
    }

    void record_phase_end(const std::string& phase, const std::string& sub_phase,
                          size_t current_findings, bool success,
                          const std::string& failure_reason = "") {
        std::lock_guard<std::mutex> lock(timeline_mutex_);
        for (auto it = entries_.rbegin(); it != entries_.rend(); ++it) {
            if (it->phase_name == phase && it->sub_phase == sub_phase && !it->succeeded) {
                it->end = std::chrono::steady_clock::now();
                it->findings_after = current_findings;
                it->succeeded = success;
                it->failure_reason = failure_reason;
                double dur = std::chrono::duration<double>(it->end - it->start).count();
                phase_durations_history_[phase].push_back(dur);
                return;
            }
        }
    }

    double get_total_elapsed_seconds() const {
        return std::chrono::duration<double>(
            std::chrono::steady_clock::now() - global_start_).count();
    }

    struct TimelineStatistics {
        double total_elapsed_seconds;
        size_t total_phases_executed;
        size_t phases_succeeded;
        size_t phases_failed;
        double slowest_phase_seconds;
        std::string slowest_phase_name;
        double fastest_phase_seconds;
        std::string fastest_phase_name;
        size_t total_findings_generated;
        double average_findings_per_phase;
        std::map<std::string, double> phase_time_percentage;
    };

    TimelineStatistics compute_statistics() const {
        TimelineStatistics stats{};
        stats.total_elapsed_seconds = get_total_elapsed_seconds();
        stats.total_phases_executed = entries_.size();
        stats.slowest_phase_seconds = 0;
        stats.fastest_phase_seconds = std::numeric_limits<double>::max();

        double total_phase_time = 0;
        std::map<std::string, double> phase_times;

        for (const auto& e : entries_) {
            double dur = std::chrono::duration<double>(e.end - e.start).count();
            if (e.succeeded) stats.phases_succeeded++;
            else stats.phases_failed++;

            if (dur > stats.slowest_phase_seconds) {
                stats.slowest_phase_seconds = dur;
                stats.slowest_phase_name = e.phase_name + "::" + e.sub_phase;
            }
            if (dur < stats.fastest_phase_seconds) {
                stats.fastest_phase_seconds = dur;
                stats.fastest_phase_name = e.phase_name + "::" + e.sub_phase;
            }

            size_t findings_delta = e.findings_after > e.findings_before ?
                e.findings_after - e.findings_before : 0;
            stats.total_findings_generated += findings_delta;
            phase_times[e.phase_name] += dur;
            total_phase_time += dur;
        }

        if (stats.total_phases_executed > 0) {
            stats.average_findings_per_phase =
                static_cast<double>(stats.total_findings_generated) / stats.total_phases_executed;
        }

        for (const auto& [name, time] : phase_times) {
            stats.phase_time_percentage[name] =
                total_phase_time > 0 ? (time / total_phase_time) * 100.0 : 0;
        }

        return stats;
    }

    std::string format_timeline_report() const {
        auto stats = compute_statistics();
        std::ostringstream oss;
        oss << "\n=== EXECUTION TIMELINE REPORT ===\n";
        oss << std::fixed << std::setprecision(3);
        oss << "Total wall-clock time:      " << stats.total_elapsed_seconds << "s\n";
        oss << "Phases executed:            " << stats.total_phases_executed << "\n";
        oss << "  Succeeded:                " << stats.phases_succeeded << "\n";
        oss << "  Failed:                   " << stats.phases_failed << "\n";
        oss << "Slowest phase:              " << stats.slowest_phase_name
            << " (" << stats.slowest_phase_seconds << "s)\n";
        if (stats.fastest_phase_seconds < std::numeric_limits<double>::max()) {
            oss << "Fastest phase:              " << stats.fastest_phase_name
                << " (" << stats.fastest_phase_seconds << "s)\n";
        }
        oss << "Total findings generated:   " << stats.total_findings_generated << "\n";
        oss << "Avg findings/phase:         " << stats.average_findings_per_phase << "\n";
        oss << "\nPhase time distribution:\n";
        for (const auto& [name, pct] : stats.phase_time_percentage) {
            oss << "  " << std::left << std::setw(30) << name
                << std::right << std::setw(6) << pct << "%\n";
        }

        oss << "\nDetailed timeline:\n";
        for (const auto& e : entries_) {
            double dur = std::chrono::duration<double>(e.end - e.start).count();
            oss << "  [" << (e.succeeded ? "OK" : "FAIL") << "] "
                << std::setw(25) << std::left << e.phase_name
                << std::setw(30) << e.sub_phase
                << std::right << std::setw(8) << dur << "s"
                << "  findings: " << e.findings_before << " -> " << e.findings_after;
            if (!e.succeeded && !e.failure_reason.empty()) {
                oss << "  reason: " << e.failure_reason;
            }
            oss << "\n";
        }
        return oss.str();
    }

    const std::vector<TimelineEntry>& entries() const { return entries_; }
};

// ---------------------------------------------------------------------------
// 73.2: DependencyResolver - topological ordering of analysis phases
// ---------------------------------------------------------------------------
class DependencyResolver {
public:
    struct PhaseDescriptor {
        std::string name;
        int phase_number;
        std::vector<std::string> depends_on;
        std::vector<std::string> provides;
        bool is_optional;
        int priority_weight;  // higher = run first among peers
        std::function<bool()> precondition_check;
    };

private:
    std::vector<PhaseDescriptor> phases_;
    std::map<std::string, size_t> name_to_index_;
    std::map<std::string, std::string> capability_provider_;  // capability -> phase name

public:
    void register_phase(const PhaseDescriptor& desc) {
        name_to_index_[desc.name] = phases_.size();
        for (const auto& cap : desc.provides) {
            capability_provider_[cap] = desc.name;
        }
        phases_.push_back(desc);
    }

    struct ResolutionResult {
        bool success;
        std::vector<std::string> execution_order;
        std::vector<std::string> skipped_phases;
        std::vector<std::string> unmet_dependencies;
        std::string cycle_description;
    };

    ResolutionResult resolve() const {
        ResolutionResult result;
        result.success = true;

        // Build adjacency list
        std::map<std::string, std::set<std::string>> adj;
        std::map<std::string, int> in_degree;
        for (const auto& p : phases_) {
            adj[p.name];  // ensure exists
            in_degree[p.name] += 0;
            for (const auto& dep : p.depends_on) {
                auto cap_it = capability_provider_.find(dep);
                if (cap_it != capability_provider_.end()) {
                    adj[cap_it->second].insert(p.name);
                    in_degree[p.name]++;
                } else {
                    // Direct phase name dependency
                    auto idx_it = name_to_index_.find(dep);
                    if (idx_it != name_to_index_.end()) {
                        adj[dep].insert(p.name);
                        in_degree[p.name]++;
                    } else {
                        result.unmet_dependencies.push_back(
                            p.name + " requires '" + dep + "' (not found)");
                        if (!p.is_optional) {
                            result.success = false;
                        } else {
                            result.skipped_phases.push_back(p.name);
                        }
                    }
                }
            }
        }

        // Check preconditions
        for (const auto& p : phases_) {
            if (p.precondition_check && !p.precondition_check()) {
                if (p.is_optional) {
                    result.skipped_phases.push_back(p.name);
                    // Remove from graph
                    in_degree.erase(p.name);
                    adj.erase(p.name);
                    for (auto& [k, v] : adj) v.erase(p.name);
                } else {
                    result.success = false;
                    result.unmet_dependencies.push_back(
                        p.name + " precondition check failed");
                }
            }
        }

        // Kahn's algorithm with priority-weighted selection
        std::set<std::string> skip_set(result.skipped_phases.begin(),
                                        result.skipped_phases.end());

        // Priority queue: (priority_weight, name)
        auto cmp = [&](const std::string& a, const std::string& b) {
            int pa = 0, pb = 0;
            auto ia = name_to_index_.find(a);
            auto ib = name_to_index_.find(b);
            if (ia != name_to_index_.end()) pa = phases_[ia->second].priority_weight;
            if (ib != name_to_index_.end()) pb = phases_[ib->second].priority_weight;
            return pa < pb;  // higher priority first
        };
        std::priority_queue<std::string, std::vector<std::string>, decltype(cmp)> queue(cmp);

        for (const auto& [name, deg] : in_degree) {
            if (deg == 0 && skip_set.find(name) == skip_set.end()) {
                queue.push(name);
            }
        }

        while (!queue.empty()) {
            std::string current = queue.top();
            queue.pop();
            result.execution_order.push_back(current);

            for (const auto& neighbor : adj[current]) {
                if (skip_set.find(neighbor) != skip_set.end()) continue;
                in_degree[neighbor]--;
                if (in_degree[neighbor] == 0) {
                    queue.push(neighbor);
                }
            }
        }

        // Cycle detection
        size_t expected = 0;
        for (const auto& p : phases_) {
            if (skip_set.find(p.name) == skip_set.end()) expected++;
        }
        if (result.execution_order.size() < expected) {
            result.success = false;
            result.cycle_description = "Circular dependency detected among: ";
            for (const auto& [name, deg] : in_degree) {
                if (deg > 0 && skip_set.find(name) == skip_set.end()) {
                    result.cycle_description += name + " ";
                }
            }
        }

        return result;
    }
};

// ---------------------------------------------------------------------------
// 73.3: AuditSessionManager - session lifecycle, crash recovery, resumption
// ---------------------------------------------------------------------------
class AuditSessionManager {
public:
    struct SessionState {
        std::string session_id;
        std::string start_time;
        std::string last_active_time;
        int last_completed_phase;
        int total_phases;
        size_t total_findings;
        size_t critical_findings;
        size_t high_findings;
        bool completed;
        bool aborted;
        std::string abort_reason;
        std::vector<std::string> completed_phase_names;
        std::map<std::string, std::string> phase_checksums;  // phase -> findings hash
        double total_elapsed_seconds;
        double quality_score;
    };

private:
    SessionState state_;
    AnalysisPersistenceLayer* persistence_;
    AnalysisCheckpoint* checkpoint_;
    std::mutex session_mutex_;

    std::string generate_session_id() {
        auto now = std::chrono::system_clock::now();
        auto epoch = now.time_since_epoch();
        auto millis = std::chrono::duration_cast<std::chrono::milliseconds>(epoch).count();
        std::ostringstream oss;
        oss << "AUDIT-" << std::hex << std::uppercase << millis;
        // Add random suffix
        std::mt19937 rng(static_cast<unsigned>(millis));
        std::uniform_int_distribution<int> dist(0, 15);
        for (int i = 0; i < 8; i++) {
            oss << "0123456789ABCDEF"[dist(rng)];
        }
        return oss.str();
    }

    std::string compute_findings_hash(const std::vector<Finding>& findings) {
        // Simple hash based on finding IDs and severity
        size_t hash = 0;
        for (const auto& f : findings) {
            hash = hash * 31 + static_cast<size_t>(f.finding_id);
            hash = hash * 31 + static_cast<int>(f.severity);
        }
        std::ostringstream oss;
        oss << std::hex << std::setw(16) << std::setfill('0') << hash;
        return oss.str();
    }

public:
    AuditSessionManager(AnalysisPersistenceLayer* persistence = nullptr,
                        AnalysisCheckpoint* checkpoint = nullptr)
        : persistence_(persistence), checkpoint_(checkpoint) {
        state_.session_id = generate_session_id();
        auto now = std::chrono::system_clock::now();
        auto time_t_now = std::chrono::system_clock::to_time_t(now);
        char buf[64];
        std::strftime(buf, sizeof(buf), "%Y-%m-%dT%H:%M:%SZ", std::gmtime(&time_t_now));
        state_.start_time = buf;
        state_.last_active_time = buf;
        state_.last_completed_phase = 0;
        state_.total_phases = 20;
        state_.total_findings = 0;
        state_.critical_findings = 0;
        state_.high_findings = 0;
        state_.completed = false;
        state_.aborted = false;
        state_.total_elapsed_seconds = 0;
        state_.quality_score = 0;
    }

    std::string session_id() const { return state_.session_id; }

    void mark_phase_complete(int phase_num, const std::string& phase_name,
                             const std::vector<Finding>& findings) {
        std::lock_guard<std::mutex> lock(session_mutex_);
        state_.last_completed_phase = phase_num;
        state_.completed_phase_names.push_back(phase_name);
        state_.total_findings = findings.size();
        state_.critical_findings = 0;
        state_.high_findings = 0;
        for (const auto& f : findings) {
            if (f.severity == Severity::Critical) state_.critical_findings++;
            if (f.severity == Severity::High) state_.high_findings++;
        }
        state_.phase_checksums[phase_name] = compute_findings_hash(findings);
        auto now = std::chrono::system_clock::now();
        auto time_t_now = std::chrono::system_clock::to_time_t(now);
        char buf[64];
        std::strftime(buf, sizeof(buf), "%Y-%m-%dT%H:%M:%SZ", std::gmtime(&time_t_now));
        state_.last_active_time = buf;

        // Persist checkpoint if available
        if (checkpoint_) {
            checkpoint_->create_checkpoint(phase_name);
        }
    }

    void mark_completed(double quality_score, double elapsed) {
        std::lock_guard<std::mutex> lock(session_mutex_);
        state_.completed = true;
        state_.quality_score = quality_score;
        state_.total_elapsed_seconds = elapsed;
    }

    void mark_aborted(const std::string& reason) {
        std::lock_guard<std::mutex> lock(session_mutex_);
        state_.aborted = true;
        state_.abort_reason = reason;
    }

    bool can_resume_from_checkpoint() const {
        if (!checkpoint_) return false;
        return state_.last_completed_phase > 0 && !state_.completed;
    }

    int get_resume_phase() const {
        return state_.last_completed_phase + 1;
    }

    SessionState get_state() const {
        std::lock_guard<std::mutex> lock(const_cast<std::mutex&>(session_mutex_));
        return state_;
    }

    std::string format_session_report() const {
        auto s = get_state();
        std::ostringstream oss;
        oss << "\n=== AUDIT SESSION REPORT ===\n";
        oss << "Session ID:           " << s.session_id << "\n";
        oss << "Started:              " << s.start_time << "\n";
        oss << "Last active:          " << s.last_active_time << "\n";
        oss << "Status:               ";
        if (s.completed) oss << "COMPLETED";
        else if (s.aborted) oss << "ABORTED (" << s.abort_reason << ")";
        else oss << "IN PROGRESS";
        oss << "\n";
        oss << "Phases completed:     " << s.last_completed_phase << "/" << s.total_phases << "\n";
        oss << "Total findings:       " << s.total_findings << "\n";
        oss << "  Critical:           " << s.critical_findings << "\n";
        oss << "  High:               " << s.high_findings << "\n";
        oss << std::fixed << std::setprecision(2);
        oss << "Quality score:        " << s.quality_score << "\n";
        oss << "Elapsed time:         " << s.total_elapsed_seconds << "s\n";
        oss << "\nCompleted phases:\n";
        for (const auto& name : s.completed_phase_names) {
            auto cs_it = s.phase_checksums.find(name);
            oss << "  [+] " << name;
            if (cs_it != s.phase_checksums.end()) {
                oss << "  (hash: " << cs_it->second << ")";
            }
            oss << "\n";
        }
        return oss.str();
    }
};

// ---------------------------------------------------------------------------
// 73.4: FindingsDeduplicator - cross-phase finding deduplication and merging
// ---------------------------------------------------------------------------
class FindingsDeduplicator {
public:
    struct DeduplicationStats {
        size_t total_input_findings;
        size_t unique_findings;
        size_t duplicates_removed;
        size_t findings_merged;
        size_t confidence_upgrades;
        std::map<std::string, int> duplicates_by_phase;
    };

private:
    struct FindingSignature {
        std::string file;
        int line;
        IssueType issue_type;
        std::string function_name;

        bool operator==(const FindingSignature& other) const {
            return file == other.file && line == other.line &&
                   issue_type == other.issue_type &&
                   function_name == other.function_name;
        }
    };

    struct SignatureHash {
        size_t operator()(const FindingSignature& sig) const {
            size_t h = std::hash<std::string>{}(sig.file);
            h ^= std::hash<int>{}(sig.line) << 1;
            h ^= std::hash<int>{}(static_cast<int>(sig.issue_type)) << 2;
            h ^= std::hash<std::string>{}(sig.function_name) << 3;
            return h;
        }
    };

    double similarity_threshold_;

    FindingSignature extract_signature(const Finding& f) const {
        return {f.file, static_cast<int>(f.location.line), f.issue_type, f.function_name};
    }

    Finding merge_findings(const Finding& existing, const Finding& duplicate) const {
        Finding merged = existing;
        // Take higher confidence
        if (duplicate.confidence > merged.confidence) {
            merged.confidence = duplicate.confidence;
        }
        if (duplicate.calibrated_severity > merged.calibrated_severity) {
            merged.calibrated_severity = duplicate.calibrated_severity;
        }
        // Merge evidence
        for (const auto& ev : duplicate.static_analysis_evidence) {
            if (std::find(merged.static_analysis_evidence.begin(),
                         merged.static_analysis_evidence.end(), ev) ==
                merged.static_analysis_evidence.end()) {
                merged.static_analysis_evidence.push_back(ev);
            }
        }
        for (const auto& dr : duplicate.dynamic_test_results) {
            if (std::find(merged.dynamic_test_results.begin(),
                         merged.dynamic_test_results.end(), dr) ==
                merged.dynamic_test_results.end()) {
                merged.dynamic_test_results.push_back(dr);
            }
        }
        // Merge data origins
        for (const auto& origin : duplicate.data_origin_points) {
            if (std::find(merged.data_origin_points.begin(),
                         merged.data_origin_points.end(), origin) ==
                merged.data_origin_points.end()) {
                merged.data_origin_points.push_back(origin);
            }
        }
        // Upgrade boolean flags
        merged.passed_through_move_semantics |= duplicate.passed_through_move_semantics;
        merged.passed_through_swap |= duplicate.passed_through_swap;
        merged.uses_secure_allocator |= duplicate.uses_secure_allocator;
        merged.secure_cleanup_performed |= duplicate.secure_cleanup_performed;
        merged.automatic_cleanup_available |= duplicate.automatic_cleanup_available;
        return merged;
    }

public:
    FindingsDeduplicator(double similarity_threshold = 0.85)
        : similarity_threshold_(similarity_threshold) {}

    std::pair<std::vector<Finding>, DeduplicationStats>
    deduplicate(const std::vector<Finding>& findings) const {
        DeduplicationStats stats{};
        stats.total_input_findings = findings.size();

        std::unordered_map<FindingSignature, size_t, SignatureHash> signature_map;
        std::vector<Finding> unique_findings;

        for (const auto& f : findings) {
            auto sig = extract_signature(f);
            auto it = signature_map.find(sig);

            if (it != signature_map.end()) {
                // Duplicate found - merge
                Finding& existing = unique_findings[it->second];
                bool had_lower_confidence = existing.confidence < f.confidence;
                existing = merge_findings(existing, f);
                stats.duplicates_removed++;
                stats.findings_merged++;
                if (had_lower_confidence) stats.confidence_upgrades++;
            } else {
                signature_map[sig] = unique_findings.size();
                unique_findings.push_back(f);
            }
        }

        stats.unique_findings = unique_findings.size();
        return {unique_findings, stats};
    }
};

// ---------------------------------------------------------------------------
// 73.5: EmergencyStopController - graceful shutdown with partial results
// ---------------------------------------------------------------------------
class EmergencyStopController {
public:
    enum class StopReason {
        UserRequested,
        MemoryExhaustion,
        TimeoutExceeded,
        CriticalError,
        SignalReceived,
        DiskFull,
        TooManyFindings
    };

private:
    std::atomic<bool> stop_requested_{false};
    std::atomic<StopReason> stop_reason_{StopReason::UserRequested};
    std::mutex callbacks_mutex_;
    std::vector<std::function<void(StopReason)>> on_stop_callbacks_;
    size_t max_findings_limit_;
    size_t max_memory_bytes_;
    double max_elapsed_seconds_;
    std::chrono::steady_clock::time_point start_time_;

public:
    EmergencyStopController(size_t max_findings = 100000,
                            size_t max_memory_mb = 4096,
                            double max_seconds = 3600.0)
        : max_findings_limit_(max_findings),
          max_memory_bytes_(max_memory_mb * 1024 * 1024),
          max_elapsed_seconds_(max_seconds),
          start_time_(std::chrono::steady_clock::now()) {}

    void register_callback(std::function<void(StopReason)> cb) {
        std::lock_guard<std::mutex> lock(callbacks_mutex_);
        on_stop_callbacks_.push_back(std::move(cb));
    }

    void request_stop(StopReason reason) {
        stop_reason_.store(reason);
        stop_requested_.store(true);
        std::lock_guard<std::mutex> lock(callbacks_mutex_);
        for (auto& cb : on_stop_callbacks_) {
            try { cb(reason); } catch (...) {}
        }
    }

    bool should_stop() const { return stop_requested_.load(); }
    StopReason get_stop_reason() const { return stop_reason_.load(); }

    // Check resource limits
    void check_limits(size_t current_findings, size_t current_memory_bytes) {
        if (current_findings > max_findings_limit_) {
            request_stop(StopReason::TooManyFindings);
        }
        if (current_memory_bytes > max_memory_bytes_) {
            request_stop(StopReason::MemoryExhaustion);
        }
        double elapsed = std::chrono::duration<double>(
            std::chrono::steady_clock::now() - start_time_).count();
        if (elapsed > max_elapsed_seconds_) {
            request_stop(StopReason::TimeoutExceeded);
        }
    }

    std::string stop_reason_string() const {
        switch (get_stop_reason()) {
            case StopReason::UserRequested: return "User requested stop";
            case StopReason::MemoryExhaustion: return "Memory exhaustion";
            case StopReason::TimeoutExceeded: return "Timeout exceeded";
            case StopReason::CriticalError: return "Critical error";
            case StopReason::SignalReceived: return "Signal received";
            case StopReason::DiskFull: return "Disk full";
            case StopReason::TooManyFindings: return "Too many findings (limit reached)";
        }
        return "Unknown";
    }
};

// ---------------------------------------------------------------------------
// 73.6: CompleteVerificationOrchestrator
// Extends Phase 2 with Phases 16-20 for full 20-phase pipeline
// ---------------------------------------------------------------------------
class CompleteVerificationOrchestrator {
public:
    struct Phase3Config {
        // P2P testing config
        bool enable_p2p_testing;
        int p2p_stress_connections;
        int p2p_stress_messages;
        bool p2p_test_eclipse_resistance;

        // Wallet analysis config
        bool enable_wallet_analysis;
        bool wallet_check_encryption;
        bool wallet_check_coin_selection;
        bool wallet_check_privacy;

        // Mempool config
        bool enable_mempool_tracing;
        bool mempool_check_rbf;
        bool mempool_check_cpfp;
        bool mempool_check_v3;
        int mempool_pipeline_steps;

        // Report validation config
        bool enable_report_validation;
        double minimum_quality_score;
        bool require_sign_off;

        // Persistence config
        bool enable_persistence;
        std::string persistence_path;
        bool enable_checkpointing;
        std::string checkpoint_path;
        std::string output_directory;

        // Resource limits
        size_t max_findings;
        size_t max_memory_mb;
        double max_elapsed_seconds;
        int max_retries_per_phase;

        Phase3Config()
            : enable_p2p_testing(true), p2p_stress_connections(50),
              p2p_stress_messages(1000), p2p_test_eclipse_resistance(true),
              enable_wallet_analysis(true), wallet_check_encryption(true),
              wallet_check_coin_selection(true), wallet_check_privacy(true),
              enable_mempool_tracing(true), mempool_check_rbf(true),
              mempool_check_cpfp(true), mempool_check_v3(true),
              mempool_pipeline_steps(20),
              enable_report_validation(true), minimum_quality_score(0.60),
              require_sign_off(true),
              enable_persistence(true), persistence_path("./audit_state"),
              enable_checkpointing(true), checkpoint_path("./audit_checkpoints"),
              output_directory("./audit_output"),
              max_findings(100000), max_memory_mb(4096),
              max_elapsed_seconds(7200.0), max_retries_per_phase(3) {}
    };

private:
    Phase3Config config_;
    std::vector<Finding> all_findings_;
    ExecutionTimeline timeline_;
    AuditSessionManager session_manager_;
    FindingsDeduplicator deduplicator_;
    EmergencyStopController stop_controller_;
    DependencyResolver dep_resolver_;
    ProgressReporter progress_;
    StructuredLogger structured_logger_;

    // Phase 3 subsystems
    std::unique_ptr<P2PTestHarness> p2p_harness_;
    std::unique_ptr<WalletDeepAnalyzer> wallet_analyzer_;
    std::unique_ptr<MempoolAcceptanceTracer> mempool_tracer_;
    std::unique_ptr<MempoolPolicyConsistency> mempool_policy_;
    std::unique_ptr<ReportValidator> report_validator_;
    std::unique_ptr<AnalysisQualityScorer> quality_scorer_;
    std::unique_ptr<AnalysisPersistenceLayer> persistence_;
    std::unique_ptr<AnalysisCheckpoint> checkpoint_;
    std::unique_ptr<PluginManager> plugin_manager_;
    std::unique_ptr<WatchdogSupervisor> watchdog_;

    // Phase execution with retry logic
    bool execute_phase_with_retry(const std::string& phase_name,
                                   std::function<void()> phase_fn,
                                   int max_retries) {
        for (int attempt = 0; attempt <= max_retries; attempt++) {
            if (stop_controller_.should_stop()) {
                structured_logger_.log("WARN", phase_name,
                    "Emergency stop requested, skipping phase");
                return false;
            }

            try {
                std::string sub = attempt > 0 ?
                    "attempt_" + std::to_string(attempt + 1) : "primary";
                timeline_.record_phase_start(phase_name, sub, all_findings_.size());

                phase_fn();

                timeline_.record_phase_end(phase_name, sub,
                    all_findings_.size(), true);
                session_manager_.mark_phase_complete(
                    0, phase_name, all_findings_);
                return true;
            } catch (const std::exception& e) {
                std::string sub = attempt > 0 ?
                    "attempt_" + std::to_string(attempt + 1) : "primary";
                timeline_.record_phase_end(phase_name, sub,
                    all_findings_.size(), false, e.what());
                structured_logger_.log("ERROR", phase_name,
                    "Phase failed: " + std::string(e.what()) +
                    (attempt < max_retries ? " (retrying)" : " (giving up)"));

                if (attempt == max_retries) return false;
                // Brief pause before retry
                std::this_thread::sleep_for(
                    std::chrono::milliseconds(100 * (attempt + 1)));
            }
        }
        return false;
    }

    void merge_findings(const std::vector<Finding>& new_findings) {
        all_findings_.insert(all_findings_.end(),
            new_findings.begin(), new_findings.end());
        stop_controller_.check_limits(all_findings_.size(), 0);
    }

public:
    CompleteVerificationOrchestrator(const Phase3Config& config = Phase3Config())
        : config_(config),
          stop_controller_(config.max_findings, config.max_memory_mb,
                           config.max_elapsed_seconds),
          progress_(20) {

        // Initialize subsystems
        p2p_harness_ = std::make_unique<P2PTestHarness>();
        wallet_analyzer_ = std::make_unique<WalletDeepAnalyzer>();
        mempool_tracer_ = std::make_unique<MempoolAcceptanceTracer>();
        mempool_policy_ = std::make_unique<MempoolPolicyConsistency>();
        report_validator_ = std::make_unique<ReportValidator>();
        quality_scorer_ = std::make_unique<AnalysisQualityScorer>();
        plugin_manager_ = std::make_unique<PluginManager>();
        register_standard_plugins(*plugin_manager_);

        if (config_.enable_persistence) {
            persistence_ = std::make_unique<AnalysisPersistenceLayer>(
                config_.persistence_path);
        }
        if (config_.enable_checkpointing) {
            checkpoint_ = std::make_unique<AnalysisCheckpoint>(
                config_.checkpoint_path, 300);
        }

        watchdog_ = std::make_unique<WatchdogSupervisor>(
            static_cast<int>(config_.max_elapsed_seconds));

        // Register dependency graph for phases 16-20
        register_phase_dependencies();
    }

    void register_phase_dependencies() {
        dep_resolver_.register_phase({
            "phase_16_p2p", 16, {"network_analysis"}, {"p2p_findings"},
            !config_.enable_p2p_testing, 10, nullptr});
        dep_resolver_.register_phase({
            "phase_17_wallet", 17, {"data_flow"}, {"wallet_findings"},
            !config_.enable_wallet_analysis, 10, nullptr});
        dep_resolver_.register_phase({
            "phase_18_mempool", 18, {"transaction_analysis"}, {"mempool_findings"},
            !config_.enable_mempool_tracing, 10, nullptr});
        dep_resolver_.register_phase({
            "phase_19_validation", 19,
            {"p2p_findings", "wallet_findings", "mempool_findings"},
            {"validated_report"}, !config_.enable_report_validation, 5, nullptr});
        dep_resolver_.register_phase({
            "phase_20_finalization", 20, {"validated_report"},
            {"final_output"}, false, 1, nullptr});
    }

    // Import findings from Phases 1-15
    void import_prior_findings(const std::vector<Finding>& prior_findings) {
        all_findings_ = prior_findings;
        structured_logger_.log("INFO", "orchestrator",
            "Imported " + std::to_string(prior_findings.size()) +
            " findings from phases 1-15");
    }

    // ---- PHASE 16: P2P Network Testing ----
    void execute_phase_16() {
        if (!config_.enable_p2p_testing) {
            structured_logger_.log("INFO", "phase_16", "P2P testing disabled, skipping");
            progress_.complete_phase("Phase 16: P2P Testing (skipped)");
            return;
        }

        execute_phase_with_retry("phase_16_p2p_testing", [this]() {
            structured_logger_.log("INFO", "phase_16", "Starting P2P network test harness");

            // Run comprehensive P2P tests
            p2p_harness_->run_all_tests();
            auto p2p_findings = p2p_harness_->generate_findings();

            // Additional stress testing
            if (config_.p2p_test_eclipse_resistance) {
                structured_logger_.log("INFO", "phase_16",
                    "Running eclipse resistance tests");
                p2p_harness_->test_eclipse_resistance();

                // Connection flood stress test
                p2p_harness_->stress_test_connection_flood(
                    config_.p2p_stress_connections);

                // Message flood stress test
                p2p_harness_->stress_test_message_flood(
                    config_.p2p_stress_messages);

                // Partial message attack
                p2p_harness_->stress_test_partial_message_attack();
            }

            // Regenerate findings after stress tests
            p2p_findings = p2p_harness_->generate_findings();
            merge_findings(p2p_findings);

            structured_logger_.log("INFO", "phase_16",
                "P2P testing complete: " + std::to_string(p2p_findings.size()) + " findings");
        }, config_.max_retries_per_phase);

        progress_.complete_phase("Phase 16: P2P Network Testing");
    }

    // ---- PHASE 17: Wallet Deep Analysis ----
    void execute_phase_17() {
        if (!config_.enable_wallet_analysis) {
            structured_logger_.log("INFO", "phase_17", "Wallet analysis disabled, skipping");
            progress_.complete_phase("Phase 17: Wallet Analysis (skipped)");
            return;
        }

        execute_phase_with_retry("phase_17_wallet_analysis", [this]() {
            structured_logger_.log("INFO", "phase_17",
                "Starting wallet deep analysis");

            std::vector<Finding> wallet_findings;

            // HD derivation path verification
            auto derivation_findings = wallet_analyzer_->verify_hd_derivation_paths();
            wallet_findings.insert(wallet_findings.end(),
                derivation_findings.begin(), derivation_findings.end());

            // Address gap limit analysis
            auto gap_findings = wallet_analyzer_->analyze_address_gap_limits();
            wallet_findings.insert(wallet_findings.end(),
                gap_findings.begin(), gap_findings.end());

            // Descriptor wallet validation
            auto desc_findings = wallet_analyzer_->validate_descriptor_wallets();
            wallet_findings.insert(wallet_findings.end(),
                desc_findings.begin(), desc_findings.end());

            // Coin selection analysis
            if (config_.wallet_check_coin_selection) {
                auto coin_findings = wallet_analyzer_->analyze_coin_selection();
                wallet_findings.insert(wallet_findings.end(),
                    coin_findings.begin(), coin_findings.end());
            }

            // Encryption analysis
            if (config_.wallet_check_encryption) {
                auto enc_findings = wallet_analyzer_->analyze_wallet_encryption();
                wallet_findings.insert(wallet_findings.end(),
                    enc_findings.begin(), enc_findings.end());
            }

            // Transaction output analysis (includes privacy)
            auto output_findings = wallet_analyzer_->analyze_transaction_outputs();
            wallet_findings.insert(wallet_findings.end(),
                output_findings.begin(), output_findings.end());

            merge_findings(wallet_findings);

            structured_logger_.log("INFO", "phase_17",
                "Wallet analysis complete: " + std::to_string(wallet_findings.size()) + " findings");
        }, config_.max_retries_per_phase);

        progress_.complete_phase("Phase 17: Wallet Deep Analysis");
    }

    // ---- PHASE 18: Mempool Tracing & Policy Consistency ----
    void execute_phase_18() {
        if (!config_.enable_mempool_tracing) {
            structured_logger_.log("INFO", "phase_18", "Mempool tracing disabled, skipping");
            progress_.complete_phase("Phase 18: Mempool Tracing (skipped)");
            return;
        }

        execute_phase_with_retry("phase_18_mempool_tracing", [this]() {
            structured_logger_.log("INFO", "phase_18",
                "Starting mempool acceptance tracing and policy analysis");

            // Trace the mempool acceptance pipeline
            for (int step = 0; step < config_.mempool_pipeline_steps; step++) {
                std::string step_name = "pipeline_step_" + std::to_string(step);
                mempool_tracer_->trace_step(step_name);
            }

            // Package tracing
            mempool_tracer_->trace_package("test_package_rbf", 3);
            mempool_tracer_->trace_package("test_package_cpfp", 2);
            mempool_tracer_->trace_package("test_package_v3", 1);

            auto tracer_findings = mempool_tracer_->generate_findings();

            // Policy consistency checks
            std::vector<Finding> policy_findings;

            if (config_.mempool_check_rbf) {
                auto rbf = mempool_policy_->check_rbf_rules();
                policy_findings.insert(policy_findings.end(), rbf.begin(), rbf.end());
            }
            if (config_.mempool_check_cpfp) {
                auto cpfp = mempool_policy_->check_cpfp_rules();
                policy_findings.insert(policy_findings.end(), cpfp.begin(), cpfp.end());
            }
            if (config_.mempool_check_v3) {
                auto v3 = mempool_policy_->check_v3_transaction_rules();
                policy_findings.insert(policy_findings.end(), v3.begin(), v3.end());
            }

            // Pinning attack surface analysis
            auto pinning = mempool_policy_->analyze_pinning_attack_surface();
            policy_findings.insert(policy_findings.end(),
                pinning.begin(), pinning.end());

            // Fee market analysis
            auto fee_market = mempool_policy_->analyze_fee_market();
            policy_findings.insert(policy_findings.end(),
                fee_market.begin(), fee_market.end());

            // Merge all mempool findings
            merge_findings(tracer_findings);
            merge_findings(policy_findings);

            structured_logger_.log("INFO", "phase_18",
                "Mempool analysis complete: " +
                std::to_string(tracer_findings.size() + policy_findings.size()) +
                " findings");
        }, config_.max_retries_per_phase);

        progress_.complete_phase("Phase 18: Mempool Tracing & Policy");
    }

    // ---- PHASE 19: Report Validation & Quality Scoring ----
    void execute_phase_19() {
        if (!config_.enable_report_validation) {
            structured_logger_.log("INFO", "phase_19",
                "Report validation disabled, skipping");
            progress_.complete_phase("Phase 19: Report Validation (skipped)");
            return;
        }

        execute_phase_with_retry("phase_19_report_validation", [this]() {
            structured_logger_.log("INFO", "phase_19",
                "Starting report validation and quality scoring");

            // Deduplicate findings across all phases
            auto [deduped, dedup_stats] = deduplicator_.deduplicate(all_findings_);
            structured_logger_.log("INFO", "phase_19",
                "Deduplication: " + std::to_string(dedup_stats.total_input_findings) +
                " -> " + std::to_string(dedup_stats.unique_findings) +
                " (" + std::to_string(dedup_stats.duplicates_removed) + " duplicates)");
            all_findings_ = deduped;

            // Run report validator
            auto report = report_validator_->validate_report(all_findings_);
            structured_logger_.log("INFO", "phase_19",
                "Validation: valid=" + std::string(report.is_valid ? "OK" : "FAIL") +
                " completeness=" + std::to_string(int(report.completeness_score * 100)) + "%" +
                " errors=" + std::to_string(report.errors.size()));

            // Quality scoring
            auto quality = quality_scorer_->score_analysis(all_findings_);
            structured_logger_.log("INFO", "phase_19",
                "Quality score: " + std::to_string(quality.overall_quality_score));

            // Check if quality meets threshold
            if (quality.overall_quality_score < config_.minimum_quality_score) {
                Finding quality_warning;
                quality_warning.finding_id = IDGenerator::instance().next();
                quality_warning.severity = Severity::High;
                quality_warning.confidence = 1.0;
                quality_warning.detailed_description =
                    "Analysis quality score (" +
                    std::to_string(quality.overall_quality_score) +
                    ") below minimum threshold (" +
                    std::to_string(config_.minimum_quality_score) + ")";
                quality_warning.file = "audit_framework";
                quality_warning.function_name = "quality_assessment";
                quality_warning.issue_type = IssueType::LogicError;
                all_findings_.push_back(quality_warning);
            }

            // Module coverage gap detection
            auto gaps = report_validator_->detect_coverage_gaps(all_findings_);
            for (const auto& gap : gaps) {
                structured_logger_.log("WARN", "phase_19",
                    "Coverage gap: " + gap.category + " / " + gap.identifier +
                    " (" + gap.reason_missed + ")");
            }

            // Sign-off determination
            if (config_.require_sign_off) {
                bool can_sign = report_validator_->determine_sign_off(all_findings_);
                structured_logger_.log("INFO", "phase_19",
                    "Sign-off determination: " +
                    std::string(can_sign ? "APPROVED" : "REQUIRES REVIEW"));
            }
        }, config_.max_retries_per_phase);

        progress_.complete_phase("Phase 19: Report Validation");
    }

    // ---- PHASE 20: Finalization ----
    void execute_phase_20() {
        execute_phase_with_retry("phase_20_finalization", [this]() {
            structured_logger_.log("INFO", "phase_20",
                "Starting finalization");

            // Run registered plugins
            plugin_manager_->run_all_plugins(all_findings_);

            // Persist final state
            if (persistence_) {
                structured_logger_.log("INFO", "phase_20",
                    "Persisting analysis state");
                persistence_->save_findings(config_.output_directory, all_findings_);
                persistence_->save_metadata(config_.output_directory, "session_id",
                    session_manager_.session_id());
                persistence_->save_metadata(config_.output_directory, "total_findings",
                    std::to_string(all_findings_.size()));
            }

            // Final checkpoint
            if (checkpoint_) {
                checkpoint_->save_checkpoint("phase_20_final");
            }

            // Final quality assessment
            auto final_quality = quality_scorer_->score_analysis(all_findings_);
            std::string quality_report =
                quality_scorer_->format_quality_report(final_quality);
            structured_logger_.log("INFO", "phase_20", quality_report);

            // Session completion
            session_manager_.mark_completed(
                final_quality.overall_quality_score,
                timeline_.get_total_elapsed_seconds());

            structured_logger_.log("INFO", "phase_20",
                "Finalization complete. Total findings: " +
                std::to_string(all_findings_.size()));
        }, config_.max_retries_per_phase);

        progress_.complete_phase("Phase 20: Finalization");
    }

    // ---- Full Phase 3 execution (16-20) ----
    void execute_phase3() {
        structured_logger_.log("INFO", "orchestrator",
            "=== PHASE 3 EXECUTION START (Phases 16-20) ===");
        structured_logger_.log("INFO", "orchestrator",
            "Session: " + session_manager_.session_id());
        structured_logger_.log("INFO", "orchestrator",
            "Input findings from phases 1-15: " +
            std::to_string(all_findings_.size()));

        // Resolve dependencies
        auto resolution = dep_resolver_.resolve();
        if (!resolution.success && !resolution.cycle_description.empty()) {
            structured_logger_.log("ERROR", "orchestrator",
                "Dependency resolution failed: " + resolution.cycle_description);
        }

        // Start watchdog
        watchdog_->start();

        // Execute phases in order
        execute_phase_16();
        if (stop_controller_.should_stop()) goto emergency_stop;

        execute_phase_17();
        if (stop_controller_.should_stop()) goto emergency_stop;

        execute_phase_18();
        if (stop_controller_.should_stop()) goto emergency_stop;

        execute_phase_19();
        if (stop_controller_.should_stop()) goto emergency_stop;

        execute_phase_20();

        watchdog_->stop();

        // Print final reports
        structured_logger_.log("INFO", "orchestrator",
            "=== PHASE 3 EXECUTION COMPLETE ===");
        structured_logger_.log("INFO", "orchestrator",
            session_manager_.format_session_report());
        structured_logger_.log("INFO", "orchestrator",
            timeline_.format_timeline_report());
        return;

    emergency_stop:
        watchdog_->stop();
        session_manager_.mark_aborted(stop_controller_.stop_reason_string());
        structured_logger_.log("WARN", "orchestrator",
            "=== EMERGENCY STOP: " + stop_controller_.stop_reason_string() + " ===");
        structured_logger_.log("INFO", "orchestrator",
            "Partial results saved. " + std::to_string(all_findings_.size()) +
            " findings collected before stop.");

        // Still persist what we have
        if (persistence_) {
            persistence_->save_findings(config_.output_directory, all_findings_);
        }
        if (checkpoint_) {
            checkpoint_->save_checkpoint("emergency_stop");
        }
    }

    // ---- Complete 20-phase audit (1-20) ----
    void run_complete_audit(const std::vector<std::string>& source_paths,
                             const std::string& target_version = "28.0") {
        structured_logger_.log("INFO", "orchestrator",
            "========================================================");
        structured_logger_.log("INFO", "orchestrator",
            "  BITCOIN CORE COMPREHENSIVE SECURITY AUDIT");
        structured_logger_.log("INFO", "orchestrator",
            "  Framework: btc_audit::enhanced_verification v3.2");
        structured_logger_.log("INFO", "orchestrator",
            "  Target: Bitcoin Core " + target_version);
        structured_logger_.log("INFO", "orchestrator",
            "  Session: " + session_manager_.session_id());
        structured_logger_.log("INFO", "orchestrator",
            "  Source paths: " + std::to_string(source_paths.size()) + " directories");
        structured_logger_.log("INFO", "orchestrator",
            "  Max findings: " + std::to_string(config_.max_findings));
        structured_logger_.log("INFO", "orchestrator",
            "  Max memory: " + std::to_string(config_.max_memory_mb) + " MB");
        structured_logger_.log("INFO", "orchestrator",
            "  Max time: " + std::to_string(config_.max_elapsed_seconds) + "s");
        structured_logger_.log("INFO", "orchestrator",
            "========================================================");

        // Phases 1-15 would be invoked here via Phase 1 and Phase 2 orchestrators.
        // For the complete pipeline, assume they've already run and findings imported.
        // In production, this would be:
        //   EnhancedVerificationOrchestrator phase1;
        //   phase1.run_11_phase_pipeline(source_paths);
        //   EnhancedVerificationOrchestrator_Phase2 phase2;
        //   phase2.run_phase2_audit(source_paths, phase1.get_findings());
        //   import_prior_findings(phase2.get_all_findings());

        // Execute Phase 3
        execute_phase3();
    }

    const std::vector<Finding>& get_all_findings() const { return all_findings_; }
    size_t finding_count() const { return all_findings_.size(); }
    const ExecutionTimeline& get_timeline() const { return timeline_; }
    const AuditSessionManager& get_session() const { return session_manager_; }
};

// ---------------------------------------------------------------------------
// 73.7: Phase3IntegrationVerifier - verify all Phase 3 subsystems
// ---------------------------------------------------------------------------
class Phase3IntegrationVerifier {
public:
    struct VerificationResult {
        bool all_passed;
        int total_checks;
        int passed_checks;
        int failed_checks;
        std::vector<std::string> failures;
        std::vector<std::string> warnings;
    };

    VerificationResult verify_all() {
        VerificationResult result;
        result.all_passed = true;
        result.total_checks = 0;
        result.passed_checks = 0;
        result.failed_checks = 0;

        // Check 1: P2PTestHarness instantiation
        check(result, "P2PTestHarness_create", [&]() {
            P2PTestHarness harness;
            return true;
        });

        // Check 2: WalletDeepAnalyzer instantiation
        check(result, "WalletDeepAnalyzer_create", [&]() {
            WalletDeepAnalyzer analyzer;
            return true;
        });

        // Check 3: MempoolAcceptanceTracer instantiation
        check(result, "MempoolAcceptanceTracer_create", [&]() {
            MempoolAcceptanceTracer tracer;
            return true;
        });

        // Check 4: MempoolPolicyConsistency instantiation
        check(result, "MempoolPolicyConsistency_create", [&]() {
            MempoolPolicyConsistency policy;
            return true;
        });

        // Check 5: ReportValidator instantiation
        check(result, "ReportValidator_create", [&]() {
            ReportValidator validator;
            return true;
        });

        // Check 6: AnalysisQualityScorer instantiation
        check(result, "AnalysisQualityScorer_create", [&]() {
            AnalysisQualityScorer scorer;
            return true;
        });

        // Check 7: PluginManager + standard plugins
        check(result, "PluginManager_standard_plugins", [&]() {
            PluginManager pm;
            register_standard_plugins(pm);
            return true;
        });

        // Check 8: ExecutionTimeline
        check(result, "ExecutionTimeline_create", [&]() {
            ExecutionTimeline timeline;
            timeline.record_phase_start("test", "sub", 0);
            timeline.record_phase_end("test", "sub", 5, true);
            auto stats = timeline.compute_statistics();
            return stats.total_phases_executed == 1;
        });

        // Check 9: DependencyResolver
        check(result, "DependencyResolver_resolve", [&]() {
            DependencyResolver resolver;
            resolver.register_phase({"a", 1, {}, {"cap_a"}, false, 10, nullptr});
            resolver.register_phase({"b", 2, {"cap_a"}, {"cap_b"}, false, 5, nullptr});
            auto res = resolver.resolve();
            return res.success && res.execution_order.size() == 2 &&
                   res.execution_order[0] == "a";
        });

        // Check 10: FindingsDeduplicator
        check(result, "FindingsDeduplicator_dedup", [&]() {
            FindingsDeduplicator dedup;
            Finding f1, f2;
            f1.finding_id = 1001; f1.file = "test.cpp";
            f1.location.line = 10; f1.issue_type = IssueType::BufferOverflow;
            f1.function_name = "foo"; f1.confidence = 0.5;
            f2 = f1; f2.finding_id = 1002; f2.confidence = 0.8; // duplicate with higher confidence
            auto [unique, stats] = dedup.deduplicate({f1, f2});
            return unique.size() == 1 && unique[0].confidence >= 0.8;
        });

        // Check 11: EmergencyStopController
        check(result, "EmergencyStopController_limits", [&]() {
            EmergencyStopController ctrl(10, 1024, 3600);
            ctrl.check_limits(5, 0);
            if (ctrl.should_stop()) return false;
            ctrl.check_limits(15, 0);  // exceeds limit
            return ctrl.should_stop();
        });

        // Check 12: AuditSessionManager
        check(result, "AuditSessionManager_lifecycle", [&]() {
            AuditSessionManager session;
            auto state = session.get_state();
            return !state.session_id.empty() && !state.completed;
        });

        // Check 13: CompleteVerificationOrchestrator instantiation
        check(result, "CompleteVerificationOrchestrator_create", [&]() {
            CompleteVerificationOrchestrator::Phase3Config cfg;
            CompleteVerificationOrchestrator orch(cfg);
            return true;
        });

        // Check 14: AnalysisPersistenceLayer
        check(result, "AnalysisPersistenceLayer_create", [&]() {
            AnalysisPersistenceLayer persistence("/tmp/test_audit_persist");
            return true;
        });

        // Check 15: WatchdogSupervisor
        check(result, "WatchdogSupervisor_create", [&]() {
            WatchdogSupervisor watchdog(60);
            return true;
        });

        // Check 16: ProgressReporter
        check(result, "ProgressReporter_phases", [&]() {
            ProgressReporter progress(5);
            progress.complete_phase("test1");
            return true;
        });

        // Check 17: StructuredLogger
        check(result, "StructuredLogger_output", [&]() {
            StructuredLogger logger;
            logger.log("INFO", "test", "verification check");
            return true;
        });

        // Check 18: SignalManager (from Section 66)
        check(result, "SignalManager_create", [&]() {
            SignalManager sigman;
            return true;
        });

        // Check 19: IncrementalStateUpdater (from Section 64)
        check(result, "IncrementalStateUpdater_create", [&]() {
            IncrementalStateUpdater updater;
            return true;
        });

        return result;
    }

private:
    void check(VerificationResult& result, const std::string& name,
               std::function<bool()> fn) {
        result.total_checks++;
        try {
            if (fn()) {
                result.passed_checks++;
            } else {
                result.failed_checks++;
                result.all_passed = false;
                result.failures.push_back(name + ": returned false");
            }
        } catch (const std::exception& e) {
            result.failed_checks++;
            result.all_passed = false;
            result.failures.push_back(name + ": exception: " + std::string(e.what()));
        }
    }
};

