// 73.8: main() - Complete Bitcoin Core Security Audit Entry Point
// ---------------------------------------------------------------------------
int run_complete_bitcoin_audit(int argc, char* argv[]) {
    // Banner
    std::cout << R"(
 ____  _ _            _          ____                 
| __ )(_) |_ ___ ___ (_)_ __    / ___|___  _ __ ___  
|  _ \| | __/ __/ _ \| | '_ \  | |   / _ \| '__/ _ \ 
| |_) | | || (_| (_) | | | | | | |__| (_) | | |  __/ 
|____/|_|\__\___\___/|_|_| |_|  \____\___/|_|  \___| 
                                                       
  ____                      _ _           _             _ _ _   
 / ___|  ___  ___ _   _ _ __(_) |_ _   _  / \  _   _  __| (_) |_ 
 \___ \ / _ \/ __| | | | '__| | __| | | |/ _ \| | | |/ _` | | __|
  ___) |  __/ (__| |_| | |  | | |_| |_| / ___ \ |_| | (_| | | |_ 
 |____/ \___|\___|\__,_|_|  |_|\__|\__, /_/   \_\__,_|\__,_|_|\__|
                                    |___/                           
    Framework: btc_audit::enhanced_verification v3.2
    20-Phase Comprehensive Pipeline
)" << std::endl;

    // Parse command line
    std::vector<std::string> source_paths;
    std::string target_version = "28.0";
    std::string config_path;
    bool verbose = false;
    bool resume = false;
    std::string resume_checkpoint;

    for (int i = 1; i < argc; i++) {
        std::string arg(argv[i]);
        if (arg == "--source" && i + 1 < argc) {
            source_paths.push_back(argv[++i]);
        } else if (arg == "--version" && i + 1 < argc) {
            target_version = argv[++i];
        } else if (arg == "--config" && i + 1 < argc) {
            config_path = argv[++i];
        } else if (arg == "--verbose") {
            verbose = true;
        } else if (arg == "--resume" && i + 1 < argc) {
            resume = true;
            resume_checkpoint = argv[++i];
        } else if (arg == "--help") {
            std::cout << "Usage: " << argv[0] << " [options]\n"
                      << "  --source <path>      Source directory to audit\n"
                      << "  --version <ver>      Bitcoin Core version (default: 28.0)\n"
                      << "  --config <path>      Configuration file path\n"
                      << "  --verbose            Enable verbose output\n"
                      << "  --resume <path>      Resume from checkpoint\n"
                      << "  --help               Show this help\n";
            return 0;
        }
    }

    if (source_paths.empty()) {
        source_paths.push_back("./src");  // default
    }

    // Configure
    CompleteVerificationOrchestrator::Phase3Config config;
    config.enable_p2p_testing = true;
    config.enable_wallet_analysis = true;
    config.enable_mempool_tracing = true;
    config.enable_report_validation = true;
    config.enable_persistence = true;
    config.enable_checkpointing = true;
    config.minimum_quality_score = 0.60;
    config.require_sign_off = true;

    // Run integration verification first
    std::cout << "[PRE-FLIGHT] Running integration verification...\n";
    Phase3IntegrationVerifier verifier;
    auto vresult = verifier.verify_all();
    std::cout << "[PRE-FLIGHT] " << vresult.passed_checks << "/"
              << vresult.total_checks << " checks passed\n";
    if (!vresult.all_passed) {
        std::cout << "[PRE-FLIGHT] FAILURES:\n";
        for (const auto& f : vresult.failures) {
            std::cout << "  FAIL: " << f << "\n";
        }
        std::cout << "[PRE-FLIGHT] Continuing despite failures...\n";
    }

    // Create orchestrator and run
    CompleteVerificationOrchestrator orchestrator(config);

    try {
        orchestrator.run_complete_audit(source_paths, target_version);
    } catch (const std::exception& e) {
        std::cerr << "[FATAL] Unhandled exception: " << e.what() << "\n";
        std::cerr << "[FATAL] Partial results may have been saved to checkpoints.\n";
        return 1;
    }

    // Summary
    auto session = orchestrator.get_session().get_state();
    std::cout << "\n=== AUDIT COMPLETE ===\n";
    std::cout << "Session:    " << session.session_id << "\n";
    std::cout << "Findings:   " << session.total_findings << "\n";
    std::cout << "  Critical: " << session.critical_findings << "\n";
    std::cout << "  High:     " << session.high_findings << "\n";
    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Quality:    " << session.quality_score << "\n";
    std::cout << "Elapsed:    " << session.total_elapsed_seconds << "s\n";
    std::cout << "Status:     " << (session.completed ? "COMPLETED" : "PARTIAL") << "\n";

    return session.completed ? 0 : 2;
}


