    bool validate_system_configuration() {
        EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
            "quality_orchestrator", "Running pre-flight system checks...");

        // Validate disk space
        ConfigurationValidator::validate_sufficient_disk_space(
            ".", 10ULL * 1024 * 1024 * 1024);  // 10GB

        // Validate memory
        ConfigurationValidator::validate_sufficient_memory(
            4ULL * 1024 * 1024 * 1024);  // 4GB

        // Validate dynamic mode prerequisites
        if (dynamic_config_.enabled && !dynamic_config_.dry_run) {
            // Check osx/ directory exists
            if (!file_exists(dynamic_config_.osx_archive_directory)) {
                EnhancedStructuredLogger::instance()->log(LogLevel::ERROR,
                    "quality_orchestrator",
                    "osx archive directory not found: " +
                    dynamic_config_.osx_archive_directory);
                std::cerr << "ERROR: --dynamic requires osx/ directory with Bitcoin Core archives\n";
                std::cerr << "       Use --dynamic-osx-dir= to specify location\n";
                std::cerr << "       Use --dynamic-dry-run for testing without archives\n";
                return false;
            }

            // Check for archives (.tar.gz) or pre-extracted directories (bitcoin-*)
            std::string check_cmd = "ls -d " + dynamic_config_.osx_archive_directory +
                "/bitcoin-*/bin/bitcoind 2>/dev/null | wc -l";
            FILE* pipe = popen(check_cmd.c_str(), "r");
            int dir_count = 0;
            if (pipe) {
                char buf[32];
                if (fgets(buf, sizeof(buf), pipe)) {
                    dir_count = std::atoi(buf);
                }
                pclose(pipe);
            }

            // Also check for .tar.gz archives
            std::string check_cmd2 = "ls " + dynamic_config_.osx_archive_directory +
                "/*.tar.gz 2>/dev/null | wc -l";
            FILE* pipe2 = popen(check_cmd2.c_str(), "r");
            int archive_count = 0;
            if (pipe2) {
                char buf[32];
                if (fgets(buf, sizeof(buf), pipe2)) {
                    archive_count = std::atoi(buf);
                }
                pclose(pipe2);
            }

            int total_count = dir_count + archive_count;
            if (total_count == 0) {
                EnhancedStructuredLogger::instance()->log(LogLevel::ERROR,
                    "quality_orchestrator",
                    "No Bitcoin Core versions found in " +
                    dynamic_config_.osx_archive_directory +
                    " (looked for bitcoin-*/bin/bitcoind dirs and .tar.gz archives)");
                return false;
            }

            EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
                "quality_orchestrator",
                "Found " + std::to_string(total_count) + " Bitcoin Core versions (" +
                std::to_string(dir_count) + " extracted dirs, " +
                std::to_string(archive_count) + " archives) in " +
                dynamic_config_.osx_archive_directory);
        }

        return true;
    }

    void execute_enhanced_static_analysis(int argc, char** argv) {
        ScopedProfile prof("74E1", "static_analysis");

        EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
            "quality_orchestrator",
            "=== ENHANCED STATIC ANALYSIS (Sections 1-73 + Quality Hardening) ===");

        // Run the existing 20-phase pipeline via run_complete_bitcoin_audit
        // This calls all the existing infrastructure from Sections 1-73
        int result = run_complete_bitcoin_audit(argc, argv);

        static_completed_ = (result == 0);

        EnhancedStructuredLogger::instance()->log(
            result == 0 ? LogLevel::INFO : LogLevel::WARNING,
            "quality_orchestrator",
            "Static analysis " + std::string(result == 0 ? "completed" : "partial"),
            {{"exit_code", std::to_string(result)}});
    }

    void execute_dynamic_verification() {
        ScopedProfile prof("74E1", "dynamic_verification");

        print_dynamic_banner();

        EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
            "quality_orchestrator",
            "=== DYNAMIC VERIFICATION MODE ===");

        // Create results/evidence directories
        create_directory_recursive(dynamic_config_.results_directory);
        if (dynamic_config_.generate_exploit_evidence) {
            create_directory_recursive(dynamic_config_.evidence_directory);
        }

        // Build and execute parallel verification
        ParallelVersionVerifier verifier(dynamic_config_);
        verifier.build_version_jobs();

        auto start = std::chrono::high_resolution_clock::now();
        verifier.execute_parallel_verification();
        auto end = std::chrono::high_resolution_clock::now();

        auto duration_min = std::chrono::duration_cast<std::chrono::minutes>(
            end - start).count();
        auto duration_sec = std::chrono::duration_cast<std::chrono::seconds>(
            end - start).count();

        // Cross-version analysis
        auto cross_findings = verifier.run_cross_version_analysis();
        for (const auto& cf : cross_findings) {
            dynamic_findings_.push_back(cf);
        }

        // Collect evidence
        if (dynamic_config_.generate_exploit_evidence) {
            EvidenceArchiveBuilder archive_builder(dynamic_config_.evidence_directory);
            for (const auto& finding : verifier.get_all_findings()) {
                verifier.collect_evidence(finding);
            }
            archive_builder.write_manifest(
                dynamic_config_.evidence_directory + "/manifest.txt");
        }

        // Write results
        verifier.write_results(dynamic_config_.results_directory);

        // Print report to console
        std::cout << verifier.generate_results_report();

        auto& summary = verifier.get_summary();

        EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
            "quality_orchestrator",
            "Dynamic verification completed in " +
            std::to_string(duration_min) + "m " +
            std::to_string(duration_sec % 60) + "s",
            {{"versions_tested", std::to_string(summary.versions_tested)},
             {"total_findings", std::to_string(summary.total_findings)},
             {"critical", std::to_string(summary.critical_findings)},
             {"high", std::to_string(summary.high_severity_findings)},
             {"medium", std::to_string(summary.medium_severity_findings)},
             {"low", std::to_string(summary.low_severity_findings)}});

        dynamic_completed_ = true;
    }

