public:
    FinalQualityOrchestrator()
        : orchestrator_start_(std::chrono::steady_clock::now()),
          static_completed_(false), dynamic_completed_(false) {}

    int execute_full_quality_audit(int argc, char** argv) {
        // Step 1: Print banner
        print_quality_banner();

        // Step 2: Parse dynamic config
        dynamic_config_ = parse_dynamic_flag(argc, argv);

        // Step 3: Initialize logging
        EnhancedStructuredLogger::instance()->set_min_level(LogLevel::DEBUG);
        EnhancedStructuredLogger::instance()->set_session_id(
            "audit_" + std::to_string(std::chrono::duration_cast<std::chrono::seconds>(
                std::chrono::system_clock::now().time_since_epoch()).count()));

        EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
            "quality_orchestrator",
            "Bitcoin Core Security Audit Framework v3.2-S74 starting",
            {{"dynamic_mode", dynamic_config_.enabled ? "true" : "false"},
             {"dry_run", dynamic_config_.dry_run ? "true" : "false"}});

        // Step 4: System validation
        if (!validate_system_configuration()) {
            return EXIT_FAILURE;
        }

        // Step 5: Check for --help
        for (int i = 1; i < argc; i++) {
            std::string arg(argv[i]);
            if (arg == "--help" || arg == "-h") {
                print_help();
                return EXIT_SUCCESS;
            }
        }

        // Step 6: Run static analysis (Sections 1-73 pipeline)
        // Only run if not in dynamic-only mode
        bool dynamic_only = false;
        for (int i = 1; i < argc; i++) {
            if (std::string(argv[i]) == "--dynamic-only") {
                dynamic_only = true;
                break;
            }
        }

        if (!dynamic_only) {
            execute_enhanced_static_analysis(argc, argv);
        }

        // Step 7: Run dynamic verification if requested
        if (dynamic_config_.enabled) {
            execute_dynamic_verification();
        }

        // Step 8: Generate final report
        generate_quality_assurance_report();

        // Step 9: Run enhanced analysis components
        run_section74_enhanced_analysis();

        return static_completed_ || dynamic_completed_ ? EXIT_SUCCESS : EXIT_FAILURE;
    }

    void run_section74_enhanced_analysis() {
        ScopedProfile prof("74E1", "enhanced_analysis");

        EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
            "quality_orchestrator",
            "Running Section 74 enhanced analysis components...");

        // Run enhanced call graph analysis
        {
            EnhancedCallGraphPathExplorer explorer;
            // Populate with Bitcoin Core-specific call graph edges
            explorer.add_call_edge("ProcessMessage", "ProcessBlockMsg");
            explorer.add_call_edge("ProcessBlockMsg", "AcceptBlock");
            explorer.add_call_edge("AcceptBlock", "CheckBlock");
            explorer.add_call_edge("CheckBlock", "CheckTransaction");
            explorer.add_call_edge("ProcessMessage", "ProcessTxMsg");
            explorer.add_call_edge("ProcessTxMsg", "AcceptToMemoryPool");
            explorer.add_call_edge("AcceptToMemoryPool", "CheckTransaction");
            explorer.add_call_edge("AcceptToMemoryPool", "VerifyScript");
            explorer.add_call_edge("VerifyScript", "EvalScript");
            explorer.add_call_edge("EvalScript", "EvalScript"); // recursive for OP_IF etc.
            explorer.add_call_edge("ConnectBlock", "ConnectTip");
            explorer.add_call_edge("ConnectTip", "FlushStateToDisk");
            explorer.add_call_edge("ActivateBestChain", "ConnectTip");
            explorer.add_call_edge("ActivateBestChain", "DisconnectTip");
            explorer.add_call_edge("DisconnectTip", "DisconnectBlock");

            explorer.mark_consensus("CheckBlock");
            explorer.mark_consensus("CheckTransaction");
            explorer.mark_consensus("AcceptBlock");
            explorer.mark_consensus("ConnectBlock");
            explorer.mark_consensus("VerifyScript");
            explorer.mark_crypto("VerifyScript");
            explorer.mark_crypto("EvalScript");
            explorer.mark_sensitive("AcceptToMemoryPool");

            explorer.add_lock_usage("ConnectTip", "cs_main");
            explorer.add_lock_usage("ActivateBestChain", "cs_main");
            explorer.add_lock_usage("AcceptToMemoryPool", "cs_main");
            explorer.add_lock_usage("AcceptToMemoryPool", "m_pool.cs");

            auto cycle_findings = explorer.generate_findings();
            for (const auto& f : cycle_findings) {
                static_findings_.push_back(f);
            }

            EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
                "quality_orchestrator",
                "Call graph analysis: " + std::to_string(cycle_findings.size()) + " findings");
        }

        // Run enhanced data flow analysis
        {
            EnhancedInterProceduralDataFlow dataflow;
            auto df_findings = dataflow.generate_findings();
            for (const auto& f : df_findings) {
                static_findings_.push_back(f);
            }

            EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
                "quality_orchestrator",
                "Data flow analysis: " + std::to_string(df_findings.size()) + " findings" +
                " (" + std::to_string(dataflow.get_trust_boundaries().size()) +
                " trust boundaries, " +
                std::to_string(dataflow.get_sanitizers().size()) + " sanitizers)");
        }

        // Run enhanced chain state monitor
        {
            EnhancedChainStateMonitor monitor;
            auto chain_findings = monitor.generate_findings();
            for (const auto& f : chain_findings) {
                static_findings_.push_back(f);
            }

            EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
                "quality_orchestrator",
                "Chain state analysis: " + std::to_string(chain_findings.size()) + " findings");
        }

        EnhancedStructuredLogger::instance()->log(LogLevel::INFO,
            "quality_orchestrator",
            "Section 74 enhanced analysis complete: " +
            std::to_string(static_findings_.size()) + " total enhanced findings");
    }

